func int64Ptr(value int64) *int64 { return &value }

func assertDockerComposeConfigAccepts(t *testing.T, path string) {
	t.Helper()
	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker CLI not available for Compose compatibility smoke test")
	}
	cmd := exec.Command("docker", "compose", "-f", path, "config")
	if output, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("docker compose rejected %s: %v\n%s", path, err, string(output))
	}
}

func assertComposeCLIsAccept(t *testing.T, path string) {
	t.Helper()
	type cliCheck struct {
		name string
		cmd  []string
	}
	for _, check := range []cliCheck{
		{name: "docker compose", cmd: []string{"docker", "compose", "-f", path, "config"}},
		{name: "docker-compose", cmd: []string{"docker-compose", "-f", path, "config"}},
	} {
		if _, err := exec.LookPath(check.cmd[0]); err != nil {
			t.Skipf("%s is unavailable: %v", check.name, err)
		}
		command := exec.Command(check.cmd[0], check.cmd[1:]...)
		output, err := command.CombinedOutput()
		if err != nil {
			t.Fatalf("%s rejected %s: %v\n%s", check.name, path, err, string(output))
		}
	}
}

func validateComposeSchema(t *testing.T, content string) {
	t.Helper()
	schemaPath, ok := findComposeSpecSchemaPath()
	if !ok {
		t.Skip("compose-spec schema file not available locally")
	}
	schemaData, err := os.ReadFile(schemaPath)
	if err != nil {
		t.Fatalf("failed to read compose-spec schema: %v", err)
	}
	schemaDoc, err := jsonschema.UnmarshalJSON(strings.NewReader(string(schemaData)))
	if err != nil {
		t.Fatalf("failed to decode compose-spec schema: %v", err)
	}
	compiler := jsonschema.NewCompiler()
	if err := compiler.AddResource(schemaPath, schemaDoc); err != nil {
		t.Fatalf("failed to register compose-spec schema: %v", err)
	}
	schema, err := compiler.Compile(schemaPath)
	if err != nil {
		t.Fatalf("failed to compile compose-spec schema: %v", err)
	}
	var instance any
	if err := yaml.Unmarshal([]byte(content), &instance); err != nil {
		t.Fatalf("failed to decode compose output for schema validation: %v", err)
	}
	if err := schema.Validate(instance); err != nil {
		t.Fatalf("compose output did not validate against official compose-spec schema: %v\n%s", err, content)
	}
}

func findComposeSpecSchemaPath() (string, bool) {
	candidates := []string{
		filepath.Clean(filepath.Join("..", "..", "compose-spec", "schema", "compose-spec.json")),
		filepath.Clean(filepath.Join("..", "compose-spec", "schema", "compose-spec.json")),
		"/run/media/brunner56/MyBook/Workspaces/compose-spec/schema/compose-spec.json",
	}
	for _, candidate := range candidates {
		if _, err := os.Stat(candidate); err == nil {
			return candidate, true
		}
	}
	return "", false
}

func canonicalRawResourceIDs(app *Application) []string {
	if app == nil || app.Canonical == nil {
		return nil
	}
	raw := app.Canonical.RawResources()
	ids := make([]string, 0, len(raw))
	for _, resource := range raw {
		if resource == nil {
			continue
		}
		ids = append(ids, resource.ID)
	}
	return ids
}

func assertComposeGoLoads(t *testing.T, path, expectedService string, profiles ...string) {
	t.Helper()
	content, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("failed to read compose file %s: %v", path, err)
	}
	loadOptions := []func(*loader.Options){
		func(options *loader.Options) {
			options.SetProjectName("paas", true)
		},
	}
	if len(profiles) > 0 {
		loadOptions = append(loadOptions, loader.WithProfiles(profiles))
	}
	loaded, err := loader.LoadWithContext(t.Context(), compasetypes.ConfigDetails{
		WorkingDir:  filepath.Dir(path),
		ConfigFiles: []compasetypes.ConfigFile{{Filename: "compose.yml", Content: []byte(content)}},
	}, loadOptions...)
	if err != nil {
		t.Fatalf("official compose-go loader rejected generated Compose output: %v", err)
	}
	if expectedService != "" {
		if _, ok := loaded.Services[expectedService]; !ok {
			t.Fatalf("official compose-go loader did not preserve %s service: %#v", expectedService, loaded.Services)
		}
	}
}

func assertComposeUsesOnlyExtensionKeys(t *testing.T, content string) {
	t.Helper()
	var data map[string]interface{}
	if err := yaml.Unmarshal([]byte(content), &data); err != nil {
		t.Fatalf("failed to decode compose output for extension-key audit: %v", err)
	}

	var walk func(path []string, value interface{})
	walk = func(path []string, value interface{}) {
		switch typed := value.(type) {
		case map[string]interface{}:
			for key, child := range typed {
				if strings.HasPrefix(key, "x-") {
					walk(append(path, key), child)
					continue
				}
				switch {
				case key == "group" && len(path) >= 2 && path[0] == "services":
					t.Fatalf("compose output leaked raw service group key at %s", strings.Join(path, "."))
				case strings.HasPrefix(key, "kubernetes."):
					t.Fatalf("compose output leaked raw kubernetes key %q at %s", key, strings.Join(path, "."))
				case strings.HasPrefix(key, "nomad."):
					t.Fatalf("compose output leaked raw nomad key %q at %s", key, strings.Join(path, "."))
				case strings.HasPrefix(key, "swarm."):
					t.Fatalf("compose output leaked raw swarm key %q at %s", key, strings.Join(path, "."))
				case strings.HasPrefix(key, "helm."):
					t.Fatalf("compose output leaked raw helm key %q at %s", key, strings.Join(path, "."))
				}
				walk(append(path, key), child)
			}
		case []interface{}:
			for index, child := range typed {
				walk(append(path, fmt.Sprintf("[%d]", index)), child)
			}
		}
	}

	walk(nil, data)
}

func TestParseServiceRehydratesKubernetesGroupFromFallbackParser(t *testing.T) {
	service, err := parseService("api", map[string]interface{}{
		"image":                "ghcr.io/example/api:latest",
		"x-kubernetes-group":   "2000",
		"x-kubernetes-pidMode": "host",
		"x-kubernetes-ipcMode": "host",
	})
	if err != nil {
		t.Fatalf("parseService rejected fallback compose input: %v", err)
	}
	if service.Group != "2000" {
		t.Fatalf("parseService did not rehydrate kubernetes group: %#v", service)
	}
	if service.Extensions["kubernetes.group"] != "2000" {
		t.Fatalf("parseService did not preserve kubernetes group extension: %#v", service.Extensions)
	}
	if service.PIDMode != "host" || service.HostPID == nil || !*service.HostPID {
		t.Fatalf("parseService did not rehydrate kubernetes pidMode: %#v", service)
	}
	if service.IPCMode != "host" || service.HostIPC == nil || !*service.HostIPC {
		t.Fatalf("parseService did not rehydrate kubernetes ipcMode: %#v", service)
	}
	if service.Extensions["kubernetes.pidMode"] != "host" || service.Extensions["kubernetes.ipcMode"] != "host" {
		t.Fatalf("parseService did not preserve pid/ipc extensions: %#v", service.Extensions)
	}
}

func TestFallbackComposeParserCanonicalizesKubernetesExtensionAliases(t *testing.T) {
	service, err := parseService("api", map[string]interface{}{
		"image":                     "ghcr.io/example/api:latest",
		"x-kubernetes-nodeSelector": map[string]interface{}{"env": "prod"},
		"x-kubernetes-resourceClaims": []interface{}{
			map[string]interface{}{
				"name": "scratch",
				"source": map[string]interface{}{
					"resourceClaimTemplateName": "scratch-template",
				},
			},
		},
	})
	if err != nil {
		t.Fatalf("parseService rejected fallback compose input: %v", err)
	}
	app := &Application{
		Platform:   PlatformDockerCompose,
		Services:   map[string]*Service{"api": service},
		Extensions: map[string]interface{}{},
	}
	syncPortableApplicationState(app)

	api := app.Services["api"]
	if api == nil {
		t.Fatalf("missing api service after rehydration: %#v", app.Services)
	}
	if len(api.NodeSelector) != 1 || api.NodeSelector["env"] != "prod" {
		t.Fatalf("nodeSelector alias was not canonicalized by fallback parser: %#v", api.NodeSelector)
	}
	if len(api.ResourceClaims) != 1 || toString(api.ResourceClaims[0]["name"]) != "scratch" {
		t.Fatalf("resourceClaims alias was not canonicalized by fallback parser: %#v", api.ResourceClaims)
	}
	if api.Extensions["kubernetes.nodeSelector"] == nil || api.Extensions["x-kubernetes-node-selector"] == nil {
		t.Fatalf("nodeSelector alias was not preserved in canonical form: %#v", api.Extensions)
	}
	if api.Extensions["kubernetes.resourceClaims"] == nil || api.Extensions["x-kubernetes-resource-claims"] == nil {
		t.Fatalf("resourceClaims alias was not preserved in canonical form: %#v", api.Extensions)
	}
	if _, ok := api.Extensions["x-kubernetes-nodeSelector"]; ok {
		t.Fatalf("fallback parser retained camelCase nodeSelector alias: %#v", api.Extensions)
	}
	if _, ok := api.Extensions["x-kubernetes-resourceClaims"]; ok {
		t.Fatalf("fallback parser retained camelCase resourceClaims alias: %#v", api.Extensions)
	}
}

