// TestMerging tests application merging
func TestMerging(t *testing.T) {
	paas := New(nil)

	app1 := createTestApplication()

	// Create app2 with different services
	app2 := &Application{
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"web2": {
				Name:  "web2",
				Image: "nginx:alpine",
			},
			"cache": {
				Name:  "cache",
				Image: "redis:alpine",
			},
		},
		Networks: make(map[string]*Network),
		Volumes:  make(map[string]*Volume),
		Configs:  make(map[string]*Config),
		Secrets:  make(map[string]*Secret),
	}

	merged, err := paas.MergeApplications(app1, app2)
	if err != nil {
		t.Fatalf("Failed to merge applications: %v", err)
	}

	expectedServices := len(app1.Services) + len(app2.Services)
	if len(merged.Services) != expectedServices {
		t.Errorf("Merge failed: expected %d services, got %d",
			expectedServices, len(merged.Services))
	}
}

func TestDockerSwarmDeployPolicyRoundTrip(t *testing.T) {
	content := `
x-platform: docker-swarm
services:
  api:
    image: ghcr.io/example/api:1
    labels:
      traefik.enable: "true"
      traefik.http.routers.api.rule: Host(` + "`api.example.test`" + `) && PathPrefix(` + "`/v1`" + `)
      traefik.http.routers.api.entrypoints: websecure
      traefik.http.routers.api.tls: "true"
      traefik.http.routers.api.middlewares: nginx-auth@file,rate-limit-paid@file
    ports:
      - target: 8080
        published: "80"
        protocol: tcp
    deploy:
      mode: replicated
      replicas: 3
      labels:
        traefik.enable: "true"
      placement:
        constraints:
          - node.labels.region == us
      resources:
        limits:
          cpus: "0.50"
          memory: 256M
        reservations:
          cpus: "0.25"
          memory: 128M
      update_config:
        parallelism: 1
        delay: 10s
        order: start-first
        failure_action: rollback
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse swarm compose: %v", err)
	}
	if app.Platform != PlatformDockerSwarm {
		t.Fatalf("expected docker-swarm platform, got %s", app.Platform)
	}
	api := app.Services["api"]
	if api == nil || api.Deploy == nil {
		t.Fatalf("api deploy policy not parsed")
	}
	if api.Replicas != 3 || api.Deploy.Replicas != 3 {
		t.Fatalf("replicas not preserved: service=%d deploy=%d", api.Replicas, api.Deploy.Replicas)
	}
	if api.Deploy.Resources == nil || api.Deploy.Resources.MemoryLimit != "268435456" {
		t.Fatalf("deploy resources not parsed: %#v", api.Deploy.Resources)
	}
	out, err := p.SaveContent(app, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize swarm compose: %v", err)
	}
	parsedAgain, err := p.LoadContent(out, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse serialized swarm compose: %v", err)
	}
	if parsedAgain.Services["api"].Deploy.UpdateConfig.Order != "start-first" {
		t.Fatalf("update config lost after roundtrip: %#v", parsedAgain.Services["api"].Deploy.UpdateConfig)
	}
	if app.Canonical == nil {
		t.Fatalf("canonical model was not attached")
	}
	if _, ok := app.Canonical.Resources["docker-swarm:raw:compose-project"]; !ok {
		t.Fatalf("compose-go raw project was not preserved in canonical resources")
	}
	if app.Extensions[composeRawYAMLExtension] != content {
		t.Fatalf("raw swarm compose YAML was not preserved")
	}
	if _, ok := app.Canonical.Resources["docker-swarm:raw:compose-yaml"]; !ok {
		t.Fatalf("raw swarm compose YAML was not indexed canonically")
	}
	if _, ok := app.Canonical.Resources["docker-swarm:service:api"]; !ok {
		t.Fatalf("canonical service resource missing")
	}
	route := app.Canonical.Routes["api"]
	if route == nil || route.Service != "api" || len(route.Hosts) != 1 || route.Hosts[0] != "api.example.test" || !route.TLS {
		t.Fatalf("traefik route not normalized: %#v", route)
	}
	if app.Canonical.Policies["api-auth"] == nil || app.Canonical.Policies["api-middlewares"] == nil {
		t.Fatalf("traefik auth/middleware policies not normalized: %#v", app.Canonical.Policies)
	}
}

func TestComposeRawSourcePreservedWithoutLeakingIntoGeneratedYAML(t *testing.T) {
	content := `
# source comments and ordering matter for exact restore
name: demo
services:
  api:
    image: ghcr.io/example/api:raw
    x-custom-service-field: keep-me
x-top-level-note: keep-me-too
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose: %v", err)
	}
	if app.Extensions[composeRawYAMLExtension] != content {
		t.Fatalf("raw compose source was not preserved")
	}
	if app.Canonical == nil || app.Canonical.Resources["docker-compose:raw:compose-yaml"] == nil {
		t.Fatalf("raw compose source was not indexed canonically: %#v", app.Canonical)
	}
	generated, err := p.SaveContent(app, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize compose: %v", err)
	}
	if strings.Contains(generated, composeRawYAMLExtension) || strings.Contains(generated, "source comments and ordering matter") {
		t.Fatalf("internal raw compose source leaked into generated YAML:\n%s", generated)
	}
	restorePath := filepath.Join(t.TempDir(), "compose.yml")
	if err := RestoreDockerComposeSource(app, restorePath); err != nil {
		t.Fatalf("failed to restore raw compose source: %v", err)
	}
	restored, err := os.ReadFile(restorePath)
	if err != nil {
		t.Fatalf("failed to read restored compose source: %v", err)
	}
	if string(restored) != content {
		t.Fatalf("restored compose source changed\nexpected:\n%s\nactual:\n%s", content, string(restored))
	}

	nomadApp, err := p.Convert(app, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert compose to nomad: %v", err)
	}
	convertedRestorePath := filepath.Join(t.TempDir(), "compose-converted.yml")
	if err := RestoreDockerComposeSource(nomadApp, convertedRestorePath); err != nil {
		t.Fatalf("failed to restore compose source from converted app: %v", err)
	}
	convertedRestored, err := os.ReadFile(convertedRestorePath)
	if err != nil {
		t.Fatalf("failed to read restored converted compose source: %v", err)
	}
	if string(convertedRestored) != content {
		t.Fatalf("restored converted compose source changed\nexpected:\n%s\nactual:\n%s", content, string(convertedRestored))
	}
}

func TestComposeRawSourceSurvivesUniversalRoundTripAndCanBeRestored(t *testing.T) {
	content := `
# source comments and ordering matter for exact restore
name: demo
services:
  api:
    image: ghcr.io/example/api:raw
    x-custom-service-field: keep-me
    x-kubernetes-job-parallelism: 3
x-top-level-note: keep-me-too
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose: %v", err)
	}
	kubernetesApp, err := p.Convert(app, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert compose to kubernetes: %v", err)
	}
	helmApp, err := p.Convert(kubernetesApp, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert kubernetes to helm: %v", err)
	}
	nomadApp, err := p.Convert(helmApp, PlatformHelm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert helm to nomad: %v", err)
	}
	swarmApp, err := p.Convert(nomadApp, PlatformNomad, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert nomad to swarm: %v", err)
	}
	backToCompose, err := p.Convert(swarmApp, PlatformDockerSwarm, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert swarm back to compose: %v", err)
	}

	restorePath := filepath.Join(t.TempDir(), "compose.yml")
	if err := RestoreDockerComposeSource(backToCompose, restorePath); err != nil {
		t.Fatalf("failed to restore compose source after full chain: %v", err)
	}
	restored, err := os.ReadFile(restorePath)
	if err != nil {
		t.Fatalf("failed to read restored compose source: %v", err)
	}
	if string(restored) != content {
		t.Fatalf("restored compose source changed after full chain\nexpected:\n%s\nactual:\n%s", content, string(restored))
	}
}

