func TestComposeLifecycleHooksRoundTripThroughTypedModel(t *testing.T) {
	content := `
services:
  api:
    image: ghcr.io/example/api:lifecycle
    pre_start:
      - command: ["./migrate.sh"]
        user: root
        privileged: true
        environment:
          MIGRATE: "1"
        x-bolabaden-hook: pre
        custom.hook-field: pre-hook
    post_start:
      - command: ./warm-cache.sh
        working_dir: /workspace
    pre_stop:
      - command: ["./drain.sh"]
        image: ghcr.io/example/drain:latest
        per_replica: true
`
	app, err := ParseDockerCompose(content)
	if err != nil {
		t.Fatalf("failed to parse compose lifecycle hooks: %v", err)
	}
	api := app.Services["api"]
	if api == nil || api.Lifecycle == nil {
		t.Fatalf("lifecycle hooks were not lifted into portable model: %#v", api)
	}
	if len(api.Lifecycle.PreStart) != 1 || api.Lifecycle.PreStart[0].Command[0] != "./migrate.sh" || api.Lifecycle.PreStart[0].User != "root" || !api.Lifecycle.PreStart[0].Privileged {
		t.Fatalf("pre_start hook was not preserved: %#v", api.Lifecycle.PreStart)
	}
	if api.Lifecycle.PreStart[0].Environment["MIGRATE"] == nil || *api.Lifecycle.PreStart[0].Environment["MIGRATE"] != "1" || api.Lifecycle.PreStart[0].Extensions["x-bolabaden-hook"] != "pre" {
		t.Fatalf("pre_start hook metadata was not preserved: %#v", api.Lifecycle.PreStart[0])
	}
	api.Lifecycle.PreStart[0].Extensions["custom.hook-field"] = "pre-hook"
	if len(api.Lifecycle.PostStart) != 1 || api.Lifecycle.PostStart[0].Command[0] != "./warm-cache.sh" || api.Lifecycle.PostStart[0].WorkingDir != "/workspace" {
		t.Fatalf("post_start hook was not preserved: %#v", api.Lifecycle.PostStart)
	}
	if len(api.Lifecycle.PreStop) != 1 || api.Lifecycle.PreStop[0].Image != "ghcr.io/example/drain:latest" || !api.Lifecycle.PreStop[0].PerReplica {
		t.Fatalf("pre_stop hook was not preserved: %#v", api.Lifecycle.PreStop)
	}

	out, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize compose lifecycle hooks: %v", err)
	}
	for _, expected := range []string{
		"pre_start:",
		"post_start:",
		"pre_stop:",
		"privileged: true",
		"working_dir: /workspace",
		"per_replica: true",
		"x-bolabaden-hook: pre",
		"x-custom-hook-field: pre-hook",
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("serialized compose lifecycle hooks missing %q:\n%s", expected, out)
		}
	}
}

