func TestKubernetesWorkloadMetadataSurvivesCrossFormatWithoutRawFallback(t *testing.T) {
	content := `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
  labels:
    app.kubernetes.io/name: api
    app.kubernetes.io/part-of: control-plane
  annotations:
    rollout.example.com/source: workload
spec:
  replicas: 1
  selector:
    matchLabels:
      app.kubernetes.io/name: api
  template:
    metadata:
      labels:
        app.kubernetes.io/name: api
        app.kubernetes.io/component: backend
      annotations:
        prometheus.io/scrape: "true"
        rollout.example.com/source: template
    spec:
      containers:
        - name: api
          image: ghcr.io/example/api:metadata
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse workload metadata fixture: %v", err)
	}
	delete(app.Extensions, "kubernetes.raw")
	api := app.Services["api"]
	if api == nil {
		t.Fatalf("workload service not parsed")
	}
	if labels := serviceExtensionStringMap(api, "kubernetes.workload.labels"); labels["app.kubernetes.io/part-of"] != "control-plane" {
		t.Fatalf("workload labels not preserved distinctly: %#v", api.Extensions)
	}
	if labels := serviceExtensionStringMap(api, "kubernetes.template.labels"); labels["app.kubernetes.io/component"] != "backend" {
		t.Fatalf("template labels not preserved distinctly: %#v", api.Extensions)
	}
	if annotations := serviceExtensionStringMap(api, "kubernetes.workload.annotations"); annotations["rollout.example.com/source"] != "workload" {
		t.Fatalf("workload annotations not preserved distinctly: %#v", api.Extensions)
	}
	if annotations := serviceExtensionStringMap(api, "kubernetes.template.annotations"); annotations["rollout.example.com/source"] != "template" || annotations["prometheus.io/scrape"] != "true" {
		t.Fatalf("template annotations not preserved distinctly: %#v", api.Extensions)
	}

	kubernetesOut, err := p.SaveContent(app, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata fixture: %v", err)
	}
	for _, expected := range []string{"app.kubernetes.io/part-of: control-plane", "rollout.example.com/source: workload", "app.kubernetes.io/component: backend", "prometheus.io/scrape: \"true\"", "rollout.example.com/source: template"} {
		if !strings.Contains(kubernetesOut, expected) {
			t.Fatalf("typed workload metadata output missing %q:\n%s", expected, kubernetesOut)
		}
	}

	composeApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert workload metadata fixture to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata fixture as Compose: %v", err)
	}
	for _, expected := range []string{"x-kubernetes-workload-labels:", "x-kubernetes-workload-annotations:", "x-kubernetes-template-labels:", "x-kubernetes-template-annotations:", "control-plane", "prometheus.io/scrape"} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("Compose workload metadata output missing %q:\n%s", expected, composeOut)
		}
	}
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse workload metadata Compose output: %v", err)
	}
	composeKubernetesApp, err := p.Convert(parsedCompose, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert workload metadata Compose output back to Kubernetes: %v", err)
	}
	delete(composeKubernetesApp.Extensions, "kubernetes.raw")
	composeKubernetesOut, err := p.SaveContent(composeKubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata Compose round-trip as Kubernetes: %v", err)
	}
	for _, expected := range []string{"app.kubernetes.io/part-of: control-plane", "rollout.example.com/source: workload", "app.kubernetes.io/component: backend", "rollout.example.com/source: template"} {
		if !strings.Contains(composeKubernetesOut, expected) {
			t.Fatalf("Compose workload metadata round-trip missing %q:\n%s", expected, composeKubernetesOut)
		}
	}

	swarmApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert workload metadata fixture to Swarm: %v", err)
	}
	swarmOut, err := p.SaveContent(swarmApp, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata fixture as Swarm: %v", err)
	}
	if !strings.Contains(swarmOut, "x-platform: docker-swarm") || !strings.Contains(swarmOut, "x-kubernetes-template-annotations:") || !strings.Contains(swarmOut, "control-plane") {
		t.Fatalf("Swarm workload metadata output lost metadata:\n%s", swarmOut)
	}
	parsedSwarm, err := p.LoadContent(swarmOut, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse workload metadata Swarm output: %v", err)
	}
	swarmKubernetesApp, err := p.Convert(parsedSwarm, PlatformDockerSwarm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert workload metadata Swarm output back to Kubernetes: %v", err)
	}
	delete(swarmKubernetesApp.Extensions, "kubernetes.raw")
	swarmKubernetesOut, err := p.SaveContent(swarmKubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata Swarm round-trip as Kubernetes: %v", err)
	}
	if !strings.Contains(swarmKubernetesOut, "app.kubernetes.io/part-of: control-plane") || !strings.Contains(swarmKubernetesOut, "rollout.example.com/source: template") {
		t.Fatalf("Swarm workload metadata round-trip lost fields:\n%s", swarmKubernetesOut)
	}

	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert workload metadata fixture to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata fixture as Nomad: %v", err)
	}
	if !strings.Contains(nomadOut, "bolabaden_extensions") || !strings.Contains(nomadOut, "kubernetes.workload.labels") || !strings.Contains(nomadOut, "prometheus.io/scrape") {
		t.Fatalf("Nomad workload metadata output lost metadata:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse workload metadata Nomad output: %v", err)
	}
	nomadKubernetesApp, err := p.Convert(parsedNomad, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert workload metadata Nomad output back to Kubernetes: %v", err)
	}
	delete(nomadKubernetesApp.Extensions, "kubernetes.raw")
	nomadKubernetesOut, err := p.SaveContent(nomadKubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata Nomad round-trip as Kubernetes: %v", err)
	}
	if !strings.Contains(nomadKubernetesOut, "app.kubernetes.io/part-of: control-plane") || !strings.Contains(nomadKubernetesOut, "rollout.example.com/source: template") {
		t.Fatalf("Nomad workload metadata round-trip lost fields:\n%s", nomadKubernetesOut)
	}

	helmDir := filepath.Join(t.TempDir(), "workload-metadata-chart")
	helmApp, err := p.Convert(app, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert workload metadata fixture to Helm: %v", err)
	}
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to save workload metadata Helm chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse workload metadata Helm chart: %v", err)
	}
	delete(parsedHelm.Extensions, "kubernetes.raw")
	helmKubernetesOut, err := p.SaveContent(parsedHelm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize workload metadata Helm round-trip as Kubernetes: %v", err)
	}
	if !strings.Contains(helmKubernetesOut, "app.kubernetes.io/part-of: control-plane") || !strings.Contains(helmKubernetesOut, "rollout.example.com/source: template") {
		t.Fatalf("Helm workload metadata round-trip lost fields:\n%s", helmKubernetesOut)
	}
}

func TestKubernetesPersistentVolumeParsingAndSerialization(t *testing.T) {
	content := `
apiVersion: v1
kind: PersistentVolume
metadata:
  name: pv-data
  labels:
    storage.example.com/tier: gold
  annotations:
    storage.example.com/owner: platform
spec:
  capacity:
    storage: 10Gi
  accessModes:
    - ReadWriteOnce
  storageClassName: fast
  volumeMode: Filesystem
  persistentVolumeReclaimPolicy: Retain
  mountOptions:
    - hard
    - nfsvers=4.1
  claimRef:
    apiVersion: v1
    kind: PersistentVolumeClaim
    namespace: storage
    name: data-claim
    uid: claim-uid
    resourceVersion: "42"
  local:
    path: /var/lib/data
  nodeAffinity:
    required:
      nodeSelectorTerms:
        - matchExpressions:
            - key: kubernetes.io/hostname
              operator: In
              values:
                - worker-01
`
	app, err := ParseKubernetesYAML(content)
	if err != nil {
		t.Fatalf("failed to parse persistent volume: %v", err)
	}
	volume := app.Volumes["pv-data"]
	if volume == nil {
		t.Fatalf("persistent volume not parsed")
	}
	if volume.Driver != "local" {
		t.Fatalf("persistent volume driver not parsed: %#v", volume)
	}
	if volume.DriverOpts["path"] != "/var/lib/data" || volume.DriverOpts["capacity.storage"] != "10Gi" || volume.DriverOpts["storageClassName"] != "fast" || volume.DriverOpts["volumeMode"] != "Filesystem" || volume.DriverOpts["persistentVolumeReclaimPolicy"] != "Retain" || volume.DriverOpts["mountOptions"] != "hard,nfsvers=4.1" || volume.DriverOpts["claimRefUID"] != "claim-uid" {
		t.Fatalf("persistent volume fields not parsed: %#v", volume.DriverOpts)
	}
	if volumeKubernetesLabels(volume)["storage.example.com/tier"] != "gold" || volumeKubernetesAnnotations(volume)["storage.example.com/owner"] != "platform" || volumeKubernetesMap(volume, "kubernetes.nodeAffinity")["required"] == nil {
		t.Fatalf("persistent volume metadata not parsed: %#v", volume.Extensions)
	}
	if volume.Extensions["kubernetes.kind"] != "PersistentVolume" {
		t.Fatalf("persistent volume kind not preserved: %#v", volume.Extensions)
	}

	out, err := SerializeKubernetesYAML(app)
	if err != nil {
		t.Fatalf("failed to serialize persistent volume: %v", err)
	}
	for _, expected := range []string{
		"kind: PersistentVolume",
		"name: pv-data",
		"storage: 10Gi",
		"storageClassName: fast",
		"volumeMode: Filesystem",
		"persistentVolumeReclaimPolicy: Retain",
		"mountOptions:",
		"claim-uid",
		"nodeAffinity:",
		"path: /var/lib/data",
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("persistent volume output missing %q:\n%s", expected, out)
		}
	}
	parsedAgain, err := ParseKubernetesYAML(out)
	if err != nil {
		t.Fatalf("failed to reparse persistent volume output: %v", err)
	}
	volumeAgain := parsedAgain.Volumes["pv-data"]
	if volumeAgain == nil || volumeAgain.Driver != "local" || volumeAgain.DriverOpts["path"] != "/var/lib/data" || volumeAgain.DriverOpts["claimRefUID"] != "claim-uid" {
		t.Fatalf("persistent volume did not round-trip: %#v", volumeAgain)
	}
}

