	api := app.Services["api"]
	if api == nil {
		t.Fatalf("api deployment was not parsed")
	}
	if api.ServiceAccountName != "api-sa" {
		t.Fatalf("serviceAccountName did not parse: %#v", api)
	}
	if serviceAccountSpec := app.KubernetesServiceAccounts["api-sa"]; serviceAccountSpec == nil || serviceAccountSpec.Name != "api-sa" || serviceAccountSpec.Namespace != "mesh" || len(serviceAccountSpec.ImagePullSecrets) != 1 || serviceAccountSpec.ImagePullSecrets[0] != "registry-secret" || len(serviceAccountSpec.Secrets) != 1 || serviceAccountSpec.Secrets[0] != "api-token" {
		t.Fatalf("typed ServiceAccount was not preserved: %#v", serviceAccountSpec)
	}
