	swarmKubernetes, err := p.Convert(parsedSwarm, PlatformDockerSwarm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Swarm ServiceAccount bridge back to Kubernetes: %v", err)
	}
