func TestKubernetesLegacyRoutePolicyRawResourcesSurviveSwarmBridge(t *testing.T) {
	app := legacyRoutePolicyRawBridgeFixture()

	p := New(nil)
	swarmApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert legacy Kubernetes route/policy app to Swarm: %v", err)
	}
	swarmOut, err := p.SaveContent(swarmApp, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize legacy Kubernetes route/policy Swarm bridge: %v", err)
	}
	if strings.Contains(swarmOut, "kubernetes.routes:") || strings.Contains(swarmOut, "kubernetes.policies:") {
		t.Fatalf("legacy Kubernetes carriers leaked as native app extensions in Swarm output:\n%s", swarmOut)
	}
	if !strings.Contains(swarmOut, "x-platform: docker-swarm") || !strings.Contains(swarmOut, "x-bolabaden-canonical-routes:") || !strings.Contains(swarmOut, "x-bolabaden-canonical-policies:") || !strings.Contains(swarmOut, "x-bolabaden-kubernetes-raw-resources:") {
		t.Fatalf("Swarm bridge did not preserve normalized route/policy sidecars:\n%s", swarmOut)
	}

	parsedSwarm, err := p.LoadContent(swarmOut, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse exported Swarm route/policy bridge: %v", err)
	}
	restorePath := filepath.Join(t.TempDir(), "kubernetes.yaml")
	if err := RestoreKubernetesSource(parsedSwarm, restorePath); err != nil {
		t.Fatalf("failed to restore Kubernetes route/policy raw resources from Swarm bridge: %v", err)
	}
	assertRestoredLegacyRoutePolicyRawResources(t, restorePath)
}

func TestKubernetesLegacyRoutePolicyRawResourcesSurviveNomadAndHelmExports(t *testing.T) {
	app := legacyRoutePolicyRawBridgeFixture()
	p := New(nil)

	composeApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert legacy Kubernetes route/policy app to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize legacy Kubernetes route/policy Compose bridge: %v", err)
	}
	if !strings.Contains(composeOut, composeCanonicalRawResourcesExtension) || !strings.Contains(composeOut, "api-edge") || !strings.Contains(composeOut, "api-policy") {
		t.Fatalf("Compose bridge did not preserve Kubernetes raw resources:\n%s", composeOut)
	}
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse exported Compose route/policy bridge: %v", err)
	}
	composeRestorePath := filepath.Join(t.TempDir(), "compose-kubernetes.yaml")
	if err := RestoreKubernetesSource(parsedCompose, composeRestorePath); err != nil {
		t.Fatalf("failed to restore Kubernetes route/policy raw resources from Compose bridge: %v", err)
	}
	assertRestoredLegacyRoutePolicyRawResources(t, composeRestorePath)

	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert legacy Kubernetes route/policy app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize legacy Kubernetes route/policy Nomad bridge: %v", err)
	}
	if !strings.Contains(nomadOut, nomadKubernetesRawResourcesMetaKey) || !strings.Contains(nomadOut, "api-edge") || !strings.Contains(nomadOut, "api-policy") {
		t.Fatalf("Nomad bridge did not preserve Kubernetes raw resources:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse exported Nomad route/policy bridge: %v", err)
	}
	nomadRestorePath := filepath.Join(t.TempDir(), "nomad-kubernetes.yaml")
	if err := RestoreKubernetesSource(parsedNomad, nomadRestorePath); err != nil {
		t.Fatalf("failed to restore Kubernetes route/policy raw resources from Nomad bridge: %v", err)
	}
	assertRestoredLegacyRoutePolicyRawResources(t, nomadRestorePath)

	helmApp, err := p.Convert(app, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert legacy Kubernetes route/policy app to Helm: %v", err)
	}
	helmDir := filepath.Join(t.TempDir(), "legacy-raw-chart")
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to save legacy Kubernetes route/policy Helm bridge: %v", err)
	}
	if _, err := os.Stat(filepath.Join(helmDir, helmKubernetesRawResourcesFile)); err != nil {
		t.Fatalf("Helm Kubernetes raw resources sidecar missing: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse exported Helm route/policy bridge: %v", err)
	}
	rawResources := cloneInterfaceSlice(kubernetesRawExtensionResourcesToInterfaces(parsedHelm.Extensions[composeKubernetesRawResourcesExtension]))
	if len(rawResources) == 0 {
		t.Fatalf("Helm bridge did not rehydrate Kubernetes raw resources sidecar: %#v", parsedHelm.Extensions)
	}
	parsedHelm.Extensions = map[string]interface{}{
		composeKubernetesRawResourcesExtension: rawResources,
	}
	parsedHelm.Canonical = nil
	helmRestorePath := filepath.Join(t.TempDir(), "helm-kubernetes.yaml")
	if err := RestoreKubernetesSource(parsedHelm, helmRestorePath); err != nil {
		t.Fatalf("failed to restore Kubernetes route/policy raw resources from Helm bridge sidecar: %v", err)
	}
	assertRestoredLegacyRoutePolicyRawResources(t, helmRestorePath)
}

