func kubernetesRawExtensionResourcesToInterfaces(value interface{}) []interface{} {
	resources := kubernetesRawExtensionResources(value)
	if len(resources) == 0 {
		return nil
	}
	result := make([]interface{}, 0, len(resources))
	for _, resource := range resources {
		result = append(result, resource)
	}
	return result
}

