func assertHasCanonicalRawResource(t *testing.T, app *Application, nativeKind, name, annotationKey, annotationValue string) {
	t.Helper()
	if app == nil || app.Canonical == nil {
		t.Fatalf("canonical graph missing while checking %s/%s", nativeKind, name)
	}
	for _, resource := range app.Canonical.RawResources() {
		if resource == nil || resource.NativeKind != nativeKind || resource.Name != name {
			continue
		}
		if annotationKey == "" {
			return
		}
		if resource.Annotations != nil && resource.Annotations[annotationKey] == annotationValue {
			return
		}
	}
	t.Fatalf("canonical raw resource %s/%s with annotation %s=%s not found: %#v", nativeKind, name, annotationKey, annotationValue, app.Canonical.Resources)
}

