func TestSerializersDoNotMutateSourceApplicationDuringEmit(t *testing.T) {
	app := &Application{
		Platform: PlatformDockerCompose,
		Name:     "mutability-check",
		Version:  "3.9",
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "ghcr.io/example/api:claims",
				Deploy: &DeploySpec{
					Mode:      "replicated",
					Resources: &ResourceSpec{},
				},
				ImagePullSecrets: []string{"regcred"},
				Extensions: map[string]interface{}{
					"x-custom":            "keep-me",
					"x-kubernetes-claims": []interface{}{map[string]interface{}{"name": "scratch", "request": "scratch-request"}},
				},
			},
		},
	}
	beforeExtensions := copyStringInterfaceMap(app.Services["api"].Extensions)
	beforeImagePullSecrets := append([]string{}, app.Services["api"].ImagePullSecrets...)
	beforeDeploy := cloneDeploySpec(app.Services["api"].Deploy)

	if _, err := SerializeDockerCompose(app); err != nil {
		t.Fatalf("failed to serialize compose: %v", err)
	}
	if _, err := SerializeKubernetesYAML(app); err != nil {
		t.Fatalf("failed to serialize kubernetes: %v", err)
	}
	if _, err := SerializeNomadHCL(app); err != nil {
		t.Fatalf("failed to serialize nomad: %v", err)
	}
	helmDir := t.TempDir()
	if err := SerializeHelmChart(app, helmDir); err != nil {
		t.Fatalf("failed to serialize helm: %v", err)
	}

	if !reflect.DeepEqual(app.Services["api"].Extensions, beforeExtensions) {
		t.Fatalf("serializers mutated the source service extensions during emit\nbefore: %#v\nafter: %#v", beforeExtensions, app.Services["api"].Extensions)
	}
	if !reflect.DeepEqual(app.Services["api"].ImagePullSecrets, beforeImagePullSecrets) {
		t.Fatalf("serializers mutated the source imagePullSecrets during emit\nbefore: %#v\nafter: %#v", beforeImagePullSecrets, app.Services["api"].ImagePullSecrets)
	}
	if !reflect.DeepEqual(app.Services["api"].Deploy, beforeDeploy) {
		t.Fatalf("serializers mutated the source deploy during emit\nbefore: %#v\nafter: %#v", beforeDeploy, app.Services["api"].Deploy)
	}
	if app.Name != "mutability-check" || app.Version != "3.9" || app.Platform != PlatformDockerCompose {
		t.Fatalf("serializers mutated the source application metadata during emit: %#v", app)
	}
}

func TestKubernetesReadinessGatesRoundTripThroughNomad(t *testing.T) {
	content := `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
  namespace: team-a
spec:
  replicas: 1
  selector:
    matchLabels:
      app: api
  template:
    metadata:
      labels:
        app: api
    spec:
      readinessGates:
        - conditionType: example.com/ready
      containers:
        - name: api
          image: ghcr.io/example/api:readiness
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse readinessGates manifest: %v", err)
	}
	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert readinessGates app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad readinessGates bridge: %v", err)
	}
	if !strings.Contains(nomadOut, "bolabaden_extensions") || !strings.Contains(nomadOut, "example.com/ready") {
		t.Fatalf("Nomad output did not preserve readinessGates extension:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad readinessGates bridge: %v", err)
	}
	if len(parsedNomad.Services["api"].ReadinessGates) != 1 || toString(parsedNomad.Services["api"].ReadinessGates[0]["conditionType"]) != "example.com/ready" {
		t.Fatalf("Nomad bridge did not rehydrate readinessGates: %#v", parsedNomad.Services["api"])
	}
	backToK8s, err := p.Convert(parsedNomad, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad readinessGates bridge back to Kubernetes: %v", err)
	}
	backOut, err := p.SaveContent(backToK8s, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Kubernetes readinessGates manifest: %v", err)
	}
	if !strings.Contains(backOut, "readinessGates:") || !strings.Contains(backOut, "example.com/ready") {
		t.Fatalf("readinessGates did not survive Nomad round-trip:\n%s", backOut)
	}
}

func TestKubernetesPodMetadataRoundTripThroughNomad(t *testing.T) {
	content := `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
spec:
  replicas: 1
  selector:
    matchLabels:
      app: api
  template:
    metadata:
      labels:
        app: api
    spec:
      hostNetwork: true
      hostPID: true
      hostIPC: true
      hostUsers: false
      shareProcessNamespace: true
      enableServiceLinks: false
      dnsPolicy: ClusterFirstWithHostNet
      schedulerName: custom-scheduler
      priorityClassName: high-priority
      runtimeClassName: kata
      nodeName: worker-1
      subdomain: api-headless
      setHostnameAsFQDN: true
      serviceAccountName: api-sa
      automountServiceAccountToken: false
      activeDeadlineSeconds: 42
      imagePullSecrets:
        - name: regcred
      tolerations:
        - key: dedicated
          operator: Equal
          value: api
          effect: NoSchedule
          tolerationSeconds: 60
      hostAliases:
        - ip: 10.10.0.10
          hostnames:
            - db.internal
      securityContext:
        runAsUser: 1000
        runAsGroup: 2000
        fsGroup: 2000
        seLinuxOptions:
          user: system_u
          role: system_r
          type: spc_t
          level: s0:c123,c456
        windowsOptions:
          gmsaCredentialSpecName: gmsa-spec-name
          gmsaCredentialSpec: gmsa-spec-json
          runAsUserName: ContainerUser
          hostProcess: true
        runAsNonRoot: true
        supplementalGroups:
          - 3000
          - 4000
      containers:
        - name: api
          image: ghcr.io/example/api:roundtrip
          tty: true
          stdin: true
          terminationMessagePath: /var/log/term.log
          terminationMessagePolicy: FallbackToLogsOnError
          imagePullPolicy: IfNotPresent
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes pod metadata manifest: %v", err)
	}
	composeApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes pod metadata app to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose pod metadata bridge: %v", err)
	}
	if !strings.Contains(composeOut, "x-kubernetes-windowsOptions") || !strings.Contains(composeOut, "gmsaCredentialSpecName: gmsa-spec-name") || !strings.Contains(composeOut, "x-kubernetes-group") {
		t.Fatalf("Compose output missing windows options bridge:\n%s", composeOut)
	}
	composePath := filepath.Join(t.TempDir(), "pod-metadata-compose.yml")
	if err := os.WriteFile(composePath, []byte(composeOut), 0644); err != nil {
		t.Fatalf("failed to write Compose pod metadata bridge: %v", err)
	}
	assertComposeGoLoads(t, composePath, "api")
	assertComposeUsesOnlyExtensionKeys(t, composeOut)
	assertComposeCLIsAccept(t, composePath)
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose pod metadata bridge: %v", err)
	}
	if parsedCompose.Services["api"] == nil || parsedCompose.Services["api"].WindowsOptions == nil || parsedCompose.Services["api"].WindowsOptions.RunAsUserName == nil || *parsedCompose.Services["api"].WindowsOptions.RunAsUserName != "ContainerUser" {
		t.Fatalf("Compose bridge did not rehydrate windows security context: %#v", parsedCompose.Services["api"])
	}
	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes pod metadata app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad pod metadata bridge: %v", err)
	}
	for _, needle := range []string{
		"bolabaden_extensions",
		"hostNetwork",
		"hostAliases",
		"imagePullSecrets",
		"tolerations",
		"serviceAccountName",
		"kubernetes.group",
		"x-kubernetes-seLinuxOptions",
		"bolabaden_group",
		"bolabaden_tty",
		"bolabaden_stdin_open",
	} {
		if !strings.Contains(nomadOut, needle) {
			t.Fatalf("Nomad output missing %q:\n%s", needle, nomadOut)
		}
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad pod metadata bridge: %v", err)
	}
	api := parsedNomad.Services["api"]
	if api == nil {
		t.Fatalf("parsed Nomad app did not contain api service: %#v", parsedNomad.Services)
	}
	if !api.HostNetwork || api.HostPID == nil || !*api.HostPID || api.HostIPC == nil || !*api.HostIPC {
		t.Fatalf("Nomad bridge did not rehydrate pod network flags: %#v", api)
	}
	if api.HostUsers == nil || *api.HostUsers {
		t.Fatalf("Nomad bridge did not rehydrate hostUsers: %#v", api)
	}
	if api.ShareProcessNamespace == nil || !*api.ShareProcessNamespace || api.EnableServiceLinks == nil || *api.EnableServiceLinks {
		t.Fatalf("Nomad bridge did not rehydrate shared process/service flags: %#v", api)
	}
	if api.FSGroup == nil || *api.FSGroup != 2000 || api.RunAsNonRoot == nil || !*api.RunAsNonRoot || api.SELinuxOptions == nil || api.SELinuxOptions.User != "system_u" || api.SELinuxOptions.Role != "system_r" || api.SELinuxOptions.Type != "spc_t" || api.SELinuxOptions.Level != "s0:c123,c456" {
		t.Fatalf("Nomad bridge did not rehydrate pod security context: %#v", api)
	}
	if api.WindowsOptions == nil || api.WindowsOptions.GMSACredentialSpecName == nil || *api.WindowsOptions.GMSACredentialSpecName != "gmsa-spec-name" || api.WindowsOptions.GMSACredentialSpec == nil || *api.WindowsOptions.GMSACredentialSpec != "gmsa-spec-json" || api.WindowsOptions.RunAsUserName == nil || *api.WindowsOptions.RunAsUserName != "ContainerUser" || api.WindowsOptions.HostProcess == nil || !*api.WindowsOptions.HostProcess {
		t.Fatalf("Nomad bridge did not rehydrate windows security context: %#v", api.WindowsOptions)
	}
	if api.User != "1000" || api.Group != "2000" {
		t.Fatalf("Nomad bridge did not rehydrate runtime user/group: %#v", api)
	}
	if !api.Tty || !api.StdinOpen {
		t.Fatalf("Nomad bridge did not rehydrate tty/stdin: %#v", api)
	}
	if len(api.SupplementalGroups) != 2 || api.SupplementalGroups[0] != 3000 || api.SupplementalGroups[1] != 4000 {
		t.Fatalf("Nomad bridge did not rehydrate supplementalGroups: %#v", api.SupplementalGroups)
	}
	if api.ActiveDeadlineSeconds == nil || *api.ActiveDeadlineSeconds != 42 {
		t.Fatalf("Nomad bridge did not rehydrate activeDeadlineSeconds: %#v", api)
	}
	if api.ServiceAccountName != "api-sa" || api.AutomountServiceAccountToken == nil || *api.AutomountServiceAccountToken {
		t.Fatalf("Nomad bridge did not rehydrate service account fields: %#v", api)
	}
	if api.DNSPolicy != "ClusterFirstWithHostNet" || api.SchedulerName != "custom-scheduler" {
		t.Fatalf("Nomad bridge did not rehydrate pod scheduler/dns fields: %#v", api)
	}
	if api.PriorityClassName != "high-priority" || api.RuntimeClassName != "kata" || api.NodeName != "worker-1" || api.Subdomain != "api-headless" {
		t.Fatalf("Nomad bridge did not rehydrate pod placement fields: %#v", api)
	}
	if api.SetHostnameAsFQDN == nil || !*api.SetHostnameAsFQDN {
		t.Fatalf("Nomad bridge did not rehydrate setHostnameAsFQDN: %#v", api)
	}
	if api.ImagePullPolicy != "IfNotPresent" || len(api.ImagePullSecrets) != 1 || api.ImagePullSecrets[0] != "regcred" {
		t.Fatalf("Nomad bridge did not rehydrate image pull settings: %#v", api)
	}
	if len(api.HostAliases) != 1 || api.HostAliases[0].IP != "10.10.0.10" || len(api.HostAliases[0].Hostnames) != 1 || api.HostAliases[0].Hostnames[0] != "db.internal" {
		t.Fatalf("Nomad bridge did not rehydrate hostAliases: %#v", api.HostAliases)
	}
	if api.TerminationMessagePath != "/var/log/term.log" || api.TerminationMessagePolicy != "FallbackToLogsOnError" {
		t.Fatalf("Nomad bridge did not rehydrate termination message fields: %#v", api)
	}
	if len(api.Tolerations) != 1 || api.Tolerations[0].Key != "dedicated" || api.Tolerations[0].Value != "api" {
		t.Fatalf("Nomad bridge did not rehydrate tolerations: %#v", api.Tolerations)
	}
	backToK8s, err := p.Convert(parsedNomad, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad pod metadata bridge back to Kubernetes: %v", err)
	}
	backOut, err := p.SaveContent(backToK8s, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Kubernetes pod metadata manifest: %v", err)
	}
	for _, needle := range []string{
		"hostNetwork: true",
		"hostPID: true",
		"hostIPC: true",
		"shareProcessNamespace: true",
		"enableServiceLinks: false",
		"dnsPolicy: ClusterFirstWithHostNet",
		"schedulerName: custom-scheduler",
		"priorityClassName: high-priority",
		"runtimeClassName: kata",
		"nodeName: worker-1",
		"subdomain: api-headless",
		"setHostnameAsFQDN: true",
		"serviceAccountName: api-sa",
		"automountServiceAccountToken: false",
		"activeDeadlineSeconds: 42",
		"runAsUser: 1000",
		"runAsGroup: 2000",
		"tty: true",
		"stdin: true",
		"fsGroup: 2000",
		"seLinuxOptions:",
		"user: system_u",
		"role: system_r",
		"type: spc_t",
		"level: s0:c123,c456",
		"windowsOptions:",
		"gmsaCredentialSpecName: gmsa-spec-name",
		"gmsaCredentialSpec: gmsa-spec-json",
		"runAsUserName: ContainerUser",
		"hostProcess: true",
		"runAsNonRoot: true",
		"imagePullPolicy: IfNotPresent",
		"terminationMessagePath: /var/log/term.log",
		"terminationMessagePolicy: FallbackToLogsOnError",
		"regcred",
		"db.internal",
		"dedicated",
	} {
		if !strings.Contains(backOut, needle) {
			t.Fatalf("round-tripped Kubernetes manifest missing %q:\n%s", needle, backOut)
		}
	}
}

func TestKubernetesWindowsHostProcessDefaultsHostNetworkAcrossBridges(t *testing.T) {
	content := `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: win-api
spec:
  replicas: 1
  selector:
    matchLabels:
      app: win-api
  template:
    metadata:
      labels:
        app: win-api
    spec:
      securityContext:
        windowsOptions:
          hostProcess: true
      containers:
        - name: win-api
          image: ghcr.io/example/win-api:roundtrip
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes windows hostProcess manifest: %v", err)
	}
	service := app.Services["win-api"]
	if service == nil {
		t.Fatalf("parsed Windows manifest missing service: %#v", app.Services)
	}
	if service.WindowsOptions == nil || service.WindowsOptions.HostProcess == nil || !*service.WindowsOptions.HostProcess {
		t.Fatalf("parsed Windows manifest did not rehydrate hostProcess: %#v", service.WindowsOptions)
	}
	if !service.HostNetwork || service.Extensions["kubernetes.hostNetwork"] != "true" {
		t.Fatalf("hostProcess did not default hostNetwork: %#v", service)
	}
	if service.DNSPolicy != "ClusterFirstWithHostNet" {
		t.Fatalf("hostProcess did not default dnsPolicy: %#v", service)
	}
	composeApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Windows manifest to Compose: %v", err)
	}
	if composeApp.Services["win-api"] == nil || !composeApp.Services["win-api"].HostNetwork {
		t.Fatalf("Compose conversion lost hostNetwork default: %#v", composeApp.Services["win-api"])
	}
	if composeApp.Services["win-api"].DNSPolicy != "ClusterFirstWithHostNet" {
		t.Fatalf("Compose conversion lost dnsPolicy default: %#v", composeApp.Services["win-api"])
	}
	if _, ok := composeApp.Services["win-api"].Extensions["kubernetes.hostNetwork"]; ok {
		t.Fatalf("Compose conversion leaked raw Kubernetes hostNetwork extension: %#v", composeApp.Services["win-api"].Extensions)
	}
	if composeApp.Services["win-api"].Extensions["x-kubernetes-hostNetwork"] != "true" {
		t.Fatalf("Compose conversion did not namespace Kubernetes hostNetwork extension: %#v", composeApp.Services["win-api"].Extensions)
	}
	if composeApp.Services["win-api"].Extensions["x-kubernetes-dnsPolicy"] != "ClusterFirstWithHostNet" {
		t.Fatalf("Compose conversion did not namespace Kubernetes dnsPolicy extension: %#v", composeApp.Services["win-api"].Extensions)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Windows Compose bridge: %v", err)
	}
	if !strings.Contains(composeOut, "x-kubernetes-hostNetwork") || !strings.Contains(composeOut, "x-kubernetes-windowsOptions") || !strings.Contains(composeOut, "x-kubernetes-dnsPolicy") {
		t.Fatalf("Compose output missing Windows hostProcess bridge:\n%s", composeOut)
	}
	composePath := filepath.Join(t.TempDir(), "win-api-compose.yml")
	if err := os.WriteFile(composePath, []byte(composeOut), 0644); err != nil {
		t.Fatalf("failed to write Windows Compose bridge: %v", err)
	}
	assertComposeGoLoads(t, composePath, "win-api")
	assertComposeUsesOnlyExtensionKeys(t, composeOut)
	assertComposeCLIsAccept(t, composePath)
	backToK8s, err := p.Convert(composeApp, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Windows Compose bridge back to Kubernetes: %v", err)
	}
	if backToK8s.Services["win-api"] == nil || !backToK8s.Services["win-api"].HostNetwork {
		t.Fatalf("Kubernetes reconversion lost hostNetwork default: %#v", backToK8s.Services["win-api"])
	}
	if backToK8s.Services["win-api"].DNSPolicy != "ClusterFirstWithHostNet" {
		t.Fatalf("Kubernetes reconversion lost dnsPolicy default: %#v", backToK8s.Services["win-api"])
	}
	kubernetesOut, err := p.SaveContent(backToK8s, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Windows Kubernetes bridge: %v", err)
	}
	if !strings.Contains(kubernetesOut, "hostNetwork: true") || !strings.Contains(kubernetesOut, "dnsPolicy: ClusterFirstWithHostNet") {
		t.Fatalf("Kubernetes output missing Windows hostProcess hostNetwork bridge:\n%s", kubernetesOut)
	}
}

func TestKubernetesRestartPolicyRoundTripThroughComposeAndNomad(t *testing.T) {
	content := `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
spec:
  replicas: 1
  selector:
    matchLabels:
      app: api
  template:
    metadata:
      labels:
        app: api
    spec:
      restartPolicy: OnFailure
      containers:
        - name: api
          image: ghcr.io/example/api:restart-policy
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes restartPolicy manifest: %v", err)
	}
	if app.Services["api"].PodRestartPolicy != "OnFailure" {
		t.Fatalf("restartPolicy did not parse: %#v", app.Services["api"])
	}
	composeApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose restartPolicy bridge: %v", err)
	}
	if !strings.Contains(composeOut, "x-kubernetes-restartPolicy: OnFailure") {
		t.Fatalf("Compose output did not preserve restartPolicy:\n%s", composeOut)
	}
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose restartPolicy bridge: %v", err)
	}
	if parsedCompose.Services["api"].PodRestartPolicy != "OnFailure" {
		t.Fatalf("Compose bridge did not rehydrate restartPolicy: %#v", parsedCompose.Services["api"])
	}
	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad restartPolicy bridge: %v", err)
	}
	if !strings.Contains(nomadOut, "kubernetes.restartPolicy") || !strings.Contains(nomadOut, "OnFailure") {
		t.Fatalf("Nomad output did not preserve restartPolicy:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad restartPolicy bridge: %v", err)
	}
	if parsedNomad.Services["api"].PodRestartPolicy != "OnFailure" {
		t.Fatalf("Nomad bridge did not rehydrate restartPolicy: %#v", parsedNomad.Services["api"])
	}
	backToK8s, err := p.Convert(parsedCompose, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Compose restartPolicy bridge back to Kubernetes: %v", err)
	}
	backOut, err := p.SaveContent(backToK8s, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Kubernetes restartPolicy manifest: %v", err)
	}
	if !strings.Contains(backOut, "restartPolicy: OnFailure") {
		t.Fatalf("restartPolicy did not survive Compose round-trip:\n%s", backOut)
	}
}

func TestComposeRuntimeFlagsRoundTripThroughNomad(t *testing.T) {
	content := `
services:
  api:
    image: ghcr.io/example/api:runtime-flags
    hostname: api-node
    runtime: runsc
    init: true
    tty: true
    stdin_open: true
    stop_signal: SIGTERM
    stop_grace_period: 45s
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose runtime flags: %v", err)
	}
	api := app.Services["api"]
	if api == nil || api.Hostname != "api-node" || api.Runtime != "runsc" || api.Init == nil || !*api.Init || !api.Tty || !api.StdinOpen || api.StopSignal != "SIGTERM" || api.StopGracePeriod != "45s" {
		t.Fatalf("compose runtime flags did not parse: %#v", api)
	}
	nomadApp, err := p.Convert(app, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert compose runtime flags to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad runtime flags bridge: %v", err)
	}
	for _, expected := range []string{"hostname = \"api-node\"", "runtime = \"runsc\"", "kill_signal = \"SIGTERM\"", "kill_timeout = \"45s\"", "bolabaden_init", "bolabaden_tty", "bolabaden_stdin_open", "bolabaden_stop_signal", "bolabaden_stop_grace_period", "SIGTERM", "45s"} {
		if !strings.Contains(nomadOut, expected) {
			t.Fatalf("Nomad output missing %q:\n%s", expected, nomadOut)
		}
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad runtime flags bridge: %v", err)
	}
	roundTripped := parsedNomad.Services["api"]
	if roundTripped == nil || roundTripped.Hostname != "api-node" || roundTripped.Runtime != "runsc" || roundTripped.Init == nil || !*roundTripped.Init || !roundTripped.Tty || !roundTripped.StdinOpen || roundTripped.StopSignal != "SIGTERM" || roundTripped.StopGracePeriod != "45s" {
		t.Fatalf("Nomad bridge did not rehydrate runtime flags: %#v", roundTripped)
	}
	backToCompose, err := p.Convert(parsedNomad, PlatformNomad, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Nomad runtime flags back to Compose: %v", err)
	}
	backOut, err := p.SaveContent(backToCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Compose runtime flags: %v", err)
	}
	for _, expected := range []string{"hostname: api-node", "runtime: runsc", "init: true", "tty: true", "stdin_open: true", "stop_signal: SIGTERM", "stop_grace_period: 45s"} {
		if !strings.Contains(backOut, expected) {
			t.Fatalf("runtime flags did not survive Nomad round-trip %q:\n%s", expected, backOut)
		}
	}
	swarmApp, err := p.Convert(app, PlatformDockerCompose, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert compose runtime flags to Swarm: %v", err)
	}
	swarmOut, err := p.SaveContent(swarmApp, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Swarm runtime flags bridge: %v", err)
	}
	for _, expected := range []string{"x-platform: docker-swarm", "hostname: api-node", "runtime: runsc", "init: true", "tty: true", "stdin_open: true", "stop_signal: SIGTERM", "stop_grace_period: 45s"} {
		if !strings.Contains(swarmOut, expected) {
			t.Fatalf("Swarm output missing %q:\n%s", expected, swarmOut)
		}
	}
	swarmPath := filepath.Join(t.TempDir(), "runtime-flags-swarm.yml")
	if err := os.WriteFile(swarmPath, []byte(swarmOut), 0644); err != nil {
		t.Fatalf("failed to write Swarm runtime flags output: %v", err)
	}
	assertComposeGoLoads(t, swarmPath, "api")
	assertComposeCLIsAccept(t, swarmPath)
	parsedSwarm, err := p.LoadContent(swarmOut, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse Swarm runtime flags bridge: %v", err)
	}
	if roundTripped := parsedSwarm.Services["api"]; roundTripped == nil || roundTripped.Hostname != "api-node" || roundTripped.Runtime != "runsc" || roundTripped.Init == nil || !*roundTripped.Init || !roundTripped.Tty || !roundTripped.StdinOpen || roundTripped.StopSignal != "SIGTERM" || roundTripped.StopGracePeriod != "45s" {
		t.Fatalf("Swarm bridge did not rehydrate runtime flags: %#v", roundTripped)
	}
	swarmBackToCompose, err := p.Convert(parsedSwarm, PlatformDockerSwarm, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Swarm runtime flags back to Compose: %v", err)
	}
	swarmBackOut, err := p.SaveContent(swarmBackToCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Swarm runtime flags: %v", err)
	}
	for _, expected := range []string{"hostname: api-node", "runtime: runsc", "init: true", "tty: true", "stdin_open: true", "stop_signal: SIGTERM", "stop_grace_period: 45s"} {
		if !strings.Contains(swarmBackOut, expected) {
			t.Fatalf("runtime flags did not survive Swarm round-trip %q:\n%s", expected, swarmBackOut)
		}
	}
	kubernetesApp, err := p.Convert(parsedNomad, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad runtime flags to Kubernetes: %v", err)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes runtime flags bridge: %v", err)
	}
	if !strings.Contains(kubernetesOut, "bolabaden.dev/portable-runtime: runsc") {
		t.Fatalf("Kubernetes output missing runtime annotation:\n%s", kubernetesOut)
	}
	parsedKubernetes, err := p.LoadContent(kubernetesOut, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes runtime flags bridge: %v", err)
	}
	if roundTripped := parsedKubernetes.Services["api"]; roundTripped == nil || roundTripped.Runtime != "runsc" {
		t.Fatalf("Kubernetes bridge did not rehydrate runtime: %#v", roundTripped)
	}
}

