	if err != nil {
		t.Fatalf("failed to convert schedulingGates app to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose schedulingGates bridge: %v", err)
	}
	if !strings.Contains(composeOut, "x-kubernetes-scheduling-gates:") || !strings.Contains(composeOut, "example.com/maintenance") {
		t.Fatalf("Compose output did not preserve schedulingGates extension:\n%s", composeOut)
	}
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose schedulingGates bridge: %v", err)
	}
	if len(parsedCompose.Services["api"].SchedulingGates) != 1 || toString(parsedCompose.Services["api"].SchedulingGates[0]["name"]) != "example.com/maintenance" {
		t.Fatalf("Compose bridge did not rehydrate schedulingGates: %#v", parsedCompose.Services["api"])
	}
	backToKubernetes, err := p.Convert(parsedCompose, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Compose schedulingGates bridge back to Kubernetes: %v", err)
	}
	backOut, err := p.SaveContent(backToKubernetes, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Kubernetes schedulingGates manifest: %v", err)
	}
	if !strings.Contains(backOut, "schedulingGates:") || !strings.Contains(backOut, "example.com/maintenance") {
		t.Fatalf("schedulingGates did not survive Compose round-trip:\n%s", backOut)
	}

	swarmApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert schedulingGates app to Swarm: %v", err)
	}
	swarmOut, err := p.SaveContent(swarmApp, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Swarm schedulingGates bridge: %v", err)
	}
	if !strings.Contains(swarmOut, "x-platform: docker-swarm") || !strings.Contains(swarmOut, "x-kubernetes-scheduling-gates:") || !strings.Contains(swarmOut, "example.com/maintenance") {
		t.Fatalf("Swarm output did not preserve schedulingGates:\n%s", swarmOut)
	}
	swarmPath := filepath.Join(t.TempDir(), "scheduling-gates-swarm.yml")
	if err := os.WriteFile(swarmPath, []byte(swarmOut), 0644); err != nil {
		t.Fatalf("failed to write Swarm schedulingGates output: %v", err)
	}
	assertComposeGoLoads(t, swarmPath, "api")
	assertComposeCLIsAccept(t, swarmPath)
	parsedSwarm, err := p.LoadContent(swarmOut, PlatformDockerSwarm)
