func TestHyphenatedKubernetesPodSpecAliasRoundTripThroughCompose(t *testing.T) {
	p := New(nil)
	const composeContent = `
services:
  api:
    image: ghcr.io/example/api:podspec
    x-kubernetes-set-hostname-as-fqdn: true
    x-kubernetes-share-process-namespace: true
    x-kubernetes-enable-service-links: false
    x-kubernetes-host-users: false
`

	app, err := p.LoadContent(composeContent, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse hyphenated pod spec aliases: %v", err)
	}
	service := app.Services["api"]
	if service == nil || service.SetHostnameAsFQDN == nil || !*service.SetHostnameAsFQDN || service.ShareProcessNamespace == nil || !*service.ShareProcessNamespace || service.EnableServiceLinks == nil || *service.EnableServiceLinks || service.HostUsers == nil || *service.HostUsers {
		t.Fatalf("hyphenated pod spec aliases did not rehydrate: %#v", service)
	}
	for _, key := range []string{"kubernetes.setHostnameAsFQDN", "kubernetes.shareProcessNamespace", "kubernetes.enableServiceLinks", "kubernetes.hostUsers"} {
		if _, ok := service.Extensions[key]; !ok {
			t.Fatalf("hyphenated pod spec alias did not canonicalize %q: %#v", key, service.Extensions)
		}
	}

	composeOut, err := p.SaveContent(app, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize hyphenated pod spec aliases back to Compose: %v", err)
	}
	boolExpectations := map[string][]string{
		"x-kubernetes-setHostnameAsFQDN":     {"true", "\"true\""},
		"x-kubernetes-shareProcessNamespace": {"true", "\"true\""},
		"x-kubernetes-enableServiceLinks":    {"false", "\"false\""},
		"x-kubernetes-hostUsers":             {"false", "\"false\""},
	}
	for key, values := range boolExpectations {
		matched := false
		for _, value := range values {
			if strings.Contains(composeOut, key+": "+value) {
				matched = true
				break
			}
		}
		if !matched {
			t.Fatalf("Compose output did not preserve %s:\n%s", key, composeOut)
		}
	}
	composePath := filepath.Join(t.TempDir(), "podspec-alias-compose.yml")
	if err := os.WriteFile(composePath, []byte(composeOut), 0o644); err != nil {
		t.Fatalf("failed to write pod spec alias compose fixture: %v", err)
	}
	assertComposeGoLoads(t, composePath, "api")
	assertComposeCLIsAccept(t, composePath)
	validateComposeSchema(t, composeOut)

	k8sOut, err := p.SaveContent(app, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize hyphenated pod spec aliases to Kubernetes: %v", err)
	}
	for _, expected := range []string{
		"setHostnameAsFQDN: true",
		"shareProcessNamespace: true",
		"enableServiceLinks: false",
		"hostUsers: false",
	} {
		if !strings.Contains(k8sOut, expected) {
			t.Fatalf("Kubernetes output lost %q:\n%s", expected, k8sOut)
		}
	}
}

