func TestKubernetesEnableServiceLinksRoundTrip(t *testing.T) {
	content := `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
spec:
  replicas: 1
  selector:
    matchLabels:
      app: api
  template:
    metadata:
      labels:
        app: api
    spec:
      enableServiceLinks: false
      containers:
        - name: api
          image: ghcr.io/example/api:service-links
`
	app, err := ParseKubernetesYAML(content)
	if err != nil {
		t.Fatalf("failed to parse enableServiceLinks manifest: %v", err)
	}
	service := app.Services["api"]
	if service == nil {
		t.Fatalf("service not parsed")
	}
	if service.EnableServiceLinks == nil || *service.EnableServiceLinks {
		t.Fatalf("enableServiceLinks did not parse: %#v", service)
	}
	out, err := SerializeKubernetesYAML(app)
	if err != nil {
		t.Fatalf("failed to serialize enableServiceLinks manifest: %v", err)
	}
	if !strings.Contains(out, "enableServiceLinks: false") {
		t.Fatalf("enableServiceLinks did not serialize:\n%s", out)
	}
	parsedAgain, err := ParseKubernetesYAML(out)
	if err != nil {
		t.Fatalf("failed to reparse enableServiceLinks output: %v", err)
	}
	if parsedAgain.Services["api"].EnableServiceLinks == nil || *parsedAgain.Services["api"].EnableServiceLinks {
		t.Fatalf("enableServiceLinks did not round-trip: %#v", parsedAgain.Services["api"])
	}

	p := New(nil)
	swarmApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert enableServiceLinks app to Swarm: %v", err)
	}
	swarmOut, err := p.SaveContent(swarmApp, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Swarm enableServiceLinks bridge: %v", err)
	}
	if !strings.Contains(swarmOut, "x-platform: docker-swarm") || !strings.Contains(swarmOut, "x-kubernetes-enableServiceLinks: \"false\"") {
		t.Fatalf("Swarm output did not preserve enableServiceLinks:\n%s", swarmOut)
	}
	swarmPath := filepath.Join(t.TempDir(), "enable-service-links-swarm.yml")
	if err := os.WriteFile(swarmPath, []byte(swarmOut), 0644); err != nil {
		t.Fatalf("failed to write Swarm enableServiceLinks output: %v", err)
	}
	assertComposeGoLoads(t, swarmPath, "api")
	assertComposeCLIsAccept(t, swarmPath)
	parsedSwarm, err := p.LoadContent(swarmOut, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse Swarm enableServiceLinks bridge: %v", err)
	}
	if parsedSwarm.Services["api"].EnableServiceLinks == nil || *parsedSwarm.Services["api"].EnableServiceLinks {
		t.Fatalf("Swarm bridge did not rehydrate enableServiceLinks: %#v", parsedSwarm.Services["api"])
	}
	swarmBackToKubernetes, err := p.Convert(parsedSwarm, PlatformDockerSwarm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Swarm enableServiceLinks bridge back to Kubernetes: %v", err)
	}
	swarmBackOut, err := p.SaveContent(swarmBackToKubernetes, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Swarm-round-tripped enableServiceLinks manifest: %v", err)
	}
	if !strings.Contains(swarmBackOut, "enableServiceLinks: false") {
		t.Fatalf("enableServiceLinks did not survive Swarm round-trip:\n%s", swarmBackOut)
	}
}

