func TestNomadConnectNestedExtensionsRoundTrip(t *testing.T) {
	app := &Application{
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "ghcr.io/example/api:nomad-connect-extensions",
				Connect: &NomadConnectSpec{
					Native:    true,
					NativeSet: true,
					Extensions: map[string]interface{}{
						"x-custom-connect": "keep-connect",
					},
					SidecarService: &NomadConnectSidecarService{
						Tags: []string{"mesh"},
						Extensions: map[string]interface{}{
							"x-custom-sidecar": "keep-sidecar",
						},
						Proxy: &NomadConnectProxy{
							Extensions: map[string]interface{}{
								"x-custom-proxy": "keep-proxy",
							},
							Upstreams: []NomadConnectUpstream{
								{
									DestinationName: "db",
									LocalBindPort:   15432,
									Extensions: map[string]interface{}{
										"x-custom-upstream": "keep-upstream",
									},
								},
							},
						},
					},
				},
			},
		},
	}

	nomadOut, err := SerializeNomadHCL(app)
	if err != nil {
		t.Fatalf("failed to serialize nomad nested connect extensions: %v", err)
	}
	for _, expected := range []string{
		"extensions {",
		"x-custom-connect = \"keep-connect\"",
		"x-custom-sidecar = \"keep-sidecar\"",
		"x-custom-proxy = \"keep-proxy\"",
		"x-custom-upstream = \"keep-upstream\"",
	} {
		if !strings.Contains(nomadOut, expected) {
			t.Fatalf("nomad output lost nested connect extension %q:\n%s", expected, nomadOut)
		}
	}

	parsedNomad, err := ParseNomadHCL(nomadOut)
	if err != nil {
		t.Fatalf("failed to parse nomad nested connect extensions: %v", err)
	}
	connect := parsedNomad.Services["api"].Connect
	if connect == nil || toString(connect.Extensions["x-custom-connect"]) != "keep-connect" {
		t.Fatalf("nomad round-trip lost connect extensions: %#v", connect)
	}
	if connect.SidecarService == nil || toString(connect.SidecarService.Extensions["x-custom-sidecar"]) != "keep-sidecar" {
		t.Fatalf("nomad round-trip lost sidecar extensions: %#v", connect.SidecarService)
	}
	if connect.SidecarService.Proxy == nil || toString(connect.SidecarService.Proxy.Extensions["x-custom-proxy"]) != "keep-proxy" {
		t.Fatalf("nomad round-trip lost proxy extensions: %#v", connect.SidecarService.Proxy)
	}
	if len(connect.SidecarService.Proxy.Upstreams) != 1 || toString(connect.SidecarService.Proxy.Upstreams[0].Extensions["x-custom-upstream"]) != "keep-upstream" {
		t.Fatalf("nomad round-trip lost upstream extensions: %#v", connect.SidecarService.Proxy.Upstreams)
	}
}

func TestComposeTopLevelModelsRoundTripAcrossFormats(t *testing.T) {
	app := &Application{
		Version:  "3.9",
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "ghcr.io/example/api:models",
				ComposeCompat: &ComposeCompat{
					Models: map[string]map[string]interface{}{
						"llm": {
							"endpoint_var":       "LLM_ENDPOINT",
							"model_var":          "LLM_MODEL",
							"custom.model-field": "keep-me",
							"x-bolabaden-model-ref": map[string]interface{}{
								"placement": "gpu-node",
							},
						},
					},
				},
			},
		},
		Models: map[string]*ComposeModel{
			"llm": {
				Name:         "llm",
				Model:        "ai/model",
				ContextSize:  1024,
				RuntimeFlags: []string{"--foo", "--bar=42"},
				Extensions: map[string]interface{}{
					"custom.model-field": "keep-me",
					"x-bolabaden-model-ref": map[string]interface{}{
						"placement": "gpu-node",
					},
				},
			},
		},
	}
	p := New(nil)

	composeOut, err := p.SaveContent(app, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose models bridge: %v", err)
	}
	for _, expected := range []string{
		"models:",
		"ai/model",
		"context_size: 1024",
		"runtime_flags:",
		"- --foo",
		"- --bar=42",
		"x-custom-model-field: keep-me",
		"endpoint_var: LLM_ENDPOINT",
		"model_var: LLM_MODEL",
		"x-custom-model-field: keep-me",
		"x-bolabaden-model-ref:",
		"placement: gpu-node",
	} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("Compose output did not preserve %q:\n%s", expected, composeOut)
		}
	}
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose models bridge: %v", err)
	}
	if parsedCompose.Models == nil || parsedCompose.Models["llm"] == nil || parsedCompose.Models["llm"].Model != "ai/model" || parsedCompose.Models["llm"].ContextSize != 1024 || len(parsedCompose.Models["llm"].RuntimeFlags) != 2 {
		t.Fatalf("Compose models did not rehydrate: %#v", parsedCompose.Models)
	}
	if parsedCompose.Models["llm"].Extensions["x-custom-model-field"] != "keep-me" {
		t.Fatalf("Compose model extension did not rehydrate through x-* prefixing: %#v", parsedCompose.Models["llm"].Extensions)
	}
	if parsedCompose.Services["api"].ComposeCompat == nil || len(parsedCompose.Services["api"].ComposeCompat.Models) != 1 || parsedCompose.Services["api"].ComposeCompat.Models["llm"]["endpoint_var"] != "LLM_ENDPOINT" {
		t.Fatalf("service model references did not rehydrate: %#v", parsedCompose.Services["api"].ComposeCompat)
	}
	if parsedCompose.Services["api"].ComposeCompat.Models["llm"]["x-custom-model-field"] != "keep-me" {
		t.Fatalf("service model extension did not rehydrate through x-* prefixing: %#v", parsedCompose.Services["api"].ComposeCompat.Models["llm"])
	}
	assertModelRefExtension := func(t *testing.T, compat *ComposeCompat) {
		t.Helper()
		if compat == nil || len(compat.Models) != 1 {
			t.Fatalf("service model references missing: %#v", compat)
		}
		ref := compat.Models["llm"]
		extension, ok := asMap(ref["x-bolabaden-model-ref"])
		if !ok || extension["placement"] != "gpu-node" {
			t.Fatalf("service model reference extension did not rehydrate: %#v", ref)
		}
	}
	assertModelRefExtension(t, parsedCompose.Services["api"].ComposeCompat)

	kubernetesApp, err := p.Convert(app, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Compose models bridge to Kubernetes: %v", err)
	}
	if kubernetesApp.Models == nil || kubernetesApp.Models["llm"] == nil || kubernetesApp.Models["llm"].Model != "ai/model" {
		t.Fatalf("Kubernetes conversion dropped compose models: %#v", kubernetesApp.Models)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes models bridge: %v", err)
	}
	if !strings.Contains(kubernetesOut, "bolabaden.dev/portable-models") || !strings.Contains(kubernetesOut, "ai/model") {
		t.Fatalf("Kubernetes output did not preserve portable models:\n%s", kubernetesOut)
	}
	parsedKubernetes, err := p.LoadContent(kubernetesOut, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes models bridge: %v", err)
	}
	if parsedKubernetes.Models == nil || parsedKubernetes.Models["llm"] == nil || parsedKubernetes.Models["llm"].Model != "ai/model" || len(parsedKubernetes.Models["llm"].RuntimeFlags) != 2 {
		t.Fatalf("Kubernetes models did not rehydrate: %#v", parsedKubernetes.Models)
	}
	assertModelRefExtension(t, parsedKubernetes.Services["api"].ComposeCompat)
	backToCompose, err := p.Convert(kubernetesApp, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes models bridge back to Compose: %v", err)
	}
	backOut, err := p.SaveContent(backToCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Compose models bridge: %v", err)
	}
	if !strings.Contains(backOut, "ai/model") || !strings.Contains(backOut, "runtime_flags:") || !strings.Contains(backOut, "x-bolabaden-model-ref:") {
		t.Fatalf("round-tripped Compose output lost top-level models:\n%s", backOut)
	}

	nomadApp, err := p.Convert(app, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Compose models bridge to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad models bridge: %v", err)
	}
	if !strings.Contains(nomadOut, "bolabaden_app_models") || !strings.Contains(nomadOut, "ai/model") {
		t.Fatalf("Nomad output did not preserve portable models:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad models bridge: %v", err)
	}
	if parsedNomad.Models == nil || parsedNomad.Models["llm"] == nil || parsedNomad.Models["llm"].Model != "ai/model" || len(parsedNomad.Models["llm"].RuntimeFlags) != 2 {
		t.Fatalf("Nomad models did not rehydrate: %#v", parsedNomad.Models)
	}
	assertModelRefExtension(t, parsedNomad.Services["api"].ComposeCompat)

	helmApp, err := p.Convert(app, PlatformDockerCompose, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert Compose models bridge to Helm: %v", err)
	}
	helmDir := filepath.Join(t.TempDir(), "models-chart")
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to serialize Helm models chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse Helm models chart: %v", err)
	}
	if parsedHelm.Models == nil || parsedHelm.Models["llm"] == nil || parsedHelm.Models["llm"].Model != "ai/model" || len(parsedHelm.Models["llm"].RuntimeFlags) != 2 {
		t.Fatalf("Helm models did not rehydrate: %#v", parsedHelm.Models)
	}
	assertModelRefExtension(t, parsedHelm.Services["api"].ComposeCompat)
	helmCompose, err := p.Convert(parsedHelm, PlatformHelm, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Helm models chart back to Compose: %v", err)
	}
	helmOut, err := p.SaveContent(helmCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Helm round-tripped models bridge: %v", err)
	}
	if !strings.Contains(helmOut, "x-bolabaden-model-ref:") || !strings.Contains(helmOut, "placement: gpu-node") {
		t.Fatalf("Helm round-trip lost service model reference extension:\n%s", helmOut)
	}
}

func TestKubernetesRawResourcesReemitWithoutLoss(t *testing.T) {
	content := `
apiVersion: v1
kind: Service
metadata:
  name: api-public
  namespace: default
  annotations:
    service.beta.kubernetes.io/aws-load-balancer-type: nlb
spec:
  selector:
    app: api
  ports:
    - name: web
      port: 80
      targetPort: 8080
---
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
spec:
  selector:
    matchLabels:
      app: api
  template:
    metadata:
      labels:
        app: api
    spec:
      containers:
        - name: api
          image: ghcr.io/example/api:raw-k8s
          ports:
            - containerPort: 8080
---
apiVersion: autoscaling/v2
kind: HorizontalPodAutoscaler
metadata:
  name: api-scale
spec:
  scaleTargetRef:
    apiVersion: apps/v1
    kind: Deployment
    name: api
  minReplicas: 2
  maxReplicas: 5
  metrics:
    - type: Resource
      resource:
        name: cpu
        target:
          type: Utilization
          averageUtilization: 70
`
	app, err := ParseKubernetesYAML(content)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes YAML: %v", err)
	}
	if app.Canonical == nil || app.Canonical.Resources["kubernetes:unknown:api-scale"] == nil {
		t.Fatalf("unknown Kubernetes resource was not preserved canonically: %#v", app.Canonical)
	}
	out, err := SerializeKubernetesYAML(app)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes YAML: %v", err)
	}
	for _, expected := range []string{
		"kind: HorizontalPodAutoscaler",
		"name: api-scale",
		"averageUtilization: 70",
		"service.beta.kubernetes.io/aws-load-balancer-type: nlb",
		"name: api-public",
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("serialized Kubernetes output missing %q:\n%s", expected, out)
		}
	}
	roundTrip, err := ParseKubernetesYAML(out)
	if err != nil {
		t.Fatalf("failed to parse re-emitted Kubernetes YAML: %v", err)
	}
	if roundTrip.Canonical == nil || roundTrip.Canonical.Resources["kubernetes:unknown:api-scale"] == nil {
		t.Fatalf("unknown Kubernetes resource was lost after reparse: %#v", roundTrip.Canonical)
	}

	composeBridge, err := New(nil).Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert kubernetes raw fixture to compose: %v", err)
	}
	backToK8s, err := New(nil).Convert(composeBridge, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert compose bridge back to kubernetes: %v", err)
	}
	bridgeOut, err := SerializeKubernetesYAML(backToK8s)
	if err != nil {
		t.Fatalf("failed to serialize bridged Kubernetes YAML: %v", err)
	}
	for _, expected := range []string{
		"kind: HorizontalPodAutoscaler",
		"name: api-scale",
		"averageUtilization: 70",
	} {
		if !strings.Contains(bridgeOut, expected) {
			t.Fatalf("bridged Kubernetes output missing %q:\n%s", expected, bridgeOut)
		}
	}
}

func TestKubernetesHorizontalPodAutoscalerBridgesAcrossTargets(t *testing.T) {
	content := `
apiVersion: autoscaling/v2
kind: HorizontalPodAutoscaler
metadata:
  name: api-scale
  namespace: mesh
spec:
  scaleTargetRef:
    apiVersion: apps/v1
    kind: Deployment
    name: api
  minReplicas: 2
  maxReplicas: 7
  metrics:
    - type: Resource
      resource:
        name: cpu
        target:
          type: Utilization
          averageUtilization: 65
    - type: Resource
      resource:
        name: memory
        target:
          type: AverageValue
          averageValue: 512Mi
---
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
  namespace: mesh
spec:
  selector:
    matchLabels:
      app: api
  template:
    metadata:
      labels:
        app: api
    spec:
      containers:
        - name: api
          image: ghcr.io/example/api:hpa
          ports:
            - name: http
              containerPort: 8080
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes HPA fixture: %v", err)
	}
	api := app.Services["api"]
	if api == nil {
		t.Fatalf("api deployment was not parsed")
	}
	if hpaSpec := app.KubernetesHPAs["api-scale"]; hpaSpec == nil || hpaSpec.Name != "api-scale" || hpaSpec.Namespace != "mesh" || hpaSpec.MinReplicas == nil || *hpaSpec.MinReplicas != 2 || hpaSpec.MaxReplicas != 7 || hpaSpec.ScaleTarget["name"] != "api" {
		t.Fatalf("typed HPA was not preserved: %#v", hpaSpec)
	}
	hpa, ok := api.Extensions[kubernetesHPAExtensionKey].(map[string]interface{})
	if !ok || toString(hpa["kind"]) != "HorizontalPodAutoscaler" {
		t.Fatalf("HPA was not attached to target service: %#v", api.Extensions)
	}
	delete(app.Extensions, "kubernetes.raw")
	delete(app.Extensions, "kubernetes.resources")
	delete(app.Extensions, "kubernetes.hpas")

	kubernetesOut, err := p.SaveContent(app, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize typed HPA Kubernetes output: %v", err)
	}
	for _, expected := range []string{
		"kind: HorizontalPodAutoscaler",
		"name: api-scale",
		"namespace: mesh",
		"averageUtilization: 65",
		"averageValue: 512Mi",
		"name: api",
	} {
		if !strings.Contains(kubernetesOut, expected) {
			t.Fatalf("typed Kubernetes HPA output missing %q:\n%s", expected, kubernetesOut)
		}
	}

	composeApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes HPA fixture to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose HPA bridge: %v", err)
	}
	for _, expected := range []string{"x-kubernetes-hpa:", "api-scale", "averageUtilization: 65", "averageValue: 512Mi"} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("Compose HPA bridge missing %q:\n%s", expected, composeOut)
		}
	}
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose HPA bridge: %v", err)
	}
	if hpaSpec := parsedCompose.KubernetesHPAs["api-scale"]; hpaSpec == nil || hpaSpec.Name != "api-scale" || hpaSpec.Namespace != "mesh" {
		t.Fatalf("Compose bridge lost typed HPA: %#v", hpaSpec)
	}
	composeKubernetes, err := p.Convert(parsedCompose, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Compose HPA bridge back to Kubernetes: %v", err)
	}
	composeKubernetesOut, err := p.SaveContent(composeKubernetes, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Compose HPA bridge back to Kubernetes: %v", err)
	}
	if !strings.Contains(composeKubernetesOut, "kind: HorizontalPodAutoscaler") || !strings.Contains(composeKubernetesOut, "averageUtilization: 65") {
		t.Fatalf("Compose round-trip lost typed Kubernetes HPA:\n%s", composeKubernetesOut)
	}

	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes HPA fixture to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad HPA bridge: %v", err)
	}
	for _, expected := range []string{"bolabaden_extensions", "kubernetes.hpa", "api-scale", "averageUtilization"} {
		if !strings.Contains(nomadOut, expected) {
			t.Fatalf("Nomad HPA bridge missing %q:\n%s", expected, nomadOut)
		}
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad HPA bridge: %v", err)
	}
	if hpaSpec := parsedNomad.KubernetesHPAs["api-scale"]; hpaSpec == nil || hpaSpec.Name != "api-scale" || hpaSpec.Namespace != "mesh" {
		t.Fatalf("Nomad bridge lost typed HPA: %#v", hpaSpec)
	}
	nomadKubernetes, err := p.Convert(parsedNomad, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad HPA bridge back to Kubernetes: %v", err)
	}
	nomadKubernetesOut, err := p.SaveContent(nomadKubernetes, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Nomad HPA bridge back to Kubernetes: %v", err)
	}
	if !strings.Contains(nomadKubernetesOut, "kind: HorizontalPodAutoscaler") || !strings.Contains(nomadKubernetesOut, "averageUtilization: 65") {
		t.Fatalf("Nomad round-trip lost typed Kubernetes HPA:\n%s", nomadKubernetesOut)
	}

	helmApp, err := p.Convert(app, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes HPA fixture to Helm: %v", err)
	}
	helmDir := filepath.Join(t.TempDir(), "hpa-chart")
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to save Helm HPA bridge: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse Helm HPA bridge: %v", err)
	}
	delete(parsedHelm.Extensions, "kubernetes.raw")
	helmKubernetes, err := p.Convert(parsedHelm, PlatformHelm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Helm HPA bridge back to Kubernetes: %v", err)
	}
	helmKubernetesOut, err := p.SaveContent(helmKubernetes, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Helm HPA bridge back to Kubernetes: %v", err)
	}
	if !strings.Contains(helmKubernetesOut, "kind: HorizontalPodAutoscaler") || !strings.Contains(helmKubernetesOut, "averageUtilization: 65") {
		t.Fatalf("Helm round-trip lost typed Kubernetes HPA:\n%s", helmKubernetesOut)
	}
}

