func TestSwarmGlobalModeUsesNativeTargetsAndRoundTrips(t *testing.T) {
	content := `
x-platform: docker-swarm
services:
  agent:
    image: ghcr.io/example/agent:global
    deploy:
      mode: global
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse swarm global app: %v", err)
	}
	agent := app.Services["agent"]
	if agent == nil || agent.Deploy == nil || agent.Deploy.Mode != "global" {
		t.Fatalf("global deploy mode was not parsed: %#v", agent)
	}

	kubernetesApp, err := p.Convert(app, PlatformDockerSwarm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert swarm global app to Kubernetes: %v", err)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes global app: %v", err)
	}
	if !strings.Contains(kubernetesOut, "kind: DaemonSet") || !strings.Contains(kubernetesOut, "bolabaden.dev/deploy-mode: global") {
		t.Fatalf("Kubernetes output did not use native DaemonSet plus portable mode:\n%s", kubernetesOut)
	}
	parsedKubernetes, err := p.LoadContent(kubernetesOut, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse emitted Kubernetes global app: %v", err)
	}
	kubernetesAgent := parsedKubernetes.Services["agent"]
	if kubernetesAgent == nil || kubernetesAgent.Deploy == nil || kubernetesAgent.Deploy.Mode != "global" {
		t.Fatalf("Kubernetes DaemonSet did not rehydrate global mode: %#v", kubernetesAgent)
	}

	daemonSetOnly := `
apiVersion: apps/v1
kind: DaemonSet
metadata:
  name: node-agent
spec:
  selector:
    matchLabels:
      app: node-agent
  template:
    metadata:
      labels:
        app: node-agent
    spec:
      containers:
        - name: node-agent
          image: ghcr.io/example/node-agent:daemonset
`
	parsedDaemonSet, err := p.LoadContent(daemonSetOnly, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse native DaemonSet fixture: %v", err)
	}
	nodeAgent := parsedDaemonSet.Services["node-agent"]
	if nodeAgent == nil || nodeAgent.Deploy == nil || nodeAgent.Deploy.Mode != "global" {
		t.Fatalf("native DaemonSet did not infer global mode: %#v", nodeAgent)
	}

	nomadApp, err := p.Convert(app, PlatformDockerSwarm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert swarm global app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad global app: %v", err)
	}
	if !strings.Contains(nomadOut, `type = "system"`) || !strings.Contains(nomadOut, `bolabaden_deploy_mode = "global"`) || strings.Contains(nomadOut, "count =") {
		t.Fatalf("Nomad output did not use native system job plus portable mode:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse emitted Nomad global app: %v", err)
	}
	nomadAgent := parsedNomad.Services["agent"]
	if nomadAgent == nil || nomadAgent.Deploy == nil || nomadAgent.Deploy.Mode != "global" {
		t.Fatalf("Nomad system job did not rehydrate global mode: %#v", nomadAgent)
	}
	roundTripSwarm, err := p.Convert(parsedNomad, PlatformNomad, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Nomad global app back to swarm: %v", err)
	}
	roundTripOut, err := p.SaveContent(roundTripSwarm, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped global swarm app: %v", err)
	}
	if !strings.Contains(roundTripOut, "mode: global") {
		t.Fatalf("Nomad round-trip lost swarm global mode:\n%s", roundTripOut)
	}
	roundTripPath := filepath.Join(t.TempDir(), "swarm-global-roundtrip.yml")
	if err := os.WriteFile(roundTripPath, []byte(roundTripOut), 0644); err != nil {
		t.Fatalf("failed to write round-tripped Swarm global fixture: %v", err)
	}
	assertComposeGoLoads(t, roundTripPath, "agent")
	assertComposeCLIsAccept(t, roundTripPath)

	helmDir := filepath.Join(t.TempDir(), "global-chart")
	helmApp, err := p.Convert(app, PlatformDockerSwarm, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert swarm global app to Helm: %v", err)
	}
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to serialize Helm global chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse Helm global chart: %v", err)
	}
	helmSwarm, err := p.Convert(parsedHelm, PlatformHelm, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Helm global chart back to swarm: %v", err)
	}
	helmOut, err := p.SaveContent(helmSwarm, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Helm round-tripped global swarm app: %v", err)
	}
	if !strings.Contains(helmOut, "mode: global") {
		t.Fatalf("Helm round-trip lost swarm global mode:\n%s", helmOut)
	}
}

func TestSwarmReplicatedJobModeRoundTripsAcrossTargets(t *testing.T) {
	content := `
x-platform: docker-swarm
services:
  migrate:
    image: ghcr.io/example/migrate:job
    command: ["./migrate"]
    deploy:
      mode: replicated-job
      x-swarm-job:
        max_concurrent: 2
        total_completions: 5
      restart_policy:
        condition: none
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse swarm job app: %v", err)
	}
	migrate := app.Services["migrate"]
	if migrate == nil || migrate.Deploy == nil || migrate.Deploy.Mode != "replicated-job" || migrate.Deploy.Job == nil {
		t.Fatalf("swarm job deploy intent was not parsed: %#v", migrate)
	}
	if migrate.Deploy.Job.MaxConcurrent != 2 || migrate.Deploy.Job.TotalCompletions != 5 {
		t.Fatalf("swarm job counters were not parsed: %#v", migrate.Deploy.Job)
	}

	swarmOut, err := p.SaveContent(app, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize swarm job app: %v", err)
	}
	for _, needle := range []string{"mode: replicated-job", "x-swarm-job:", "max_concurrent: 2", "total_completions: 5"} {
		if !strings.Contains(swarmOut, needle) {
			t.Fatalf("swarm output lost job marker %q:\n%s", needle, swarmOut)
		}
	}
	swarmComposePath := filepath.Join(t.TempDir(), "swarm-job.yml")
	if err := os.WriteFile(swarmComposePath, []byte(swarmOut), 0644); err != nil {
		t.Fatalf("failed to write swarm compose fixture: %v", err)
	}
	assertComposeGoLoads(t, swarmComposePath, "migrate")
	assertComposeCLIsAccept(t, swarmComposePath)

	kubernetesApp, err := p.Convert(app, PlatformDockerSwarm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert swarm job app to Kubernetes: %v", err)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes job app: %v", err)
	}
	for _, needle := range []string{"kind: Job", "parallelism: 2", "completions: 5", "bolabaden.dev/deploy-mode: replicated-job", "bolabaden.dev/deploy-job:"} {
		if !strings.Contains(kubernetesOut, needle) {
			t.Fatalf("Kubernetes output lost job marker %q:\n%s", needle, kubernetesOut)
		}
	}
	parsedKubernetes, err := p.LoadContent(kubernetesOut, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse emitted Kubernetes job app: %v", err)
	}
	kubernetesMigrate := parsedKubernetes.Services["migrate"]
	if kubernetesMigrate == nil || kubernetesMigrate.Deploy == nil || kubernetesMigrate.Deploy.Mode != "replicated-job" || kubernetesMigrate.Deploy.Job == nil || kubernetesMigrate.Deploy.Job.TotalCompletions != 5 {
		t.Fatalf("Kubernetes job did not rehydrate swarm job intent: %#v", kubernetesMigrate)
	}
	kubernetesSwarm, err := p.Convert(parsedKubernetes, PlatformKubernetes, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes job app back to swarm: %v", err)
	}
	kubernetesSwarmOut, err := p.SaveContent(kubernetesSwarm, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes round-tripped swarm job app: %v", err)
	}
	if !strings.Contains(kubernetesSwarmOut, "mode: replicated-job") || !strings.Contains(kubernetesSwarmOut, "total_completions: 5") {
		t.Fatalf("Kubernetes round-trip lost swarm job data:\n%s", kubernetesSwarmOut)
	}

	nomadApp, err := p.Convert(app, PlatformDockerSwarm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert swarm job app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad job app: %v", err)
	}
	for _, needle := range []string{`type = "batch"`, "bolabaden_deploy_mode", "bolabaden_deploy_job", `\"max_concurrent\":2`, `\"total_completions\":5`} {
		if !strings.Contains(nomadOut, needle) {
			t.Fatalf("Nomad output lost job marker %q:\n%s", needle, nomadOut)
		}
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse emitted Nomad job app: %v", err)
	}
	nomadMigrate := parsedNomad.Services["migrate"]
	if nomadMigrate == nil || nomadMigrate.Deploy == nil || nomadMigrate.Deploy.Mode != "replicated-job" || nomadMigrate.Deploy.Job == nil || nomadMigrate.Deploy.Job.MaxConcurrent != 2 {
		t.Fatalf("Nomad job metadata did not rehydrate: %#v", nomadMigrate)
	}
	nomadSwarm, err := p.Convert(parsedNomad, PlatformNomad, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Nomad job app back to swarm: %v", err)
	}
	nomadSwarmOut, err := p.SaveContent(nomadSwarm, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Nomad round-tripped swarm job app: %v", err)
	}
	if !strings.Contains(nomadSwarmOut, "mode: replicated-job") || !strings.Contains(nomadSwarmOut, "max_concurrent: 2") {
		t.Fatalf("Nomad round-trip lost swarm job data:\n%s", nomadSwarmOut)
	}

	helmApp, err := p.Convert(app, PlatformDockerSwarm, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert swarm job app to Helm: %v", err)
	}
	helmDir := filepath.Join(t.TempDir(), "swarm-job-chart")
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to serialize Helm swarm job chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse Helm swarm job chart: %v", err)
	}
	helmSwarm, err := p.Convert(parsedHelm, PlatformHelm, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Helm swarm job chart back to swarm: %v", err)
	}
	helmOut, err := p.SaveContent(helmSwarm, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Helm round-tripped swarm job app: %v", err)
	}
	if !strings.Contains(helmOut, "mode: replicated-job") || !strings.Contains(helmOut, "total_completions: 5") {
		t.Fatalf("Helm round-trip lost swarm job data:\n%s", helmOut)
	}
}

func TestComposeSwarmJobExtensionInfersSwarmPlatform(t *testing.T) {
	content := `
services:
  migrate:
    image: ghcr.io/example/migrate:job
    command: ["./migrate"]
    deploy:
      mode: replicated-job
      x-swarm-job:
        max_concurrent: 2
        total_completions: 5
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose swarm-job app: %v", err)
	}
	if app.Platform != PlatformDockerSwarm {
		t.Fatalf("compose swarm-job extension did not infer swarm platform: %s", app.Platform)
	}
	if migrate := app.Services["migrate"]; migrate == nil || migrate.Deploy == nil || migrate.Deploy.Job == nil || migrate.Deploy.Job.MaxConcurrent != 2 || migrate.Deploy.Job.TotalCompletions != 5 {
		t.Fatalf("compose swarm-job extension did not preserve job data: %#v", migrate)
	}
	out, err := p.SaveContent(app, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize inferred swarm app: %v", err)
	}
	if !strings.Contains(out, "x-platform: docker-swarm") || !strings.Contains(out, "x-swarm-job:") {
		t.Fatalf("inferred swarm app did not serialize as swarm:\n%s", out)
	}
}

