func TestSwarmDeployResourceExtrasRoundTripAcrossTargets(t *testing.T) {
	content := `
x-platform: docker-swarm
services:
  api:
    image: ghcr.io/example/api:resources
    deploy:
      x-custom-resources: preserve-me
      resources:
        limits:
          cpus: "0.50"
          memory: 512M
          pids: 128
          x-custom-limits: preserve-me
        reservations:
          cpus: "0.25"
          memory: 256M
          pids: 64
          x-custom-reservations: preserve-me
          devices:
            - capabilities: ["gpu"]
              driver: nvidia
              count: all
              options:
                virtualization: "false"
              x-custom-device: preserve-me
          generic_resources:
            - discrete_resource_spec:
                kind: SSD
                value: 2
                x-custom-discrete: preserve-me
              x-custom-generic: preserve-me
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse swarm app: %v", err)
	}
	api := app.Services["api"]
	if api == nil || api.Deploy == nil || api.Deploy.Resources == nil {
		t.Fatalf("deploy resources were not parsed: %#v", api)
	}
	resources := api.Deploy.Resources
	if resources.PidsLimit != 128 || resources.PidsReservation != 64 {
		t.Fatalf("pids resources not parsed: %#v", resources)
	}
	if len(resources.Devices) != 1 || resources.Devices[0].Driver != "nvidia" || resources.Devices[0].Count != "all" || resources.Devices[0].Options["virtualization"] != "false" {
		t.Fatalf("device reservation not parsed: %#v", resources.Devices)
	}
	if len(resources.GenericResources) != 1 || resources.GenericResources[0].Kind != "SSD" || resources.GenericResources[0].Value != "2" {
		t.Fatalf("generic resource not parsed: %#v", resources.GenericResources)
	}

	composeOut, err := p.SaveContent(app, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize swarm app: %v", err)
	}
	for _, needle := range []string{"x-custom-resources: preserve-me", "x-custom-limits: preserve-me", "x-custom-reservations: preserve-me", "x-custom-device: preserve-me", "x-custom-generic: preserve-me", "x-custom-discrete: preserve-me", "pids: 128", "pids: 64", "devices:", "driver: nvidia", "count: all", "generic_resources:", "kind: SSD"} {
		if !strings.Contains(composeOut, needle) {
			t.Fatalf("swarm output lost %q:\n%s", needle, composeOut)
		}
	}

	nomadApp, err := p.Convert(app, PlatformDockerSwarm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert swarm app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad app: %v", err)
	}
	for _, needle := range []string{"bolabaden_deploy_resources", "x-custom-resources", "x-custom-limits", "x-custom-reservations", "x-custom-device", "x-custom-generic", "x-custom-discrete", `\"limits\":{\"cpus\":\"0.50\",\"memory\":\"512M\",\"pids\":128`, `\"devices\"`, `\"generic_resources\"`} {
		if !strings.Contains(nomadOut, needle) {
			t.Fatalf("Nomad output lost %q:\n%s", needle, nomadOut)
		}
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse emitted Nomad app: %v", err)
	}
	nomadResources := parsedNomad.Services["api"].Deploy.Resources
	if nomadResources == nil || nomadResources.PidsLimit != 128 || len(nomadResources.Devices) != 1 || len(nomadResources.GenericResources) != 1 {
		t.Fatalf("Nomad deploy resources did not rehydrate: %#v", nomadResources)
	}
	roundTripCompose, err := p.Convert(parsedNomad, PlatformNomad, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Nomad app back to swarm: %v", err)
	}
	roundTripOut, err := p.SaveContent(roundTripCompose, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped swarm app: %v", err)
	}
	if !strings.Contains(roundTripOut, "generic_resources:") || !strings.Contains(roundTripOut, "driver: nvidia") || !strings.Contains(roundTripOut, "pids: 128") {
		t.Fatalf("round-tripped swarm output lost resource extras:\n%s", roundTripOut)
	}

	kubernetesApp, err := p.Convert(app, PlatformDockerSwarm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert swarm app to Kubernetes: %v", err)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes app: %v", err)
	}
	for _, needle := range []string{"bolabaden.dev/deploy-resources:", `"pids":128`, `"pids":64`, "devices", "generic_resources"} {
		if !strings.Contains(kubernetesOut, needle) {
			t.Fatalf("Kubernetes output lost %q:\n%s", needle, kubernetesOut)
		}
	}
	parsedKubernetes, err := p.LoadContent(kubernetesOut, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse emitted Kubernetes app: %v", err)
	}
	kubernetesResources := parsedKubernetes.Services["api"].Deploy.Resources
	if kubernetesResources == nil || kubernetesResources.PidsReservation != 64 || len(kubernetesResources.Devices) != 1 || kubernetesResources.GenericResources[0].Kind != "SSD" {
		t.Fatalf("Kubernetes deploy resources did not rehydrate: %#v", kubernetesResources)
	}
}

