func TestKubernetesEnvSourcesRoundTripAndComposeExtensions(t *testing.T) {
	content := `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: api
spec:
  replicas: 1
  selector:
    matchLabels:
      app: api
  template:
    metadata:
      labels:
        app: api
    spec:
      containers:
        - name: api
          image: ghcr.io/example/api:env-sources
          env:
            - name: MODE
              value: prod
            - name: API_TIMEOUT
              x-custom-env-source: keep-me
              valueFrom:
                configMapKeyRef:
                  name: api-config
                  key: timeout
                  optional: true
                  x-custom-ref: keep-ref
            - name: DB_PASSWORD
              valueFrom:
                secretKeyRef:
                  name: db-password
                  key: password
          envFrom:
            - configMapRef:
                name: shared-config
                x-custom-env-from-ref: keep-env-from-ref
              prefix: SHARED_
              x-custom-env-from: keep-env-from
            - secretRef:
                name: shared-secrets
                optional: true
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes app: %v", err)
	}
	api := app.Services["api"]
	if api == nil || api.Environment["MODE"] != "prod" || len(api.EnvSources) != 2 || len(api.EnvFrom) != 2 {
		t.Fatalf("Kubernetes env sources not parsed: %#v", api)
	}
	if api.EnvSources[0].Name != "API_TIMEOUT" || api.EnvSources[0].SourceType != "config" || api.EnvSources[0].Source != "api-config" || api.EnvSources[0].Key != "timeout" || !api.EnvSources[0].Optional {
		t.Fatalf("unexpected config env source: %#v", api.EnvSources[0])
	}
	if api.EnvSources[0].Extensions == nil || api.EnvSources[0].Extensions["x-custom-env-source"] != "keep-me" {
		t.Fatalf("env source extension not parsed: %#v", api.EnvSources[0])
	}
	if nested, ok := api.EnvSources[0].Extensions["kubernetes.valueFrom"].(map[string]interface{}); !ok || nested["configMapKeyRef"].(map[string]interface{})["x-custom-ref"] != "keep-ref" {
		t.Fatalf("env source nested extension not parsed: %#v", api.EnvSources[0].Extensions)
	}
	if api.EnvSources[1].Name != "DB_PASSWORD" || api.EnvSources[1].SourceType != "secret" || api.EnvSources[1].Source != "db-password" || api.EnvSources[1].Key != "password" {
		t.Fatalf("unexpected secret env source: %#v", api.EnvSources[1])
	}
	if api.EnvFrom[0].SourceType != "config" || api.EnvFrom[0].Source != "shared-config" || api.EnvFrom[0].Prefix != "SHARED_" {
		t.Fatalf("unexpected config envFrom source: %#v", api.EnvFrom[0])
	}
	if api.EnvFrom[0].Extensions == nil || api.EnvFrom[0].Extensions["x-custom-env-from"] != "keep-env-from" {
		t.Fatalf("envFrom extension not parsed: %#v", api.EnvFrom[0])
	}
	if nested, ok := api.EnvFrom[0].Extensions["kubernetes.envFrom"].(map[string]interface{}); !ok || nested["configMapRef"].(map[string]interface{})["x-custom-env-from-ref"] != "keep-env-from-ref" {
		t.Fatalf("envFrom nested extension not parsed: %#v", api.EnvFrom[0].Extensions)
	}
	api.EnvSources[0].Extensions["custom-env-source-extra"] = "normalize-me"
	api.EnvFrom[0].Extensions["custom-env-from-extra"] = "normalize-me"
	if api.EnvFrom[1].SourceType != "secret" || api.EnvFrom[1].Source != "shared-secrets" || !api.EnvFrom[1].Optional {
		t.Fatalf("unexpected secret envFrom source: %#v", api.EnvFrom[1])
	}

	out, err := p.SaveContent(app, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes app: %v", err)
	}
	for _, expected := range []string{
		"configMapKeyRef:",
		"name: api-config",
		"key: timeout",
		"optional: true",
		"x-custom-ref: keep-ref",
		"secretKeyRef:",
		"name: db-password",
		"envFrom:",
		"configMapRef:",
		"x-custom-env-from-ref: keep-env-from-ref",
		"secretRef:",
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("Kubernetes output missing %q:\n%s", expected, out)
		}
	}

	composeApp, err := p.Convert(app, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose app: %v", err)
	}
	for _, expected := range []string{
		"x-env-sources:",
		"source_type: config",
		"source: api-config",
		"x-custom-env-source: keep-me",
		"x-custom-env-source-extra: normalize-me",
		"x-env-from:",
		"source_type: secret",
		"source: shared-secrets",
		"x-custom-env-from: keep-env-from",
		"x-custom-env-from-extra: normalize-me",
	} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("Compose output missing %q:\n%s", expected, composeOut)
		}
	}
	parsedCompose, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse emitted Compose app: %v", err)
	}
	parsedAPI := parsedCompose.Services["api"]
	if parsedAPI == nil || len(parsedAPI.EnvSources) != 2 || len(parsedAPI.EnvFrom) != 2 {
		t.Fatalf("Compose env source extensions did not rehydrate: %#v", parsedAPI)
	}
	if parsedAPI.EnvSources[0].Extensions["x-custom-env-source-extra"] != "normalize-me" || parsedAPI.EnvFrom[0].Extensions["x-custom-env-from-extra"] != "normalize-me" {
		t.Fatalf("Compose env source extensions did not normalize: %#v %#v", parsedAPI.EnvSources[0].Extensions, parsedAPI.EnvFrom[0].Extensions)
	}

	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad app: %v", err)
	}
	for _, expected := range []string{
		"bolabaden:env_source name=API_TIMEOUT type=config source=api-config key=timeout optional=true",
		"bolabaden:env_source name=DB_PASSWORD type=secret source=db-password key=password optional=false",
		"bolabaden:env_from type=config source=shared-config prefix=SHARED_ optional=false",
		"bolabaden:env_from type=secret source=shared-secrets prefix= optional=true",
	} {
		if !strings.Contains(nomadOut, expected) {
			t.Fatalf("Nomad output missing %q:\n%s", expected, nomadOut)
		}
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse emitted Nomad app: %v", err)
	}
	nomadAPI := parsedNomad.Services["api"]
	if nomadAPI == nil || len(nomadAPI.EnvSources) != 2 || len(nomadAPI.EnvFrom) != 2 {
		t.Fatalf("Nomad env refs did not rehydrate: %#v", nomadAPI)
	}
	if nomadAPI.EnvSources[0].Extensions == nil || nomadAPI.EnvSources[0].Extensions["x-custom-env-source"] != "keep-me" {
		t.Fatalf("Nomad env source extension did not persist: %#v", nomadAPI.EnvSources[0])
	}
	if nomadAPI.EnvFrom[0].Extensions == nil || nomadAPI.EnvFrom[0].Extensions["x-custom-env-from"] != "keep-env-from" {
		t.Fatalf("Nomad envFrom extension did not persist: %#v", nomadAPI.EnvFrom[0])
	}
	nomadKubernetes, err := p.Convert(parsedNomad, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert parsed Nomad app back to Kubernetes: %v", err)
	}
	nomadKubernetesOut, err := p.SaveContent(nomadKubernetes, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Nomad env refs back to Kubernetes: %v", err)
	}
	for _, expected := range []string{
		"configMapKeyRef:",
		"name: api-config",
		"secretKeyRef:",
		"name: db-password",
		"x-custom-env-source: keep-me",
		"envFrom:",
		"prefix: SHARED_",
		"x-custom-env-from: keep-env-from",
	} {
		if !strings.Contains(nomadKubernetesOut, expected) {
			t.Fatalf("Nomad->Kubernetes output missing %q:\n%s", expected, nomadKubernetesOut)
		}
	}

	helmApp, err := p.Convert(app, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Helm: %v", err)
	}
	helmDir := filepath.Join(t.TempDir(), "env-sources-chart")
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to serialize Helm env source chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse Helm env source chart: %v", err)
	}
	helmAPI := parsedHelm.Services["api"]
	if helmAPI == nil || len(helmAPI.EnvSources) != 2 || len(helmAPI.EnvFrom) != 2 {
		t.Fatalf("Helm env refs did not rehydrate: %#v", helmAPI)
	}
	helmKubernetes, err := p.Convert(parsedHelm, PlatformHelm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Helm env source chart back to Kubernetes: %v", err)
	}
	helmKubernetesOut, err := p.SaveContent(helmKubernetes, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Helm env refs back to Kubernetes: %v", err)
	}
	for _, expected := range []string{
		"configMapKeyRef:",
		"name: api-config",
		"secretKeyRef:",
		"name: db-password",
		"envFrom:",
		"prefix: SHARED_",
	} {
		if !strings.Contains(helmKubernetesOut, expected) {
			t.Fatalf("Helm->Kubernetes output missing %q:\n%s", expected, helmKubernetesOut)
		}
	}
}

func TestComposeEnvSourcesEmitNomadTemplates(t *testing.T) {
	content := `
services:
  api:
    image: ghcr.io/example/api:env-sources
    environment:
      MODE: prod
    x-env-sources:
      - name: API_TIMEOUT
        source_type: config
        source: api-config
        key: timeout
        optional: true
      - name: DB_PASSWORD
        source_type: secret
        source: db-password
        key: password
    x-env-from:
      - source_type: config
        source: shared-config
        prefix: SHARED_
      - source_type: secret
        source: shared-secrets
        optional: true
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose app: %v", err)
	}
	nomadApp, err := p.Convert(app, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert compose app to Nomad: %v", err)
	}
	out, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad HCL: %v", err)
	}
	for _, expected := range []string{
		"env = true",
		"bolabaden:env_source name=API_TIMEOUT type=config source=api-config key=timeout optional=true",
		"API_TIMEOUT={{ key \"api-config/timeout\" }}",
		"bolabaden:env_source name=DB_PASSWORD type=secret source=db-password key=password optional=false",
		"DB_PASSWORD={{ with secret \"db-password\" }}{{ index .Data.data \"password\" }}{{ end }}",
		"bolabaden:env_from type=config source=shared-config prefix=SHARED_ optional=false",
		"bolabaden:env_from type=secret source=shared-secrets prefix= optional=true",
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("Nomad output missing %q:\n%s", expected, out)
		}
	}

	parsed, err := p.LoadContent(out, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse emitted Nomad HCL: %v", err)
	}
	api := parsed.Services["api"]
	if api == nil || api.Environment["MODE"] != "prod" || len(api.EnvSources) != 2 || len(api.EnvFrom) != 2 {
		t.Fatalf("Nomad env refs did not rehydrate: %#v", api)
	}
	if api.EnvSources[0].Name != "API_TIMEOUT" || api.EnvSources[0].SourceType != "config" || api.EnvSources[0].Source != "api-config" || api.EnvSources[0].Key != "timeout" || !api.EnvSources[0].Optional {
		t.Fatalf("unexpected config env source: %#v", api.EnvSources[0])
	}
	if api.EnvSources[1].Name != "DB_PASSWORD" || api.EnvSources[1].SourceType != "secret" || api.EnvSources[1].Source != "db-password" || api.EnvSources[1].Key != "password" {
		t.Fatalf("unexpected secret env source: %#v", api.EnvSources[1])
	}
	if api.EnvFrom[0].SourceType != "config" || api.EnvFrom[0].Source != "shared-config" || api.EnvFrom[0].Prefix != "SHARED_" {
		t.Fatalf("unexpected config envFrom source: %#v", api.EnvFrom[0])
	}
	if api.EnvFrom[1].SourceType != "secret" || api.EnvFrom[1].Source != "shared-secrets" || !api.EnvFrom[1].Optional {
		t.Fatalf("unexpected secret envFrom source: %#v", api.EnvFrom[1])
	}

	composeApp, err := p.Convert(parsed, PlatformNomad, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert parsed Nomad app back to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize parsed Nomad app as Compose: %v", err)
	}
	for _, expected := range []string{
		"x-env-sources:",
		"source_type: config",
		"source: api-config",
		"x-env-from:",
		"source_type: secret",
		"source: shared-secrets",
	} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("Nomad->Compose output missing %q:\n%s", expected, composeOut)
		}
	}

	helmApp, err := p.Convert(parsed, PlatformNomad, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert parsed Nomad app to Helm: %v", err)
	}
	helmDir := filepath.Join(t.TempDir(), "env-sources-nomad-chart")
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to serialize Nomad env source Helm chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse Nomad env source Helm chart: %v", err)
	}
	helmAPI := parsedHelm.Services["api"]
	if helmAPI == nil || len(helmAPI.EnvSources) != 2 || len(helmAPI.EnvFrom) != 2 {
		t.Fatalf("Nomad->Helm env refs did not rehydrate: %#v", helmAPI)
	}
}

func TestComposeRuntimeSecurityBridgesToKubernetesAndBack(t *testing.T) {
	content := `
services:
  api:
    image: ghcr.io/example/api:runtime
    entrypoint: ["/bin/api"]
    command: ["--serve", "--port=8080"]
    working_dir: /srv/app
    user: "1000:1001"
    privileged: true
    cap_add:
      - NET_ADMIN
    cap_drop:
      - MKNOD
    security_opt:
      - no-new-privileges:true
    read_only: true
    x-kubernetes-allowPrivilegeEscalation: false
    x-kubernetes-procMount: Unmasked
    x-kubernetes-fsGroupChangePolicy: OnRootMismatch
    x-kubernetes-supplementalGroupsPolicy: Strict
    init: true
    tty: true
    stdin_open: true
    stop_signal: SIGTERM
    stop_grace_period: 45s
    x-kubernetes-seccomp-profile:
      type: RuntimeDefault
      custom.seccomp-flag: keep-me
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose app: %v", err)
	}
	api := app.Services["api"]
	if api == nil || len(api.Entrypoint) != 1 || len(api.Command) != 2 || !api.Privileged || len(api.CapAdd) != 1 || len(api.CapDrop) != 1 || len(api.SecurityOpt) != 1 || !api.ReadOnlyRootFS || api.AllowPrivilegeEscalation == nil || *api.AllowPrivilegeEscalation || api.ProcMount != "Unmasked" || api.FSGroupChangePolicy != "OnRootMismatch" || api.SupplementalGroupsPolicy != "Strict" || api.Init == nil || !*api.Init || !api.Tty || !api.StdinOpen || api.SeccompProfile == nil || api.SeccompProfile.Type != "RuntimeDefault" || api.SeccompProfile.Extensions["custom.seccomp-flag"] != "keep-me" {
		t.Fatalf("runtime fields not parsed from Compose: %#v", api)
	}

	composeBridgeOut, err := p.SaveContent(app, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose runtime bridge: %v", err)
	}
	if !strings.Contains(composeBridgeOut, "custom.seccomp-flag: keep-me") {
		t.Fatalf("Compose output lost seccomp extension:\n%s", composeBridgeOut)
	}
	composeBridgeParsed, err := p.LoadContent(composeBridgeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose runtime bridge: %v", err)
	}
	if composeBridgeParsed.Services["api"].SeccompProfile == nil || composeBridgeParsed.Services["api"].SeccompProfile.Extensions["custom.seccomp-flag"] != "keep-me" {
		t.Fatalf("Compose runtime bridge did not preserve seccomp extension: %#v", composeBridgeParsed.Services["api"].SeccompProfile)
	}

	k8sApp, err := p.Convert(app, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert compose app to Kubernetes: %v", err)
	}
	k8sOut, err := p.SaveContent(k8sApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes app: %v", err)
	}
	for _, expected := range []string{
		"command:",
		"- /bin/api",
		"args:",
		"- --serve",
		"workingDir: /srv/app",
		"runAsUser: 1000",
		"runAsGroup: 1001",
		"privileged: true",
		"readOnlyRootFilesystem: true",
		"allowPrivilegeEscalation: false",
		"procMount: Unmasked",
		"fsGroupChangePolicy: OnRootMismatch",
		"supplementalGroupsPolicy: Strict",
		"seccompProfile:",
		"type: RuntimeDefault",
		"capabilities:",
		"- NET_ADMIN",
		"- MKNOD",
		"stdin: true",
		"tty: true",
		"terminationGracePeriodSeconds: 45",
		kubernetesAnnotationRuntimeSecurityOpt + ": no-new-privileges:true",
		kubernetesAnnotationRuntimeInit + ": \"true\"",
		kubernetesAnnotationRuntimeStopSignal + ": SIGTERM",
	} {
		if !strings.Contains(k8sOut, expected) {
			t.Fatalf("Kubernetes output missing %q:\n%s", expected, k8sOut)
		}
	}

	parsedK8s, err := p.LoadContent(k8sOut, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse emitted Kubernetes app: %v", err)
	}
	parsedAPI := parsedK8s.Services["api"]
	if parsedAPI == nil || parsedAPI.User != "1000" || parsedAPI.Group != "1001" || len(parsedAPI.Entrypoint) != 1 || parsedAPI.Entrypoint[0] != "/bin/api" || len(parsedAPI.Command) != 2 || !parsedAPI.Privileged || !parsedAPI.ReadOnlyRootFS || parsedAPI.AllowPrivilegeEscalation == nil || *parsedAPI.AllowPrivilegeEscalation || parsedAPI.ProcMount != "Unmasked" || parsedAPI.FSGroupChangePolicy != "OnRootMismatch" || parsedAPI.SupplementalGroupsPolicy != "Strict" || len(parsedAPI.CapAdd) != 1 || len(parsedAPI.CapDrop) != 1 || parsedAPI.Init == nil || !*parsedAPI.Init || parsedAPI.StopSignal != "SIGTERM" || parsedAPI.SeccompProfile == nil || parsedAPI.SeccompProfile.Type != "RuntimeDefault" {
		t.Fatalf("Kubernetes runtime fields did not rehydrate: %#v", parsedAPI)
	}

	composeApp, err := p.Convert(parsedK8s, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Compose: %v", err)
	}
	composeOut, err := p.SaveContent(composeApp, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Compose app: %v", err)
	}
	for _, expected := range []string{
		"entrypoint:",
		"- /bin/api",
		"command:",
		"- --serve",
		"working_dir: /srv/app",
		"user: \"1000\"",
		"group: \"1001\"",
		"privileged: true",
		"cap_add:",
		"cap_drop:",
		"security_opt:",
		"read_only: true",
		"x-kubernetes-allowPrivilegeEscalation: false",
		"x-kubernetes-procMount: Unmasked",
		"x-kubernetes-fsGroupChangePolicy: OnRootMismatch",
		"x-kubernetes-supplementalGroupsPolicy: Strict",
		"init: true",
		"tty: true",
		"stdin_open: true",
		"x-kubernetes-seccomp-profile:",
		"type: RuntimeDefault",
		"stop_signal: SIGTERM",
		"stop_grace_period: 45s",
	} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("Compose output missing %q:\n%s", expected, composeOut)
		}
	}

	swarmApp, err := p.Convert(parsedK8s, PlatformKubernetes, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Swarm: %v", err)
	}
	swarmOut, err := p.SaveContent(swarmApp, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize Swarm app: %v", err)
	}
	for _, expected := range []string{
		"x-platform: docker-swarm",
		"entrypoint:",
		"- /bin/api",
		"command:",
		"- --serve",
		"working_dir: /srv/app",
		"user: \"1000\"",
		"group: \"1001\"",
		"privileged: true",
		"cap_add:",
		"cap_drop:",
		"security_opt:",
		"read_only: true",
		"x-kubernetes-allowPrivilegeEscalation: false",
		"x-kubernetes-procMount: Unmasked",
		"x-kubernetes-fsGroupChangePolicy: OnRootMismatch",
		"x-kubernetes-supplementalGroupsPolicy: Strict",
		"init: true",
		"tty: true",
		"stdin_open: true",
		"x-kubernetes-seccomp-profile:",
		"type: RuntimeDefault",
		"stop_signal: SIGTERM",
		"stop_grace_period: 45s",
	} {
		if !strings.Contains(swarmOut, expected) {
			t.Fatalf("Swarm output missing %q:\n%s", expected, swarmOut)
		}
	}
	swarmPath := filepath.Join(t.TempDir(), "runtime-security-swarm.yml")
	if err := os.WriteFile(swarmPath, []byte(swarmOut), 0644); err != nil {
		t.Fatalf("failed to write Swarm runtime security output: %v", err)
	}
	assertComposeGoLoads(t, swarmPath, "api")
	assertComposeCLIsAccept(t, swarmPath)
	parsedSwarm, err := p.LoadContent(swarmOut, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to parse emitted Swarm app: %v", err)
	}
	parsedSwarmAPI := parsedSwarm.Services["api"]
	if parsedSwarmAPI == nil || parsedSwarmAPI.User != "1000" || parsedSwarmAPI.Group != "1001" || len(parsedSwarmAPI.Entrypoint) != 1 || parsedSwarmAPI.Entrypoint[0] != "/bin/api" || len(parsedSwarmAPI.Command) != 2 || !parsedSwarmAPI.Privileged || !parsedSwarmAPI.ReadOnlyRootFS || parsedSwarmAPI.AllowPrivilegeEscalation == nil || *parsedSwarmAPI.AllowPrivilegeEscalation || parsedSwarmAPI.ProcMount != "Unmasked" || parsedSwarmAPI.FSGroupChangePolicy != "OnRootMismatch" || parsedSwarmAPI.SupplementalGroupsPolicy != "Strict" || len(parsedSwarmAPI.CapAdd) != 1 || len(parsedSwarmAPI.CapDrop) != 1 || parsedSwarmAPI.Init == nil || !*parsedSwarmAPI.Init || parsedSwarmAPI.StopSignal != "SIGTERM" || parsedSwarmAPI.SeccompProfile == nil || parsedSwarmAPI.SeccompProfile.Type != "RuntimeDefault" {
		t.Fatalf("Swarm runtime fields did not rehydrate: %#v", parsedSwarmAPI)
	}
	swarmCompose, err := p.Convert(parsedSwarm, PlatformDockerSwarm, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Swarm app to Compose: %v", err)
	}
	swarmComposeOut, err := p.SaveContent(swarmCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Swarm round-tripped Compose app: %v", err)
	}
	for _, expected := range []string{
		"entrypoint:",
		"- /bin/api",
		"command:",
		"- --serve",
		"working_dir: /srv/app",
		"user: \"1000\"",
		"group: \"1001\"",
		"privileged: true",
		"cap_add:",
		"cap_drop:",
		"security_opt:",
		"read_only: true",
		"x-kubernetes-allowPrivilegeEscalation: false",
		"x-kubernetes-procMount: Unmasked",
		"x-kubernetes-fsGroupChangePolicy: OnRootMismatch",
		"x-kubernetes-supplementalGroupsPolicy: Strict",
		"init: true",
		"tty: true",
		"stdin_open: true",
		"x-kubernetes-seccomp-profile:",
		"type: RuntimeDefault",
		"stop_signal: SIGTERM",
		"stop_grace_period: 45s",
	} {
		if !strings.Contains(swarmComposeOut, expected) {
			t.Fatalf("Swarm round-tripped Compose output missing %q:\n%s", expected, swarmComposeOut)
		}
	}
}

func TestComposeBuildDeviceAndRuntimeResourceFieldsRoundTrip(t *testing.T) {
	content := `
services:
  api:
    build:
      context: .
      dockerfile: Dockerfile.api
    devices:
      - /dev/fuse:/dev/fuse
      - /dev/source:/dev/target:permissions
      - source: /dev/net/tun
        target: /dev/net/tun
        permissions: rwm
        x-bolabaden-device: mesh
    expose:
      - 9090
    mem_limit: 512M
    mem_reservation: 256M
    cpus: 1.5
    ulimits:
      nproc: 65535
      nofile:
        soft: 1024
        hard: 2048
        x-bolabaden-ulimit: file-descriptors
    userns_mode: host
    pull_policy: always
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose app: %v", err)
	}
	api := app.Services["api"]
	if api == nil || api.Build == nil || api.Build.Context != "." || api.Build.Dockerfile != "Dockerfile.api" || len(api.Devices) != 3 || len(api.DeviceMappings) != 3 || len(api.Expose) != 1 || api.Expose[0] != "9090" || api.MemLimit != "536870912" || api.MemReservation != "268435456" || api.CPUs != "1.5" || api.UserNSMode != "host" || api.PullPolicy != "always" || api.Ulimits == nil || api.Ulimits.Nofile == nil || api.Ulimits.Nofile.Soft != 1024 || api.Ulimits.Nofile.Hard != 2048 || toString(api.Ulimits.Nofile.Extensions["x-bolabaden-ulimit"]) != "file-descriptors" || api.Ulimits.Limits["nproc"].Single != 65535 {
		t.Fatalf("compose resource fields not parsed: %#v", api)
	}
	if api.Devices[0] != "/dev/fuse" || api.Devices[1] != "/dev/source:/dev/target:permissions" || api.Devices[2] != "/dev/net/tun" {
		t.Fatalf("compose device fields not canonicalized as expected: %#v", api.Devices)
	}
	if toString(api.DeviceMappings[2].Extensions["x-bolabaden-device"]) != "mesh" {
		t.Fatalf("compose device extension not preserved: %#v", api.DeviceMappings)
	}

	out, err := p.SaveContent(app, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize compose app: %v", err)
	}
	for _, expected := range []string{
		"build:",
		"context: .",
		"dockerfile: Dockerfile.api",
		"devices:",
		"- /dev/fuse",
		"- /dev/source:/dev/target:permissions",
		"source: /dev/net/tun",
		"x-bolabaden-device: mesh",
		"expose:",
		"- \"9090\"",
		"mem_limit: \"536870912\"",
		"mem_reservation: \"268435456\"",
		"cpus: 1.5",
		"ulimits:",
		"nproc: 65535",
		"nofile:",
		"soft: 1024",
		"hard: 2048",
		"x-bolabaden-ulimit: file-descriptors",
		"userns_mode: host",
		"pull_policy: always",
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("compose output missing %q:\n%s", expected, out)
		}
	}

	parsedAgain, err := p.LoadContent(out, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to reparse emitted compose app: %v", err)
	}
	apiAgain := parsedAgain.Services["api"]
	if apiAgain == nil || apiAgain.Build == nil || apiAgain.Build.Context != "." || apiAgain.Build.Dockerfile != "Dockerfile.api" || len(apiAgain.Devices) != 3 || len(apiAgain.DeviceMappings) != 3 || toString(apiAgain.DeviceMappings[2].Extensions["x-bolabaden-device"]) != "mesh" || apiAgain.MemLimit != "536870912" || apiAgain.MemReservation != "268435456" || apiAgain.CPUs != "1.5" || apiAgain.UserNSMode != "host" || apiAgain.PullPolicy != "always" || apiAgain.Ulimits == nil || apiAgain.Ulimits.Nofile == nil || apiAgain.Ulimits.Nofile.Soft != 1024 || apiAgain.Ulimits.Nofile.Hard != 2048 || toString(apiAgain.Ulimits.Nofile.Extensions["x-bolabaden-ulimit"]) != "file-descriptors" || apiAgain.Ulimits.Limits["nproc"].Single != 65535 {
		t.Fatalf("compose resource fields did not survive roundtrip: %#v", apiAgain)
	}
}

func TestComposeMemorySwapSerializesComposeCompatibleValues(t *testing.T) {
	p := New(nil)
	content := `
services:
  api:
    image: ghcr.io/example/api:1
    shm_size: 64Mi
    mem_limit: 256Mi
    mem_reservation: 64Mi
    memswap_limit: 128Mi
`
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose input: %v", err)
	}
	api := app.Services["api"]
	if api == nil || api.ShmSize != 67108864 || api.MemoryLimit != "268435456" || api.MemLimit != "268435456" || api.MemReservation != "67108864" || api.MemorySwap != "134217728" {
		t.Fatalf("compose input did not normalize resource fields: %#v", api)
	}
	if toString(api.Extensions[composeShmSizeExtension]) != "64Mi" || toString(api.Extensions[composeMemoryLimitExtension]) != "256Mi" || toString(api.Extensions[composeMemoryReservationExtension]) != "64Mi" || toString(api.Extensions[composeMemorySwapExtension]) != "128Mi" {
		t.Fatalf("compose input did not preserve raw resource units: %#v", api.Extensions)
	}

	composeOut, err := p.SaveContent(app, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize Compose output: %v", err)
	}
	for _, expected := range []string{
		"shm_size: 67108864",
		"mem_limit: \"268435456\"",
		"mem_reservation: \"67108864\"",
		"memswap_limit: \"134217728\"",
		"x-bolabaden-compose-shm-size: 64Mi",
		"x-bolabaden-compose-memory-limit: 256Mi",
		"x-bolabaden-compose-memory-reservation: 64Mi",
		"x-bolabaden-compose-memory-swap: 128Mi",
	} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("compose output missing %q:\n%s", expected, composeOut)
		}
	}
	composePath := filepath.Join(t.TempDir(), "docker-compose.yml")
	if err := os.WriteFile(composePath, []byte(composeOut), 0o644); err != nil {
		t.Fatalf("failed to write Compose output: %v", err)
	}
	assertComposeCLIsAccept(t, composePath)

	parsedAgain, err := p.LoadContent(composeOut, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to reparse emitted Compose output: %v", err)
	}
	apiAgain := parsedAgain.Services["api"]
	if apiAgain == nil || apiAgain.ShmSize != 67108864 || apiAgain.MemoryLimit != "268435456" || apiAgain.MemLimit != "268435456" || apiAgain.MemReservation != "67108864" || apiAgain.MemorySwap != "134217728" {
		t.Fatalf("compose output did not round-trip normalized resource fields: %#v", apiAgain)
	}
	if toString(apiAgain.Extensions[composeShmSizeExtension]) != "64Mi" || toString(apiAgain.Extensions[composeMemoryLimitExtension]) != "256Mi" || toString(apiAgain.Extensions[composeMemoryReservationExtension]) != "64Mi" || toString(apiAgain.Extensions[composeMemorySwapExtension]) != "128Mi" {
		t.Fatalf("compose output did not round-trip raw resource units: %#v", apiAgain.Extensions)
	}
}

func TestComposeTmpfsSizeSerializesComposeCompatibleValuesInNomad(t *testing.T) {
	content := `
services:
  api:
    image: ghcr.io/example/api:1
    volumes:
      - type: tmpfs
        target: /tmp/cache
        tmpfs:
          size: 1Mi
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse Compose input: %v", err)
	}
	api := app.Services["api"]
	if api == nil || len(api.Volumes) != 1 || api.Volumes[0].Type != "tmpfs" || api.Volumes[0].Options["size"] != "1Mi" || api.Volumes[0].TmpfsExtensions["size"] != "1Mi" {
		t.Fatalf("compose tmpfs size did not preserve raw units: %#v", api)
	}

	nomadApp, err := p.Convert(app, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Compose tmpfs service to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad tmpfs output: %v", err)
	}
	if !strings.Contains(nomadOut, "tmpfs_options {") || !strings.Contains(nomadOut, "size = 1048576") || !strings.Contains(nomadOut, nomadTmpfsMetaKey) || !strings.Contains(nomadOut, "1Mi") {
		t.Fatalf("Nomad output missing normalized tmpfs size:\n%s", nomadOut)
	}

	roundTripped, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad tmpfs output: %v", err)
	}
	if roundTripped.Services["api"] == nil || len(roundTripped.Services["api"].Volumes) != 1 || roundTripped.Services["api"].Volumes[0].Target != "/tmp/cache" || roundTripped.Services["api"].Volumes[0].Options["size"] != "1Mi" || roundTripped.Services["api"].Volumes[0].TmpfsExtensions["size"] != "1Mi" {
		t.Fatalf("Nomad tmpfs output did not round-trip mount metadata: %#v", roundTripped.Services["api"])
	}
	backOut, err := p.SaveContent(roundTripped, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize round-tripped Compose tmpfs output: %v", err)
	}
	if !strings.Contains(backOut, "size: 1Mi") || !strings.Contains(backOut, "tmpfs:") {
		t.Fatalf("Compose output did not preserve raw tmpfs units:\n%s", backOut)
	}
}

func TestComposeBuildSpecSurvivesKubernetesNomadAndHelmBridges(t *testing.T) {
	content := `
services:
  api:
    image: ghcr.io/example/api:build-rich
    build:
      context: .
      dockerfile: Dockerfile.api
      x-bolabaden-build: keep-build
      dockerfile_inline: |
        FROM alpine
        RUN echo build-rich
      additional_contexts:
        assets: ./assets
        base: docker-image://alpine:3.20
      args:
        TARGET_ENV: prod
      cache_from:
        - type=registry,ref=ghcr.io/example/api:cache
      cache_to:
        - type=inline
      extra_hosts:
        - build.local=127.0.0.1
      labels:
        org.opencontainers.image.source: https://example.test/api
      network: host
      no_cache: true
      no_cache_filter:
        - deps
      platforms:
        - linux/amd64
        - linux/arm64
      privileged: true
      provenance: mode=max
      pull: true
      sbom: generator=docker/scout-sbom-indexer
      secrets:
        - source: npm_token
          target: npm_token
      ssh:
        - default
      tags:
        - ghcr.io/example/api:build-rich
      target: runtime
secrets:
  npm_token:
    environment: NPM_TOKEN
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse rich Compose build fixture: %v", err)
	}
	api := app.Services["api"]
	if api == nil || api.Build == nil || api.Build.Context != "." || api.Build.Dockerfile != "Dockerfile.api" {
		t.Fatalf("rich Compose build fixture was not normalized: %#v", api)
	}
	rawBuild, ok := asMap(api.Build.Extensions["compose.build"])
	if !ok || rawBuild["dockerfile_inline"] == "" || rawBuild["additional_contexts"] == nil || rawBuild["secrets"] == nil || rawBuild["ssh"] == nil {
		t.Fatalf("rich Compose build sidecar was not captured: %#v", api.Build.Extensions)
	}
	if api.Build.Extensions["x-bolabaden-build"] != "keep-build" {
		t.Fatalf("rich Compose build extension was not captured: %#v", api.Build.Extensions)
	}

	assertBuildCompose := func(t *testing.T, out string, context string) {
		t.Helper()
		for _, expected := range []string{
			"build:",
			"context: .",
			"dockerfile: Dockerfile.api",
			"x-bolabaden-build: keep-build",
			"dockerfile_inline: |",
			"RUN echo build-rich",
			"additional_contexts:",
			"assets: ./assets",
			"cache_from:",
			"type=registry,ref=ghcr.io/example/api:cache",
			"cache_to:",
			"type=inline",
			"network: host",
			"no_cache: true",
			"no_cache_filter:",
			"- deps",
			"platforms:",
			"- linux/amd64",
			"- linux/arm64",
			"privileged: true",
			"provenance: mode=max",
			"pull: true",
			"sbom: generator=docker/scout-sbom-indexer",
			"secrets:",
			"source: npm_token",
			"ssh:",
			"- default",
			"tags:",
			"ghcr.io/example/api:build-rich",
			"target: runtime",
		} {
			if !strings.Contains(out, expected) {
				t.Fatalf("%s lost Compose build field %q:\n%s", context, expected, out)
			}
		}
	}

	composeOut, err := p.SaveContent(app, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize rich Compose build fixture: %v", err)
	}
	assertBuildCompose(t, composeOut, "Compose output")

	kubernetesApp, err := p.Convert(app, PlatformDockerCompose, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert rich Compose build fixture to Kubernetes: %v", err)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize rich Compose build fixture as Kubernetes: %v", err)
	}
	if !strings.Contains(kubernetesOut, "bolabaden.dev/portable-build") || !strings.Contains(kubernetesOut, "dockerfile_inline") || !strings.Contains(kubernetesOut, "additional_contexts") {
		t.Fatalf("Kubernetes output lost rich Compose build metadata:\n%s", kubernetesOut)
	}
	parsedKubernetes, err := p.LoadContent(kubernetesOut, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to parse rich Compose build Kubernetes bridge: %v", err)
	}
	kubernetesCompose, err := p.Convert(parsedKubernetes, PlatformKubernetes, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert rich Compose build Kubernetes bridge back to Compose: %v", err)
	}
	kubernetesComposeOut, err := p.SaveContent(kubernetesCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize rich Compose build Kubernetes round-trip: %v", err)
	}
	assertBuildCompose(t, kubernetesComposeOut, "Kubernetes round-trip")

	nomadApp, err := p.Convert(app, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert rich Compose build fixture to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize rich Compose build fixture as Nomad: %v", err)
	}
	if !strings.Contains(nomadOut, "bolabaden_build") || !strings.Contains(nomadOut, "dockerfile_inline") || !strings.Contains(nomadOut, "additional_contexts") {
		t.Fatalf("Nomad output lost rich Compose build metadata:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse rich Compose build Nomad bridge: %v", err)
	}
	nomadCompose, err := p.Convert(parsedNomad, PlatformNomad, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert rich Compose build Nomad bridge back to Compose: %v", err)
	}
	nomadComposeOut, err := p.SaveContent(nomadCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize rich Compose build Nomad round-trip: %v", err)
	}
	assertBuildCompose(t, nomadComposeOut, "Nomad round-trip")

	helmDir := filepath.Join(t.TempDir(), "build-chart")
	helmApp, err := p.Convert(app, PlatformDockerCompose, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert rich Compose build fixture to Helm: %v", err)
	}
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to save rich Compose build Helm chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse rich Compose build Helm chart: %v", err)
	}
	helmCompose, err := p.Convert(parsedHelm, PlatformHelm, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert rich Compose build Helm chart back to Compose: %v", err)
	}
	helmComposeOut, err := p.SaveContent(helmCompose, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to serialize rich Compose build Helm round-trip: %v", err)
	}
	assertBuildCompose(t, helmComposeOut, "Helm round-trip")
}

