	if _, ok := extensionValueForKey(parsedCompose.Services["api"], nomadRescheduleExtensionKey); !ok {
		t.Fatalf("Compose round-trip lost Nomad reschedule extension: %#v", parsedCompose.Services["api"].Extensions)
	}
	nomadFromCompose, err := p.Convert(parsedCompose, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Compose scheduler fixture back to Nomad: %v", err)
	}
	nomadFromComposeOut, err := p.SaveContent(nomadFromCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Compose round-tripped Nomad scheduler fixture: %v", err)
	}
	for _, needle := range []string{"update {", "migrate {", "reschedule {", "restart {", "canary = 2", "attempts = 4", "delay_function = \"exponential\"", "render_templates = true"} {
		if !strings.Contains(nomadFromComposeOut, needle) {
			t.Fatalf("Nomad Compose round-trip lost %q:\n%s", needle, nomadFromComposeOut)
		}
	}
	for _, needle := range []string{"health_check = \"checks\"", "min_healthy_time = \"10s\"", "healthy_deadline = \"5m\"", "progress_deadline = \"10m\"", "auto_revert = true", "auto_promote = true", "canary = 2", "stagger = \"45s\""} {
		if !strings.Contains(nomadFromComposeOut, needle) {
			t.Fatalf("Nomad Compose round-trip lost update detail %q:\n%s", needle, nomadFromComposeOut)
		}
	}

	kubernetesApp, err := p.Convert(app, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad scheduler fixture to Kubernetes: %v", err)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
