func TestKubernetesZeroValuedJobFieldsStayExplicit(t *testing.T) {
	const kubernetesContent = `
apiVersion: batch/v1
kind: Job
metadata:
  name: worker
spec:
  parallelism: 0
  completions: 0
  backoffLimit: 0
  backoffLimitPerIndex: 0
  ttlSecondsAfterFinished: 0
  template:
    metadata:
      labels:
        app: worker
    spec:
      restartPolicy: Never
      containers:
        - name: worker
          image: ghcr.io/example/worker:job
`

	app, err := ParseKubernetesYAML(kubernetesContent)
	if err != nil {
		t.Fatalf("failed to parse zero-valued Kubernetes job fixture: %v", err)
	}
	worker := app.Services["worker"]
	if worker == nil || worker.Deploy == nil || worker.Deploy.Job == nil {
		t.Fatalf("zero-valued kubernetes job did not hydrate into portable deploy job: %#v", worker)
	}
	if worker.Deploy.Job.MaxConcurrent != 0 || worker.Deploy.Job.TotalCompletions != 0 || worker.Deploy.Job.BackoffLimit != 0 || worker.Deploy.Job.BackoffLimitPerIndex != 0 || worker.Deploy.Job.TTLSecondsAfterFinished != 0 {
		t.Fatalf("zero-valued kubernetes job fields were not preserved: %#v", worker.Deploy.Job)
	}

	composeOut, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize zero-valued Kubernetes job as Compose: %v", err)
	}
	for _, expected := range []string{
		"max_concurrent: 0",
		"total_completions: 0",
		"backoff_limit: 0",
		"backoff_limit_per_index: 0",
		"ttl_seconds_after_finished: 0",
	} {
		if !strings.Contains(composeOut, expected) {
			t.Fatalf("Compose output dropped explicit zero-valued job field %q:\n%s", expected, composeOut)
		}
	}

	p := New(nil)
	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert zero-valued Kubernetes job to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize zero-valued Nomad job app: %v", err)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse zero-valued Nomad job app: %v", err)
	}
	nomadWorker := parsedNomad.Services["worker"]
	if nomadWorker == nil || nomadWorker.Deploy == nil || nomadWorker.Deploy.Job == nil || nomadWorker.Deploy.Job.MaxConcurrent != 0 || nomadWorker.Deploy.Job.TotalCompletions != 0 || nomadWorker.Deploy.Job.BackoffLimit != 0 || nomadWorker.Deploy.Job.BackoffLimitPerIndex != 0 || nomadWorker.Deploy.Job.TTLSecondsAfterFinished != 0 {
		t.Fatalf("Nomad round-trip lost explicit zero-valued job fields: %#v", nomadWorker)
	}

	helmApp, err := p.Convert(app, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert zero-valued Kubernetes job to Helm: %v", err)
	}
	helmDir := filepath.Join(t.TempDir(), "zero-job-chart")
	if err := p.SaveFile(helmApp, helmDir); err != nil {
		t.Fatalf("failed to serialize zero-valued Helm job chart: %v", err)
	}
	parsedHelm, err := p.LoadFile(helmDir)
	if err != nil {
		t.Fatalf("failed to parse zero-valued Helm job chart: %v", err)
	}
	helmWorker := parsedHelm.Services["worker"]
	if helmWorker == nil || helmWorker.Deploy == nil || helmWorker.Deploy.Job == nil || helmWorker.Deploy.Job.MaxConcurrent != 0 || helmWorker.Deploy.Job.TotalCompletions != 0 || helmWorker.Deploy.Job.BackoffLimit != 0 || helmWorker.Deploy.Job.BackoffLimitPerIndex != 0 || helmWorker.Deploy.Job.TTLSecondsAfterFinished != 0 {
		t.Fatalf("Helm round-trip lost explicit zero-valued job fields: %#v", helmWorker)
	}
}

