func TestAttachCanonicalDeepCopiesSourceModel(t *testing.T) {
	app := &Application{
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"api": {
				Name:        "api",
				Image:       "ghcr.io/example/api:canonical",
				Environment: map[string]string{"MODE": "prod"},
				Volumes: []VolumeMount{{
					Source:  "data",
					Target:  "/var/lib/data",
					Options: map[string]string{"subpath": "state"},
				}},
				Extensions: map[string]interface{}{
					"x-bolabaden-service": map[string]interface{}{"tier": "edge"},
				},
			},
		},
		Networks: map[string]*Network{
			"mesh": {
				Name:       "mesh",
				DriverOpts: map[string]string{"encrypted": "true"},
			},
		},
		Volumes: map[string]*Volume{},
		Configs: map[string]*Config{},
		Secrets: map[string]*Secret{},
		Models: map[string]*ComposeModel{
			"llm": {
				Model:        "ai/model",
				ContextSize:  1024,
				RuntimeFlags: []string{"--ctx=1024"},
				Extensions: map[string]interface{}{
					"x-bolabaden-model": map[string]interface{}{"runner": "local"},
				},
			},
		},
		Extensions: map[string]interface{}{
			"x-bolabaden-app": map[string]interface{}{"mode": "mesh"},
			"kubernetes.raw": []interface{}{
				map[string]interface{}{
					"kind": "ConfigMap",
					"metadata": map[string]interface{}{
						"name": "canonical-config",
					},
				},
			},
		},
	}

	syncPortableApplicationState(app)
	app.AttachCanonical()
	if app.Canonical == nil {
		t.Fatalf("canonical model missing after attach")
	}
	clonedApp := cloneApplication(app)
	if clonedApp == nil || len(clonedApp.KubernetesOpaqueManifests) != 1 {
		t.Fatalf("cloneApplication did not preserve opaque Kubernetes manifests: %#v", clonedApp.KubernetesOpaqueManifests)
	}
	clonedApp.KubernetesOpaqueManifests["v1/ConfigMap//canonical-config"].Name = "mutated"
	if app.KubernetesOpaqueManifests["v1/ConfigMap//canonical-config"].Name != "canonical-config" {
		t.Fatalf("cloneApplication aliased opaque Kubernetes manifests: %#v", app.KubernetesOpaqueManifests["v1/ConfigMap//canonical-config"])
	}
	app.Canonical.AddPolicy(&PolicySpec{
		Name:   "api-policy",
		Type:   "networkpolicy",
		Target: "api",
		Rules:  []string{"app=api"},
		Extension: map[string]string{
			"x-bolabaden-policy": "mesh",
		},
		Source: PlatformKubernetes,
	})
	app.Canonical.Services["api"].Environment["MODE"] = "debug"
	app.Canonical.Services["api"].Volumes[0].Options["subpath"] = "canonical"
	app.Canonical.Services["api"].Extensions["x-bolabaden-service"] = "mutated"
	app.Canonical.Networks["mesh"].DriverOpts["encrypted"] = "false"
	app.Canonical.Models["llm"].RuntimeFlags[0] = "--ctx=4096"
	app.Canonical.Models["llm"].Extensions["x-bolabaden-model"] = "mutated"
	app.Canonical.Extensions["x-bolabaden-app"] = "mutated"
	serviceResource, ok := app.Canonical.Resources["docker-compose:service:api"]
	if !ok {
		t.Fatalf("canonical service resource missing: %#v", app.Canonical.Resources)
	}
	serviceRaw, ok := serviceResource.Raw.(*Service)
	if !ok {
		t.Fatalf("canonical service raw payload missing type: %#v", serviceResource.Raw)
	}
	serviceRaw.Environment["MODE"] = "resource-mutated"
	rawResource, ok := app.Canonical.Resources["docker-compose:raw:configmap-canonical-config"]
	if !ok {
		t.Fatalf("canonical raw resource missing: %#v", app.Canonical.Resources)
	}
	rawMap, ok := asMap(rawResource.Raw)
	if !ok {
		t.Fatalf("canonical raw resource payload missing map form: %#v", rawResource.Raw)
	}
	rawMap["kind"] = "Mutated"
	modelResource, ok := app.Canonical.Resources["docker-compose:model:llm"]
	if !ok {
		t.Fatalf("canonical model resource missing: %#v", app.Canonical.Resources)
	}
	modelRaw, ok := modelResource.Raw.(*ComposeModel)
	if !ok {
		t.Fatalf("canonical model raw payload missing type: %#v", modelResource.Raw)
	}
	modelRaw.RuntimeFlags[0] = "--ctx=8192"
	app.Canonical.AddRawResource(PlatformKubernetes, "kubernetes-raw-test", 1, map[string]interface{}{
		"apiVersion": "v1",
		"kind":       "ConfigMap",
		"metadata": map[string]interface{}{
			"name":        "config-demo",
			"labels":      map[string]interface{}{"app": "demo"},
			"annotations": map[string]interface{}{"owner": "platform"},
		},
	})
	rawAdded := app.Canonical.Resources["kubernetes:raw:configmap-config-demo"]
	if rawAdded == nil || rawAdded.Annotations["owner"] != "platform" || rawAdded.Metadata["app"] != "demo" {
		t.Fatalf("raw resource annotations were not captured by AddRawResource: %#v", rawAdded)
	}
	app.Canonical.Resources["docker-compose:raw:demo"] = &CanonicalResource{
		ID:       "docker-compose:raw:demo",
		Name:     "demo",
		Kind:     ResourceKindRaw,
		Platform: PlatformDockerCompose,
		Raw:      map[string]interface{}{"kind": "ConfigMap"},
		Extensions: map[string]interface{}{
			"x-bolabaden-raw": map[string]interface{}{"tier": "edge"},
		},
		Annotations: map[string]string{
			"owner": "platform",
		},
	}
	clonedRaw := cloneCanonicalResource(app.Canonical.Resources["docker-compose:raw:demo"])
	if clonedRaw == nil || clonedRaw.Extensions["bolabaden.raw"] == nil || clonedRaw.Annotations["owner"] != "platform" {
		t.Fatalf("canonical raw resource extensions were not normalized: %#v", clonedRaw)
	}
	clonedRaw.Annotations["owner"] = "mutated"
	if app.Canonical.Resources["docker-compose:raw:demo"].Annotations["owner"] != "platform" {
		t.Fatalf("canonical raw resource annotations aliased source graph: %#v", app.Canonical.Resources["docker-compose:raw:demo"].Annotations)
	}

	composeOut, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize compose with raw resource annotations: %v", err)
	}
	if !strings.Contains(composeOut, "annotations:") || !strings.Contains(composeOut, "owner: platform") {
		t.Fatalf("compose raw resource bridge did not emit annotations:\n%s", composeOut)
	}
	parsedCompose, err := ParseDockerCompose(composeOut)
	if err != nil {
		t.Fatalf("failed to parse compose with raw resource annotations: %v", err)
	}
	roundTrippedRaw := parsedCompose.Canonical.Resources["kubernetes:raw:configmap-config-demo"]
	if roundTrippedRaw == nil || roundTrippedRaw.Annotations["owner"] != "platform" {
		t.Fatalf("compose raw resource annotations did not round-trip through bridge: %#v", roundTrippedRaw)
	}

	if app.Services["api"].Environment["MODE"] != "prod" {
		t.Fatalf("canonical service environment aliased source app: %#v", app.Services["api"].Environment)
	}
	if app.Services["api"].Volumes[0].Options["subpath"] != "state" {
		t.Fatalf("canonical volume mounts aliased source app: %#v", app.Services["api"].Volumes[0].Options)
	}
	if nested, ok := app.Services["api"].Extensions["x-bolabaden-service"].(map[string]interface{}); !ok || nested["tier"] != "edge" {
		t.Fatalf("canonical service extensions aliased source app: %#v", app.Services["api"].Extensions)
	}
	if app.Networks["mesh"].DriverOpts["encrypted"] != "true" {
		t.Fatalf("canonical network aliased source app: %#v", app.Networks["mesh"])
	}
	if app.Models["llm"].RuntimeFlags[0] != "--ctx=1024" {
		t.Fatalf("canonical model flags aliased source app: %#v", app.Models["llm"].RuntimeFlags)
	}
	if nested, ok := app.Models["llm"].Extensions["x-bolabaden-model"].(map[string]interface{}); !ok || nested["runner"] != "local" {
		t.Fatalf("canonical model extensions aliased source app: %#v", app.Models["llm"].Extensions)
	}
	if nested, ok := app.Canonical.Models["llm"].Extensions["bolabaden.model"].(map[string]interface{}); !ok || nested["runner"] != "local" {
		t.Fatalf("canonical model extension aliases missing from canonical graph: %#v", app.Canonical.Models["llm"].Extensions)
	}
	if app.Canonical.Policies["api-policy"] == nil || app.Canonical.Policies["api-policy"].Extension["bolabaden.policy"] != "mesh" {
		t.Fatalf("canonical policy extension aliases missing from canonical graph: %#v", app.Canonical.Policies["api-policy"])
	}
	if nested, ok := app.Extensions["x-bolabaden-app"].(map[string]interface{}); !ok || nested["mode"] != "mesh" {
		t.Fatalf("canonical app extensions aliased source app: %#v", app.Extensions)
	}
	if app.Extensions["kubernetes.raw"].([]interface{})[0].(map[string]interface{})["kind"] != "ConfigMap" {
		t.Fatalf("canonical raw resources aliased source app extensions: %#v", app.Extensions["kubernetes.raw"])
	}
}

