func TestPortableRouteAndPolicyAnnotationParsersPreserveExtensions(t *testing.T) {
	route := portableRouteFromKubernetesAnnotation(`{"name":"api","service":"api","extensions":{"custom.route":"keep"},"mystery":{"edge":true}}`)
	if route == nil || route.Extensions["custom.route"] != "keep" {
		t.Fatalf("portable route annotation parser lost extensions: %#v", route)
	}
	if nested, ok := route.Extensions["mystery"].(map[string]interface{}); !ok || nested["edge"] != true {
		t.Fatalf("portable route annotation parser lost unknown fields: %#v", route.Extensions)
	}

	policy := portablePolicyFromKubernetesAnnotation(`{"name":"api-policy","type":"networkpolicy","extensions":{"custom.policy":"keep"},"mystery":{"edge":true}}`)
	if policy == nil || policy.Extensions["custom.policy"] != "keep" {
		t.Fatalf("portable policy annotation parser lost extensions: %#v", policy)
	}
	if nested, ok := policy.Extensions["mystery"].(map[string]interface{}); !ok || nested["edge"] != true {
		t.Fatalf("portable policy annotation parser lost unknown fields: %#v", policy.Extensions)
	}
}

func TestHelmAndNomadRoutePolicyReadersPreserveUnknownFields(t *testing.T) {
	chartDir := filepath.Join(t.TempDir(), "chart")
	if err := os.MkdirAll(chartDir, 0755); err != nil {
		t.Fatalf("failed to create helm test chart dir: %v", err)
	}
	helmRoutes := `{"api":{"name":"api","service":"api","extensions":{"custom.route":"keep"},"mystery":{"edge":true}}}`
	helmPolicies := `{"api-policy":{"name":"api-policy","type":"networkpolicy","extensions":{"custom.policy":"keep"},"mystery":{"edge":true}}}`
	if err := os.WriteFile(filepath.Join(chartDir, helmAppRoutesFile), []byte(helmRoutes), 0644); err != nil {
		t.Fatalf("failed to write helm routes sidecar: %v", err)
	}
	if err := os.WriteFile(filepath.Join(chartDir, helmAppPoliciesFile), []byte(helmPolicies), 0644); err != nil {
		t.Fatalf("failed to write helm policies sidecar: %v", err)
	}
	routes, err := helmApplicationRoutesFromChart(chartDir)
	if err != nil {
		t.Fatalf("failed to read helm routes sidecar: %v", err)
	}
	if routes["api"] == nil || routes["api"].Extensions["custom.route"] != "keep" {
		t.Fatalf("helm route reader lost extensions: %#v", routes["api"])
	}
	if nested, ok := routes["api"].Extensions["mystery"].(map[string]interface{}); !ok || nested["edge"] != true {
		t.Fatalf("helm route reader lost unknown fields: %#v", routes["api"].Extensions)
	}
	policies, err := helmApplicationPoliciesFromChart(chartDir)
	if err != nil {
		t.Fatalf("failed to read helm policies sidecar: %v", err)
	}
	if policies["api-policy"] == nil || policies["api-policy"].Extensions["custom.policy"] != "keep" {
		t.Fatalf("helm policy reader lost extensions: %#v", policies["api-policy"])
	}
	if nested, ok := policies["api-policy"].Extensions["mystery"].(map[string]interface{}); !ok || nested["edge"] != true {
		t.Fatalf("helm policy reader lost unknown fields: %#v", policies["api-policy"].Extensions)
	}

	nomadContent := `
job "demo" {
  meta {
    bolabaden_app_routes = "{\"api\":{\"name\":\"api\",\"service\":\"api\",\"extensions\":{\"custom.route\":\"keep\"},\"mystery\":{\"edge\":true}}}"
    bolabaden_app_policies = "{\"api-policy\":{\"name\":\"api-policy\",\"type\":\"networkpolicy\",\"extensions\":{\"custom.policy\":\"keep\"},\"mystery\":{\"edge\":true}}}"
  }
  group "api" {
    task "api" {
      driver = "raw_exec"
      config {}
    }
  }
}
`
	nomadApp, err := ParseNomadHCL(nomadContent)
	if err != nil {
		t.Fatalf("failed to parse nomad sidecar fixture: %v", err)
	}
	if nomadApp.Extensions[nomadAppRoutesMetaKey] == nil || nomadApp.Extensions[nomadAppPoliciesMetaKey] == nil {
		t.Fatalf("nomad sidecar readers did not rehydrate extensions: %#v", nomadApp.Extensions)
	}
	nomadRoutes := nomadApp.Extensions[nomadAppRoutesMetaKey].(map[string]*RouteSpec)
	if nomadRoutes["api"] == nil || nomadRoutes["api"].Extensions["custom.route"] != "keep" {
		t.Fatalf("nomad route reader lost extensions: %#v", nomadRoutes["api"])
	}
	if nested, ok := nomadRoutes["api"].Extensions["mystery"].(map[string]interface{}); !ok || nested["edge"] != true {
		t.Fatalf("nomad route reader lost unknown fields: %#v", nomadRoutes["api"].Extensions)
	}
	nomadPolicies := nomadApp.Extensions[nomadAppPoliciesMetaKey].(map[string]*PolicySpec)
	if nomadPolicies["api-policy"] == nil || nomadPolicies["api-policy"].Extensions["custom.policy"] != "keep" {
		t.Fatalf("nomad policy reader lost extensions: %#v", nomadPolicies["api-policy"])
	}
	if nested, ok := nomadPolicies["api-policy"].Extensions["mystery"].(map[string]interface{}); !ok || nested["edge"] != true {
		t.Fatalf("nomad policy reader lost unknown fields: %#v", nomadPolicies["api-policy"].Extensions)
	}
}

