func TestComposeSerializerPrefixesUnknownExtensions(t *testing.T) {
	app := &Application{
		Name:     "demo",
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "nginx:latest",
				Labels: map[string]string{
					"app": "api",
				},
				Extensions: map[string]interface{}{
					"custom.service-field": "keep-me",
					"x-bolabaden-service":  "preserve-me",
				},
			},
		},
		Extensions: map[string]interface{}{
			"custom.top-level": "keep-me-too",
			"x-bolabaden-app":  "preserve-me-too",
		},
	}

	out, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize compose with custom extensions: %v", err)
	}
	for _, expected := range []string{
		"x-custom-top-level: keep-me-too",
		"x-custom-service-field: keep-me",
		"x-bolabaden-app: preserve-me-too",
		"x-bolabaden-service: preserve-me",
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("Compose serializer did not prefix or preserve extension %q:\n%s", expected, out)
		}
	}
	for _, forbidden := range []string{"custom.top-level:", "custom.service-field:"} {
		if strings.Contains(out, forbidden) {
			t.Fatalf("Compose serializer leaked non-namespaced extension %q:\n%s", forbidden, out)
		}
	}
}

func TestComposeSerializerDoesNotLeakProjectNameIntoExtensions(t *testing.T) {
	app := &Application{
		Name:     "demo",
		Version:  "3.9",
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "nginx:latest",
			},
		},
		Extensions: map[string]interface{}{
			"name": "demo",
		},
	}

	out, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize compose with project name extension: %v", err)
	}
	if !strings.Contains(out, "name: demo") {
		t.Fatalf("Compose output lost top-level project name:\n%s", out)
	}
	if !strings.Contains(out, "version: \"3.9\"") && !strings.Contains(out, "version: 3.9") {
		t.Fatalf("Compose output lost top-level version:\n%s", out)
	}
	if strings.Contains(out, "x-name:") {
		t.Fatalf("Compose output leaked project name into extension space:\n%s", out)
	}
	if strings.Contains(out, "x-version:") {
		t.Fatalf("Compose output leaked project version into extension space:\n%s", out)
	}
	parsed, err := ParseDockerCompose(out)
	if err != nil {
		t.Fatalf("failed to parse emitted compose with version: %v", err)
	}
	if parsed.Version != "3.9" {
		t.Fatalf("Compose parse lost top-level version: %#v", parsed.Version)
	}
}

func TestComposeSerializerDropsSwarmMarkerForNonSwarmApps(t *testing.T) {
	app := &Application{
		Name:     "demo",
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "nginx:latest",
			},
		},
		Extensions: map[string]interface{}{
			"x-platform": "docker-swarm",
		},
	}

	out, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize non-swarm compose: %v", err)
	}
	if strings.Contains(out, "x-platform: docker-swarm") {
		t.Fatalf("non-swarm compose output leaked swarm marker:\n%s", out)
	}
	parsed, err := ParseDockerCompose(out)
	if err != nil {
		t.Fatalf("failed to parse emitted compose: %v", err)
	}
	if parsed.Platform != PlatformDockerCompose {
		t.Fatalf("non-swarm compose output changed platform classification: %s", parsed.Platform)
	}
}

func TestNomadAndHelmSerializersDropSwarmMarker(t *testing.T) {
	nomadApp := &Application{
		Name:     "demo",
		Platform: PlatformNomad,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "nginx:latest",
			},
		},
		Extensions: map[string]interface{}{
			"x-platform": "docker-swarm",
		},
	}

	nomadOut, err := SerializeNomadHCL(nomadApp)
	if err != nil {
		t.Fatalf("failed to serialize Nomad app: %v", err)
	}
	if strings.Contains(nomadOut, "x-platform") {
		t.Fatalf("Nomad output leaked swarm marker:\n%s", nomadOut)
	}

	chartDir := t.TempDir()
	for name, content := range map[string]string{
		"Chart.yaml": `apiVersion: v2
name: demo
version: 0.1.0
`,
		"values.yaml": "replicaCount: 1\n",
	} {
		path := filepath.Join(chartDir, filepath.FromSlash(name))
		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
			t.Fatalf("failed to create Helm chart path %s: %v", name, err)
		}
		if err := os.WriteFile(path, []byte(content), 0644); err != nil {
			t.Fatalf("failed to write Helm chart file %s: %v", name, err)
		}
	}
	helmApp, err := New(nil).LoadFile(chartDir)
	if err != nil {
		t.Fatalf("failed to load Helm chart: %v", err)
	}
	helmApp.Extensions["x-platform"] = "docker-swarm"
	helmApp.Extensions["x-custom-app"] = "keep-me"
	helmDir := t.TempDir()
	if err := SerializeHelmChart(helmApp, helmDir); err != nil {
		t.Fatalf("failed to serialize Helm chart: %v", err)
	}
	rawExtensions, err := os.ReadFile(filepath.Join(helmDir, helmAppExtensionsFile))
	if err != nil {
		t.Fatalf("failed to read Helm app extensions file: %v", err)
	}
	if strings.Contains(string(rawExtensions), "x-platform") {
		t.Fatalf("Helm app extensions leaked swarm marker:\n%s", string(rawExtensions))
	}
	if !strings.Contains(string(rawExtensions), "x-custom-app") {
		t.Fatalf("Helm app extensions lost custom data:\n%s", string(rawExtensions))
	}
}

