func TestComposeGoEscapesExtensionInterpolationLiterals(t *testing.T) {
	app := &Application{
		Name:     "demo",
		Platform: PlatformDockerCompose,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "nginx:latest",
				Extensions: map[string]interface{}{
					"x-custom-service": "literal ${HOME} value",
				},
			},
		},
		Extensions: map[string]interface{}{
			"x-custom-app": "literal ${HOME} value",
		},
	}

	out, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize compose with interpolation literal extensions: %v", err)
	}
	if !strings.Contains(out, "$${HOME}") {
		t.Fatalf("compose output did not escape literal interpolation syntax:\n%s", out)
	}
	parsed, err := ParseDockerCompose(out)
	if err != nil {
		t.Fatalf("compose loader rejected escaped interpolation literal output: %v", err)
	}
	if parsed.Extensions["x-custom-app"] != "literal ${HOME} value" {
		t.Fatalf("top-level extension literal did not round-trip: %#v\n%s", parsed.Extensions, out)
	}
	api := parsed.Services["api"]
	if api == nil || api.Extensions["x-custom-service"] != "literal ${HOME} value" {
		t.Fatalf("service extension literal did not round-trip: %#v\n%s", api, out)
	}
}

