func TestConvertedSwarmMarkerStaysOnComposeFamilyExportsOnly(t *testing.T) {
	app := &Application{
		Platform: PlatformDockerSwarm,
		Services: map[string]*Service{
			"api": {
				Name:  "api",
				Image: "nginx:latest",
			},
		},
		Extensions: map[string]interface{}{
			"x-platform":         "docker-swarm",
			"x-custom-top-level": "keep-me",
		},
	}
	p := New(nil)

	nomadApp, err := p.Convert(app, PlatformDockerSwarm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert swarm app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize swarm app as Nomad: %v", err)
	}
	if strings.Contains(nomadOut, "x-platform") {
		t.Fatalf("Nomad output leaked swarm marker:\n%s", nomadOut)
	}

	kubernetesApp, err := p.Convert(app, PlatformDockerSwarm, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert swarm app to Kubernetes: %v", err)
	}
	kubernetesOut, err := p.SaveContent(kubernetesApp, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to serialize swarm app as Kubernetes: %v", err)
	}
	if strings.Contains(kubernetesOut, "x-platform") {
		t.Fatalf("Kubernetes output leaked swarm marker:\n%s", kubernetesOut)
	}

	helmApp, err := p.Convert(app, PlatformDockerSwarm, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert swarm app to Helm: %v", err)
	}
	if helmApp.Extensions["x-platform"] != nil {
		t.Fatalf("Helm conversion leaked swarm marker into app extensions: %#v", helmApp.Extensions)
	}

	swarmOut, err := p.SaveContent(app, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to serialize swarm app as Compose: %v", err)
	}
	if !strings.Contains(swarmOut, "x-platform: docker-swarm") {
		t.Fatalf("Swarm Compose output lost platform marker:\n%s", swarmOut)
	}
}

