func TestLegacyMeshExtensionKeyNormalizesToComposeSafeExtension(t *testing.T) {
	app := &Application{
		Platform: PlatformDockerCompose,
		Extensions: map[string]interface{}{
			legacyMeshExtensionKey: map[string]interface{}{
				"provider":  "headscale",
				"dns_zone":  "bolabaden.mesh",
				"magic_dns": true,
			},
		},
		Services: map[string]*Service{
			"api": {
				Name:     "api",
				Image:    "nginx:latest",
				Platform: PlatformDockerCompose,
			},
		},
	}

	composeOut, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize legacy mesh Compose app: %v", err)
	}
	if !strings.Contains(composeOut, "x-bolabaden-mesh:") {
		t.Fatalf("legacy mesh extension was not normalized to x-bolabaden-mesh:\n%s", composeOut)
	}
	parsed, err := ParseDockerCompose(composeOut)
	if err != nil {
		t.Fatalf("failed to parse normalized mesh compose output: %v", err)
	}
	if parsed.Mesh == nil || parsed.Mesh.Provider != "headscale" || parsed.Mesh.DNSZone != "bolabaden.mesh" || !parsed.Mesh.MagicDNS {
		t.Fatalf("normalized mesh compose output lost mesh state: %#v", parsed.Mesh)
	}
	if _, ok := parsed.Extensions[legacyMeshExtensionKey]; ok {
		t.Fatalf("legacy mesh key leaked back into parsed compose extensions: %#v", parsed.Extensions)
	}
	if mesh, ok := parsed.Extensions[meshExtensionKey].(map[string]interface{}); !ok || mesh["provider"] != "headscale" || mesh["dns_zone"] != "bolabaden.mesh" {
		t.Fatalf("normalized mesh compose output did not preserve x-bolabaden-mesh payload: %#v", parsed.Extensions)
	}
}

func TestLegacyMeshExtensionKeyDoesNotSurviveConversion(t *testing.T) {
	app := &Application{
		Platform: PlatformDockerCompose,
		Extensions: map[string]interface{}{
			legacyMeshExtensionKey: map[string]interface{}{
				"provider": "headscale",
				"dns_zone": "bolabaden.mesh",
			},
		},
		Services: map[string]*Service{
			"api": {
				Name:     "api",
				Image:    "nginx:latest",
				Platform: PlatformDockerCompose,
			},
		},
	}

	p := New(nil)
	for _, target := range []Platform{PlatformNomad, PlatformHelm, PlatformKubernetes} {
		converted, err := p.Convert(app, PlatformDockerCompose, target)
		if err != nil {
			t.Fatalf("failed to convert legacy mesh compose app to %s: %v", target, err)
		}
		if _, ok := converted.Extensions[legacyMeshExtensionKey]; ok {
			t.Fatalf("legacy mesh key survived conversion to %s: %#v", target, converted.Extensions)
		}
		if mesh, ok := converted.Extensions[meshExtensionKey].(map[string]interface{}); !ok || mesh["provider"] != "headscale" || mesh["dns_zone"] != "bolabaden.mesh" {
			t.Fatalf("normalized mesh extension missing after conversion to %s: %#v", target, converted.Extensions)
		}
	}
}

func TestComposeSerializerPrefixesUnknownCustomKeys(t *testing.T) {
	app := &Application{
		Name:     "demo",
		Platform: PlatformDockerCompose,
		Extensions: map[string]interface{}{
			"custom":           "alpha",
			"com.example.mesh": "beta",
			"x-custom-already": "gamma",
			"bolabaden.mesh":   map[string]interface{}{"provider": "headscale"},
			"x-bolabaden-mesh": map[string]interface{}{"provider": "headscale", "dns_zone": "bolabaden.mesh"},
			"x-bolabaden-failover": map[string]interface{}{
				"enabled": true,
			},
		},
		Services: map[string]*Service{
			"api": {
				Name:     "api",
				Image:    "nginx:latest",
				Platform: PlatformDockerCompose,
				Extensions: map[string]interface{}{
					"custom":           "service-alpha",
					"com.example.role": "edge",
					"x-custom-service": "already-safe",
				},
			},
		},
	}

	out, err := SerializeDockerCompose(app)
	if err != nil {
		t.Fatalf("failed to serialize compose with custom keys: %v", err)
	}
	for _, forbidden := range []string{"\ncustom:", "\ncom.example.mesh:", "\ncom.example.role:", "\nbolabaden.mesh:"} {
		if strings.Contains(out, forbidden) {
			t.Fatalf("compose serializer leaked bare custom key %q:\n%s", forbidden, out)
		}
	}
	for _, expected := range []string{"x-custom:", "x-com-example-mesh:", "x-custom-service:", "x-bolabaden-mesh:", "x-bolabaden-failover:"} {
		if !strings.Contains(out, expected) {
			t.Fatalf("compose serializer did not preserve custom extension %q:\n%s", expected, out)
		}
	}

	parsed, err := ParseDockerCompose(out)
	if err != nil {
		t.Fatalf("failed to parse compose with prefixed custom keys: %v", err)
	}
	if parsed.Extensions["x-custom"] != "alpha" || parsed.Extensions["x-com-example-mesh"] != "beta" {
		t.Fatalf("top-level custom keys did not round-trip: %#v", parsed.Extensions)
	}
	api := parsed.Services["api"]
	if api == nil || api.Extensions["x-custom-service"] != "already-safe" || api.Extensions["x-com-example-role"] != "edge" {
		t.Fatalf("service custom keys did not round-trip: %#v", api)
	}
}

