func TestHelmSubchartFilesRoundTripWithoutLoss(t *testing.T) {
	tempDir := t.TempDir()
	chartDir := filepath.Join(tempDir, "demo")
	subchartDir := filepath.Join(chartDir, "charts", "cache")
	for _, dir := range []string{
		filepath.Join(chartDir, "templates"),
		filepath.Join(subchartDir, "templates"),
	} {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			t.Fatalf("failed to create chart dir %s: %v", dir, err)
		}
	}
	files := map[string]string{
		"Chart.yaml": `apiVersion: v2
name: demo
version: 0.1.0
`,
		"values.yaml": `image:
  repository: ghcr.io/example/demo
`,
		"templates/deployment.yaml": `apiVersion: apps/v1
kind: Deployment
metadata:
  name: demo
spec:
  selector:
    matchLabels:
      app: demo
  template:
    metadata:
      labels:
        app: demo
    spec:
      containers:
        - name: demo
          image: {{ .Values.image.repository | quote }}
`,
		"charts/cache/Chart.yaml": `apiVersion: v2
name: cache
version: 0.1.0
`,
		"charts/cache/values.yaml": `image:
  repository: ghcr.io/example/cache
`,
		"charts/cache/templates/configmap.yaml": `apiVersion: v1
kind: ConfigMap
metadata:
  name: cache-config
data:
  image: {{ .Values.image.repository | quote }}
`,
	}
	for name, content := range files {
		path := filepath.Join(chartDir, filepath.FromSlash(name))
		if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
			t.Fatalf("failed to write chart file %s: %v", name, err)
		}
	}

	app, err := ParseHelmChart(chartDir)
	if err != nil {
		t.Fatalf("failed to parse Helm chart: %v", err)
	}
	filesMap, ok := app.Extensions[helmRawFilesExtension].(map[string]string)
	if !ok {
		t.Fatalf("helm raw file metadata missing: %#v", app.Extensions[helmRawFilesExtension])
	}
	for _, name := range []string{
		"Chart.yaml",
		"values.yaml",
		"templates/deployment.yaml",
		"charts/cache/Chart.yaml",
		"charts/cache/values.yaml",
		"charts/cache/templates/configmap.yaml",
	} {
		if filesMap[name] == "" {
			t.Fatalf("helm raw files missing %s: %#v", name, filesMap)
		}
	}

	outDir := filepath.Join(tempDir, "out")
	if err := SerializeHelmChart(app, outDir); err != nil {
		t.Fatalf("failed to serialize Helm chart with subchart: %v", err)
	}
	for name, expected := range files {
		actual, err := os.ReadFile(filepath.Join(outDir, filepath.FromSlash(name)))
		if err != nil {
			t.Fatalf("restored chart file %s missing: %v", name, err)
		}
		if string(actual) != expected {
			t.Fatalf("restored chart file %s changed\nexpected:\n%s\nactual:\n%s", name, expected, string(actual))
		}
	}
}

func TestHelmRawChartFilesSurviveConversionAndCanBeRestored(t *testing.T) {
	p := New(nil)
	chartDir := t.TempDir()
	files := map[string]string{
		"Chart.yaml": `apiVersion: v2
name: demo
version: 0.1.0
`,
		"values.yaml": `replicaCount: 2
`,
		"templates/_helpers.tpl": `{{- define "demo.name" -}}demo{{- end -}}
`,
		"templates/deployment.yaml": `apiVersion: apps/v1
kind: Deployment
metadata:
  name: demo
spec:
  replicas: {{ .Values.replicaCount }}
  selector:
    matchLabels:
      app: demo
  template:
    metadata:
      labels:
        app: demo
    spec:
      containers:
        - name: demo
          image: ghcr.io/example/demo:helm
`,
	}
	for name, content := range files {
		path := filepath.Join(chartDir, filepath.FromSlash(name))
		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
			t.Fatalf("failed to create chart dir for %s: %v", name, err)
		}
		if err := os.WriteFile(path, []byte(content), 0644); err != nil {
			t.Fatalf("failed to write chart file %s: %v", name, err)
		}
	}

	app, err := ParseHelmChart(chartDir)
	if err != nil {
		t.Fatalf("failed to parse Helm chart: %v", err)
	}
	composeApp, err := p.Convert(app, PlatformHelm, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Helm chart to Compose: %v", err)
	}
	if composeApp.Extensions[helmRawFilesExtension] != nil || composeApp.Extensions["chart"] != nil {
		t.Fatalf("helm raw extensions should have been scrubbed in converted app: %#v", composeApp.Extensions)
	}
	rawResource := composeApp.Canonical.Resources["helm:raw:files"]
	if composeApp.Canonical == nil || rawResource == nil {
		t.Fatalf("helm raw files were not preserved canonically after conversion: %#v", composeApp.Canonical)
	}

	restoreDir := t.TempDir()
	if err := SerializeHelmChart(composeApp, restoreDir); err != nil {
		t.Fatalf("failed to restore Helm chart from converted app: %v", err)
	}
	for name, expected := range files {
		actual, err := os.ReadFile(filepath.Join(restoreDir, filepath.FromSlash(name)))
		if err != nil {
			t.Fatalf("restored chart file %s missing: %v", name, err)
		}
		if string(actual) != expected {
			t.Fatalf("restored chart file %s changed\nexpected:\n%s\nactual:\n%s", name, expected, string(actual))
		}
	}
}

func TestHelmRawChartFilesSurviveUniversalRoundTripAndCanBeRestored(t *testing.T) {
	p := New(nil)
	chartDir := t.TempDir()
	files := map[string]string{
		"Chart.yaml": `apiVersion: v2
name: demo
version: 0.1.0
`,
		"values.yaml": `replicaCount: 2
`,
		"templates/_helpers.tpl": `{{- define "demo.name" -}}demo{{- end -}}
`,
		"templates/deployment.yaml": `apiVersion: apps/v1
kind: Deployment
metadata:
  name: demo
spec:
  replicas: {{ .Values.replicaCount }}
  selector:
    matchLabels:
      app: demo
  template:
    metadata:
      labels:
        app: demo
    spec:
      containers:
        - name: demo
          image: ghcr.io/example/demo:helm
`,
	}
	for name, content := range files {
		path := filepath.Join(chartDir, filepath.FromSlash(name))
		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
			t.Fatalf("failed to create chart dir for %s: %v", name, err)
		}
		if err := os.WriteFile(path, []byte(content), 0644); err != nil {
			t.Fatalf("failed to write chart file %s: %v", name, err)
		}
	}

	app, err := ParseHelmChart(chartDir)
	if err != nil {
		t.Fatalf("failed to parse Helm chart: %v", err)
	}

	composeApp, err := p.Convert(app, PlatformHelm, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Helm chart to Compose: %v", err)
	}
	swarmApp, err := p.Convert(composeApp, PlatformDockerCompose, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Compose to Swarm: %v", err)
	}
	nomadApp, err := p.Convert(swarmApp, PlatformDockerSwarm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Swarm to Nomad: %v", err)
	}
	kubernetesApp, err := p.Convert(nomadApp, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad to Kubernetes: %v", err)
	}
	backToHelm, err := p.Convert(kubernetesApp, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes back to Helm: %v", err)
	}

	restoreDir := t.TempDir()
	if err := SerializeHelmChart(backToHelm, restoreDir); err != nil {
		t.Fatalf("failed to restore Helm chart after full chain: %v", err)
	}
	for name, expected := range files {
		actual, err := os.ReadFile(filepath.Join(restoreDir, filepath.FromSlash(name)))
		if err != nil {
			t.Fatalf("restored chart file %s missing: %v", name, err)
		}
		if string(actual) != expected {
			t.Fatalf("restored chart file %s changed\nexpected:\n%s\nactual:\n%s", name, expected, string(actual))
		}
	}
}

func TestHelmRenderedExtensionsPreserveCanonicalRoutesPoliciesAndRawResources(t *testing.T) {
	tempDir := t.TempDir()
	chartDir := filepath.Join(tempDir, "mesh")
	if err := os.MkdirAll(filepath.Join(chartDir, "templates"), 0755); err != nil {
		t.Fatalf("failed to create chart dirs: %v", err)
	}
	if err := os.WriteFile(filepath.Join(chartDir, "Chart.yaml"), []byte(`apiVersion: v2
name: mesh
version: 0.1.0
`), 0644); err != nil {
		t.Fatalf("failed to write Chart.yaml: %v", err)
	}
	if err := os.WriteFile(filepath.Join(chartDir, "values.yaml"), []byte(`host: api.example.test
`), 0644); err != nil {
		t.Fatalf("failed to write values.yaml: %v", err)
	}
	template := `apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ .Release.Name }}
  labels:
    app: {{ .Release.Name }}
spec:
  replicas: 1
  selector:
    matchLabels:
      app: {{ .Release.Name }}
  template:
    metadata:
      labels:
        app: {{ .Release.Name }}
    spec:
      containers:
        - name: {{ .Release.Name }}
          image: ghcr.io/example/mesh:latest
---
apiVersion: networking.k8s.io/v1
kind: Ingress
metadata:
  name: {{ .Release.Name }}-ingress
spec:
  rules:
    - host: {{ .Values.host | quote }}
      http:
        paths:
          - path: /
            pathType: Prefix
            backend:
              service:
                name: {{ .Release.Name }}
                port:
                  number: 80
---
apiVersion: networking.k8s.io/v1
kind: NetworkPolicy
metadata:
  name: {{ .Release.Name }}-policy
spec:
  podSelector:
    matchLabels:
      app: {{ .Release.Name }}
  policyTypes:
    - Ingress
`
	if err := os.WriteFile(filepath.Join(chartDir, "templates", "resources.yaml"), []byte(template), 0644); err != nil {
		t.Fatalf("failed to write template: %v", err)
	}

	app, err := ParseHelmChart(chartDir)
	if err != nil {
		t.Fatalf("failed to parse Helm chart: %v", err)
	}
	if app.Extensions["kubernetes.routes"] == nil || app.Extensions["kubernetes.policies"] == nil || app.Extensions["kubernetes.raw"] == nil {
		t.Fatalf("rendered Kubernetes extensions were not preserved on Helm app: %#v", app.Extensions)
	}
	if app.Canonical == nil {
		t.Fatalf("canonical model missing")
	}
	route := app.Canonical.Routes["api.example.test"]
	if route == nil || route.Source != PlatformHelm || route.Service != "mesh" || len(route.Hosts) != 1 || route.Hosts[0] != "api.example.test" {
		t.Fatalf("Helm route was not canonicalized from rendered ingress: %#v", route)
	}
	policy := app.Canonical.Policies["mesh-policy"]
	if policy == nil || policy.Source != PlatformHelm || policy.Type != "networkpolicy" || len(policy.Rules) != 1 || policy.Rules[0] != "app=mesh" {
		t.Fatalf("Helm policy was not canonicalized from rendered NetworkPolicy: %#v", policy)
	}
	foundIngress := false
	foundPolicy := false
	for _, resource := range app.Canonical.Resources {
		if resource.Platform != PlatformHelm || resource.Kind != ResourceKindRaw {
			continue
		}
		if resource.NativeKind == "Ingress" && resource.Name == "mesh-ingress" {
			foundIngress = true
		}
		if resource.NativeKind == "NetworkPolicy" && resource.Name == "mesh-policy" {
			foundPolicy = true
		}
	}
	if !foundIngress || !foundPolicy {
		t.Fatalf("rendered Helm raw resources were not indexed canonically: %#v", app.Canonical.Resources)
	}
}

