func TestNomadRawHCLSurvivesUniversalRoundTripAndCanBeRestored(t *testing.T) {
	content := `
job "demo" {
  datacenters = ["dc1"]
  group "api" {
    count = 2
    task "api" {
      driver = "docker"
      config {
        image = "ghcr.io/example/original:1"
      }
    }
  }
}
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad HCL: %v", err)
	}

	composeApp, err := p.Convert(app, PlatformNomad, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to convert Nomad to Compose: %v", err)
	}
	swarmApp, err := p.Convert(composeApp, PlatformDockerCompose, PlatformDockerSwarm)
	if err != nil {
		t.Fatalf("failed to convert Compose to Swarm: %v", err)
	}
	nomadApp, err := p.Convert(swarmApp, PlatformDockerSwarm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Swarm back to Nomad: %v", err)
	}
	kubernetesApp, err := p.Convert(nomadApp, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad to Kubernetes: %v", err)
	}
	helmApp, err := p.Convert(kubernetesApp, PlatformKubernetes, PlatformHelm)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes to Helm: %v", err)
	}
	backToNomad, err := p.Convert(helmApp, PlatformHelm, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Helm back to Nomad: %v", err)
	}

	restorePath := filepath.Join(t.TempDir(), "job.hcl")
	if err := RestoreNomadSource(backToNomad, restorePath); err != nil {
		t.Fatalf("failed to restore Nomad HCL after full chain: %v", err)
	}
	restored, err := os.ReadFile(restorePath)
	if err != nil {
		t.Fatalf("failed to read restored Nomad HCL: %v", err)
	}
	if string(restored) != content {
		t.Fatalf("restored Nomad HCL changed after full chain\nexpected:\n%s\nactual:\n%s", content, string(restored))
	}
}

func TestNomadApplicationExtensionsRoundTrip(t *testing.T) {
	app := &Application{
		Platform: PlatformKubernetes,
		Services: map[string]*Service{
			"api": {
				Name:     "api",
				Image:    "ghcr.io/example/api:1",
				Platform: PlatformKubernetes,
				Extensions: map[string]interface{}{
					"custom.service-field": "keep-service",
					"x-bolabaden-service": map[string]interface{}{
						"tier": "edge",
					},
					"x-custom-service": "keep-me",
				},
			},
		},
		Extensions: map[string]interface{}{
			"custom.app-field": "keep-app",
			"x-bolabaden-app": map[string]interface{}{
				"mode":    "mesh",
				"enabled": true,
			},
		},
	}
	p := New(nil)
	nomadApp, err := p.Convert(app, PlatformKubernetes, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert Kubernetes app to Nomad: %v", err)
	}
	nomadOut, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad app with extensions: %v", err)
	}
	if !strings.Contains(nomadOut, "bolabaden_app_extensions") || !strings.Contains(nomadOut, "mesh") {
		t.Fatalf("Nomad app output did not preserve application extensions:\n%s", nomadOut)
	}
	if !strings.Contains(nomadOut, "x-custom-service") || !strings.Contains(nomadOut, "keep-me") {
		t.Fatalf("Nomad service output did not preserve service extensions:\n%s", nomadOut)
	}
	if !strings.Contains(nomadOut, "custom.service-field") || !strings.Contains(nomadOut, "keep-service") {
		t.Fatalf("Nomad service output did not preserve raw custom service fields:\n%s", nomadOut)
	}
	parsedNomad, err := p.LoadContent(nomadOut, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse Nomad app with extensions: %v", err)
	}
	if parsedNomad.Extensions["custom.app-field"] != "keep-app" {
		t.Fatalf("Nomad app raw custom extension did not round-trip: %#v", parsedNomad.Extensions)
	}
	nested, ok := parsedNomad.Extensions["x-bolabaden-app"].(map[string]interface{})
	if !ok || toString(nested["mode"]) != "mesh" || nested["enabled"] != true {
		t.Fatalf("Nomad app extensions did not round-trip: %#v", parsedNomad.Extensions)
	}
	parsedService := parsedNomad.Services["api"]
	if parsedService == nil {
		t.Fatalf("Nomad service missing after round-trip")
	}
	if parsedService.Extensions["x-custom-service"] != "keep-me" {
		t.Fatalf("Nomad service extensions did not round-trip: %#v", parsedService.Extensions)
	}
	if parsedService.Extensions["custom.service-field"] != "keep-service" {
		t.Fatalf("Nomad raw custom service field did not round-trip: %#v", parsedService.Extensions)
	}
	serviceNested, ok := parsedService.Extensions["x-bolabaden-service"].(map[string]interface{})
	if !ok || serviceNested["tier"] != "edge" {
		t.Fatalf("Nomad nested service extensions did not round-trip: %#v", parsedService.Extensions)
	}
	backToK8s, err := p.Convert(parsedNomad, PlatformNomad, PlatformKubernetes)
	if err != nil {
		t.Fatalf("failed to convert Nomad app back to Kubernetes: %v", err)
	}
	if nested, ok := backToK8s.Extensions["x-bolabaden-app"].(map[string]interface{}); !ok || toString(nested["mode"]) != "mesh" {
		t.Fatalf("Kubernetes app extensions did not survive Nomad round-trip: %#v", backToK8s.Extensions)
	}
}

