func TestComposeHealthCheckEmitsNomadServiceCheck(t *testing.T) {
	content := `
services:
  api:
    image: ghcr.io/example/api:nomad-health
    ports:
      - name: http
        target: 8080
        published: "8080"
    healthcheck:
      test: ["CMD-SHELL", "curl -fsS http://127.0.0.1:8080/ready || exit 1"]
      interval: 10s
      timeout: 2s
`
	p := New(nil)
	app, err := p.LoadContent(content, PlatformDockerCompose)
	if err != nil {
		t.Fatalf("failed to parse compose app: %v", err)
	}
	nomadApp, err := p.Convert(app, PlatformDockerCompose, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to convert compose app to Nomad: %v", err)
	}
	out, err := p.SaveContent(nomadApp, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to serialize Nomad HCL: %v", err)
	}
	for _, expected := range []string{
		`ports = ["http"]`,
		`service {`,
		`port = "http"`,
		`check {`,
		`type = "http"`,
		`path = "/ready"`,
		`interval = "10s"`,
		`timeout = "2s"`,
	} {
		if !strings.Contains(out, expected) {
			t.Fatalf("Nomad output missing %q:\n%s", expected, out)
		}
	}

	parsed, err := p.LoadContent(out, PlatformNomad)
	if err != nil {
		t.Fatalf("failed to parse emitted Nomad HCL: %v", err)
	}
	health := parsed.Services["api"].HealthCheck
	if health == nil || health.Type != "http" || health.Path != "/ready" || health.Port != "http" || health.Interval != "10s" || health.Timeout != "2s" {
		t.Fatalf("Nomad health check did not rehydrate: %#v", health)
	}
}

