func containsString(values []string, expected string) bool {
	for _, value := range values {
		if value == expected {
			return true
		}
	}
	return false
}

func assertComposeIncludeEntries(t *testing.T, app *Application) {
	t.Helper()
	if app == nil {
		t.Fatalf("application missing")
	}
	if len(app.IncludeEntries) != 2 {
		t.Fatalf("include entries did not survive bridge: includes=%#v entries=%#v", app.Includes, app.IncludeEntries)
	}
	if !containsString(app.Includes, "./common.yml") || !containsString(app.Includes, "./team.yml") || !containsString(app.Includes, "./ops.yml") {
		t.Fatalf("include paths did not survive bridge: includes=%#v entries=%#v", app.Includes, app.IncludeEntries)
	}
	mapped, ok := asMap(app.IncludeEntries[1])
	if !ok {
		t.Fatalf("object include entry did not survive bridge: %#v", app.IncludeEntries[1])
	}
	paths, err := toStringSlice(mapped["path"])
	if err != nil || !containsString(paths, "./team.yml") || !containsString(paths, "./ops.yml") {
		t.Fatalf("include path list did not survive bridge: %#v", mapped)
	}
	envFiles, err := toStringSlice(mapped["env_file"])
	if err != nil || !containsString(envFiles, "./.env.common") || !containsString(envFiles, "./.env.local") {
		t.Fatalf("include env_file list did not survive bridge: %#v", mapped)
	}
	if toString(mapped["project_directory"]) != "./subproject" {
		t.Fatalf("include project_directory did not survive bridge: %#v", mapped)
	}
}

func assertComposeExternalObjectMetadata(t *testing.T, app *Application) {
	t.Helper()
	if app == nil {
		t.Fatalf("application missing")
	}
	if owner := externalOwner(app.Networks["mesh"].ExternalExtensions); owner != "network-team" {
		t.Fatalf("network external metadata did not survive bridge: %#v", app.Networks["mesh"])
	}
	if owner := externalOwner(app.Volumes["app-data"].ExternalExtensions); owner != "storage-team" {
		t.Fatalf("volume external metadata did not survive bridge: %#v", app.Volumes["app-data"])
	}
	if owner := externalOwner(app.Configs["app-config"].ExternalExtensions); owner != "config-team" {
		t.Fatalf("config external metadata did not survive bridge: %#v", app.Configs["app-config"])
	}
	if owner := externalOwner(app.Secrets["app-secret"].ExternalExtensions); owner != "secret-team" {
		t.Fatalf("secret external metadata did not survive bridge: %#v", app.Secrets["app-secret"])
	}
}

func externalOwner(extensions map[string]interface{}) string {
	data, ok := asMap(extensions["x-bolabaden-external"])
	if !ok {
		return ""
	}
	return toString(data["owner"])
}

func assertDeployExtensions(t *testing.T, service *Service) {
	t.Helper()
	if service == nil || service.Deploy == nil {
		t.Fatalf("service deploy is nil: %#v", service)
	}
	deploy := service.Deploy
	if toString(deploy.Extensions["x-bolabaden-deploy"]) != "mesh-rollout" {
		t.Fatalf("deploy extension not preserved: %#v", deploy.Extensions)
	}
	if deploy.UpdateConfig == nil || toString(deploy.UpdateConfig.Extensions["x-bolabaden-update"]) != "canary" {
		t.Fatalf("update extension not preserved: %#v", deploy.UpdateConfig)
	}
	if deploy.RollbackConfig == nil || !deploy.RollbackConfig.ParallelismSet || deploy.RollbackConfig.Parallelism != 0 || toString(deploy.RollbackConfig.Extensions["x-bolabaden-rollback"]) != "auto" {
		t.Fatalf("rollback extension not preserved: %#v", deploy.RollbackConfig)
	}
	if deploy.RestartPolicy == nil || deploy.RestartPolicy.Condition != "on-failure" || toString(deploy.RestartPolicy.Extensions["x-bolabaden-restart"]) != "bounded" {
		t.Fatalf("restart extension not preserved: %#v", deploy.RestartPolicy)
	}
}

func assertDeployResourceExtensions(t *testing.T, service *Service) {
	t.Helper()
	if service == nil || service.Deploy == nil || service.Deploy.Resources == nil {
		t.Fatalf("service deploy resources are nil: %#v", service)
	}
	resources := service.Deploy.Resources
	if toString(resources.Extensions["x-bolabaden-resources"]) != "resource-scope" {
		t.Fatalf("resource extension not preserved: %#v", resources.Extensions)
	}
	if toString(resources.LimitExtensions["x-bolabaden-limits"]) != "hard" {
		t.Fatalf("resource limits extension not preserved: %#v", resources.LimitExtensions)
	}
	if toString(resources.ReservationExtensions["x-bolabaden-reservations"]) != "soft" {
		t.Fatalf("resource reservations extension not preserved: %#v", resources.ReservationExtensions)
	}
	if len(resources.Devices) != 1 || resources.Devices[0].Driver != "nvidia" || resources.Devices[0].Count != "all" || toString(resources.Devices[0].Extensions["x-bolabaden-device"]) != "passthrough" {
		t.Fatalf("resource device extension not preserved: %#v", resources.Devices)
	}
	if len(resources.GenericResources) != 1 ||
		resources.GenericResources[0].Kind != "SSD" ||
		resources.GenericResources[0].Value != "2" ||
		toString(resources.GenericResources[0].Extensions["x-bolabaden-generic"]) != "pool" ||
		toString(resources.GenericResources[0].DiscreteExtensions["x-bolabaden-discrete"]) != "fast" {
		t.Fatalf("generic resource extension not preserved: %#v", resources.GenericResources)
	}
}

func assertPlacementExtensions(t *testing.T, service *Service) {
	t.Helper()
	if service == nil || service.Deploy == nil || service.Deploy.Placement == nil {
		t.Fatalf("service deploy placement is nil: %#v", service)
	}
	placement := service.Deploy.Placement
	if toString(placement.Extensions["x-bolabaden-placement"]) != "mesh-aware" {
		t.Fatalf("placement extension not preserved: %#v", placement.Extensions)
	}
	if placement.MaxReplicasPerNode != 1 || !containsString(placement.Constraints, "node.labels.region == us") || !containsString(placement.Preferences, "spread=node.labels.zone") {
		t.Fatalf("placement fields not preserved: %#v", placement)
	}
	if len(placement.PreferenceExtensions) != 1 || toString(placement.PreferenceExtensions[0]["x-bolabaden-preference-meta"]) != "balanced" {
		t.Fatalf("placement preference extension not preserved: %#v", placement.PreferenceExtensions)
	}
}

func assertPortableHealthCheck(t *testing.T, service *Service) {
	t.Helper()
	if service == nil || service.HealthCheck == nil {
		t.Fatalf("service healthcheck is nil: %#v", service)
	}
	health := service.HealthCheck
	if !health.Disable ||
		health.Interval != "15s" ||
		health.Timeout != "2s" ||
		health.Retries != 4 ||
		health.StartPeriod != "20s" ||
		health.StartInterval != "5s" ||
		toString(health.Extensions["x-bolabaden-health"]) != "portable" {
		t.Fatalf("portable healthcheck fields not preserved: %#v", health)
	}
	if len(health.Test) == 0 || !containsString(health.Test, "CMD-SHELL") {
		t.Fatalf("portable healthcheck test not preserved: %#v", health.Test)
	}
}

func assertMeshNetworkAttachment(t *testing.T, service *Service) {
	t.Helper()
	if service == nil {
		t.Fatalf("service missing")
	}
	mesh := service.NetworkAttachments["mesh"]
	if mesh == nil {
		t.Fatalf("mesh network attachment missing: %#v", service)
	}
	if mesh.IPv4Address != "10.42.0.10" ||
		mesh.InterfaceName != "eth0" ||
		len(mesh.Aliases) != 1 ||
		mesh.Aliases[0] != "api.mesh" ||
		len(mesh.LinkLocalIPs) != 1 ||
		mesh.LinkLocalIPs[0] != "169.254.42.10" ||
		mesh.Extensions["x-bolabaden-mesh-peer"] != "headscale" {
		t.Fatalf("mesh network attachment did not survive bridge: %#v", mesh)
	}
}

func assertMeshNetworkDefinition(t *testing.T, app *Application) {
	t.Helper()
	if app == nil {
		t.Fatalf("application missing")
	}
	mesh := app.Networks["mesh"]
	if mesh == nil {
		t.Fatalf("mesh network definition missing: %#v", app.Networks)
	}
	if mesh.PlatformName != "bolabaden_mesh" ||
		mesh.Driver != "bridge" ||
		mesh.DriverOpts["encrypted"] != "true" ||
		!mesh.Attachable ||
		!mesh.Internal ||
		mesh.EnableIPv4 == nil || !*mesh.EnableIPv4 ||
		mesh.EnableIPv6 == nil || !*mesh.EnableIPv6 ||
		mesh.Labels["bolabaden.mesh"] != "headscale" {
		t.Fatalf("mesh network definition did not survive bridge: %#v", mesh)
	}
	if mesh.IPAM == nil ||
		mesh.IPAM.Driver != "default" ||
		mesh.IPAM.Options["com.docker.network.bridge.name"] != "bolabaden0" ||
		len(mesh.IPAM.Config) != 1 ||
		mesh.IPAM.Config[0].Subnet != "10.42.0.0/24" ||
		mesh.IPAM.Config[0].Gateway != "10.42.0.1" ||
		mesh.IPAM.Config[0].IPRange != "10.42.0.0/25" ||
		mesh.IPAM.Config[0].AuxAddresses["headscale"] != "10.42.0.2" ||
		mesh.IPAM.Config[0].Extensions["x-bolabaden-ipam"] != "mesh" {
		t.Fatalf("mesh network IPAM did not survive bridge: %#v", mesh.IPAM)
	}
	meshExtension, ok := mesh.Extensions["x-bolabaden-mesh"].(map[string]interface{})
	if !ok || meshExtension["provider"] != "headscale" || meshExtension["dns_zone"] != "bolabaden.mesh" {
		t.Fatalf("mesh network extension did not survive bridge: %#v", mesh.Extensions)
	}
}

func assertGrafanaFailover(t *testing.T, service *Service) {
	t.Helper()
	if service == nil {
		t.Fatalf("grafana service missing")
	}
	failover := service.Failover
	if failover == nil {
		t.Fatalf("grafana failover intent missing: %#v", service)
	}
	if !failover.Enabled ||
		failover.Type != "http" ||
		failover.Port != "3000" ||
		failover.HealthcheckPath != "/api/health" ||
		failover.HealthcheckInterval != "30s" ||
		failover.MaxRetries != 3 ||
		!failover.RedeployOnPeer ||
		failover.Strategy != "weighted-round-robin" ||
		!failover.PreferLocal {
		t.Fatalf("grafana failover intent did not survive bridge: %#v", failover)
	}
	vractor := failover.Nodes["vractormania"]
	zeus := failover.Nodes["zeus"]
	if vractor == nil || vractor.Status != "healthy" || vractor.Priority != 1 || vractor.Weight != 100 || vractor.URL != "https://grafana.vractormania.bolabaden.org" {
		t.Fatalf("primary failover node did not survive bridge: %#v", failover.Nodes)
	}
	if vractor.Extensions["x-bolabaden-node-note"] != "primary" {
		t.Fatalf("primary failover node extension did not survive bridge: %#v", vractor.Extensions)
	}
	if zeus == nil || zeus.Status != "stopped" || zeus.Priority != 2 || zeus.Weight != 40 || zeus.URL != "https://grafana.zeus.bolabaden.org" {
		t.Fatalf("peer failover node did not survive bridge: %#v", failover.Nodes)
	}
}

