func TestKubernetesOpaqueServiceExtensionsRoundTrip(t *testing.T) {
	app := &Application{
		Platform: PlatformKubernetes,
		Services: map[string]*Service{
			"api": {
				Name:     "api",
				Image:    "ghcr.io/example/api:1",
				Platform: PlatformKubernetes,
				Extensions: map[string]interface{}{
					"custom.service-field": "keep-me",
					"x-custom-service":     map[string]interface{}{"tier": "edge"},
				},
			},
		},
	}

	out, err := SerializeKubernetesYAML(app)
	if err != nil {
		t.Fatalf("failed to serialize Kubernetes app with opaque service extensions: %v", err)
	}
	if !strings.Contains(out, kubernetesAnnotationPortableServiceExtensions) {
		t.Fatalf("Kubernetes output did not emit opaque service extension annotation:\n%s", out)
	}

	parsed, err := ParseKubernetesYAML(out)
	if err != nil {
		t.Fatalf("failed to parse Kubernetes app with opaque service extensions: %v", err)
	}
	api := parsed.Services["api"]
	if api == nil {
		t.Fatalf("api workload missing after Kubernetes round-trip")
	}
	if api.Extensions["custom.service-field"] != "keep-me" {
		t.Fatalf("opaque raw service extension did not round-trip: %#v", api.Extensions)
	}
	nested, ok := api.Extensions["x-custom-service"].(map[string]interface{})
	if !ok || nested["tier"] != "edge" {
		t.Fatalf("opaque x-* service extension did not round-trip: %#v", api.Extensions)
	}
}

